{
  "name": "Receitas Fit Generator",
  "description": "Um gerador inteligente de receitas saudáveis e personalizadas com base em suas preferências dietéticas, nível de calorias e ingredientes disponíveis.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum DietaryFilter {
  VEGANO = 'Vegano',
  SEM_LACTOSE = 'Sem Lactose',
  SEM_GLUTEN = 'Sem Glúten',
  SEM_ACUCAR = 'Sem Açúcar'
}

export enum MealType {
  CAFE_DA_MANHA = 'Café da Manhã',
  ALMOCO = 'Almoço',
  JANTAR = 'Jantar',
  LANCHE = 'Lanche',
  SOBREMESA = 'Sobremesa'
}

export enum CalorieLevel {
  BAIXISSIMO = 'Baixíssimo (até 200 kcal)',
  BAIXO = 'Baixo (201-400 kcal)',
  MEDIO = 'Médio (401-600 kcal)',
  ALTO = 'Alto (601-800 kcal)',
  ALTISSIMO = 'Altíssimo (acima de 800 kcal)'
}

export enum Flavor {
  SALGADO = 'Salgado',
  DOCE = 'Doce'
}

export enum PrepMethod {
  COZIDO = 'Cozido',
  FRITO = 'Frito (Saudável)',
  GELADO = 'Gelado',
  AO_FORNO = 'Ao Forno',
  AIR_FRYER = 'Air Fryer',
  MICRO_ONDAS = 'Micro-ondas',
  APENAS_MISTURADO = 'Apenas Misturado'
}

export enum ResultOption {
  INGREDIENTES = 'Lista de Ingredientes',
  PREPARO = 'Forma de Preparo',
  CUSTO = 'Custo Estimado',
  IMAGEM = 'Imagem da Receita',
  TODOS = 'Todas as Opções'
}

export interface UserPreferences {
  dietaryFilters: DietaryFilter[];
  mealType: MealType;
  peopleCount: number;
  calorieLevel: CalorieLevel;
  flavor: Flavor;
  ingredients: string;
  prepMethods: PrepMethod[];
  resultOptions: ResultOption[];
}

export interface RecipeResult {
  title: string;
  description: string;
  ingredients?: string[];
  instructions?: string[];
  estimatedCost?: string;
  imageUrl?: string;
  macros: {
    protein: string;
    carbs: string;
    fats: string;
    calories: string;
  };
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { UserPreferences, RecipeResult } from "../types";

const API_KEY = process.env.API_KEY || '';

export const generateRecipe = async (prefs: UserPreferences): Promise<RecipeResult> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const prompt = `Crie uma receita saudável (FIT) com as seguintes preferências:
  - Filtros: ${prefs.dietaryFilters.join(', ')}
  - Tipo: ${prefs.mealType}
  - Para ${prefs.peopleCount} pessoas
  - Nível de calorias: ${prefs.calorieLevel}
  - Sabor: ${prefs.flavor}
  - Ingredientes base: ${prefs.ingredients || 'Qualquer um saudável'}
  - Métodos de preparo preferidos: ${prefs.prepMethods.join(', ') || 'Qualquer um saudável'}

  A receita deve ser balanceada nutricionalmente.
  Se solicitado custo, forneça em Reais (R$) baseado no mercado brasileiro.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          ingredients: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
          instructions: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
          estimatedCost: { type: Type.STRING },
          macros: {
            type: Type.OBJECT,
            properties: {
              protein: { type: Type.STRING },
              carbs: { type: Type.STRING },
              fats: { type: Type.STRING },
              calories: { type: Type.STRING },
            },
            required: ["protein", "carbs", "fats", "calories"]
          }
        },
        required: ["title", "description", "ingredients", "instructions", "macros"]
      },
    },
  });

  const recipeData = JSON.parse(response.text || '{}') as RecipeResult;

  // Optional: Generate image if requested
  if (prefs.resultOptions.includes('Imagem da Receita' as any) || prefs.resultOptions.includes('Todas as Opções' as any)) {
    try {
      const imgResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `Uma foto profissional de comida gourmet saudável e apetitosa de: ${recipeData.title}. Iluminação natural, close-up.` }]
        },
      });

      for (const part of imgResponse.candidates[0].content.parts) {
        if (part.inlineData) {
          recipeData.imageUrl = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }
    } catch (e) {
      console.error("Erro ao gerar imagem", e);
      recipeData.imageUrl = 'https://picsum.photos/800/600?random=1';
    }
  }

  return recipeData;
};

import React, { useState, useEffect } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  ResultOption, 
  UserPreferences, 
  RecipeResult 
} from './types';
import { generateRecipe } from './services/geminiService';
import StepForm from './components/StepForm';
import ResultScreen from './components/ResultScreen';
import SplashScreen from './components/SplashScreen';

const App: React.FC = () => {
  const [view, setView] = useState<'splash' | 'form' | 'loading' | 'result'>('splash');
  const [preferences, setPreferences] = useState<UserPreferences>({
    dietaryFilters: [],
    mealType: MealType.ALMOCO,
    peopleCount: 1,
    calorieLevel: CalorieLevel.MEDIO,
    flavor: Flavor.SALGADO,
    ingredients: '',
    prepMethods: [],
    resultOptions: [ResultOption.TODOS]
  });
  const [result, setResult] = useState<RecipeResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleStart = () => setView('form');

  const handleGenerate = async (prefs: UserPreferences) => {
    setPreferences(prefs);
    setView('loading');
    setError(null);
    try {
      const data = await generateRecipe(prefs);
      setResult(data);
      setView('result');
    } catch (err) {
      setError('Ocorreu um erro ao gerar sua receita. Tente novamente.');
      setView('form');
    }
  };

  const handleReset = () => {
    setView('form');
    setResult(null);
  };

  return (
    <div className="min-h-screen bg-emerald-50 text-slate-800">
      <div className="max-w-xl mx-auto min-h-screen bg-white shadow-xl relative overflow-hidden">
        {view === 'splash' && <SplashScreen onStart={handleStart} />}

        {view === 'form' && (
          <StepForm 
            initialData={preferences} 
            onSubmit={handleGenerate} 
            error={error}
          />
        )}

        {view === 'loading' && (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-6 animate-pulse mt-40">
            <div className="w-20 h-20 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
            <h2 className="text-2xl font-bold text-emerald-700">Cozinhando sua ideia...</h2>
            <p className="text-slate-500 italic">"Estamos selecionando os melhores ingredientes e calculando os macros para você."</p>
            <div className="space-y-2 w-full max-w-xs">
              <div className="h-2 bg-emerald-100 rounded-full overflow-hidden">
                <div className="h-full bg-emerald-500 animate-[loading_2s_ease-in-out_infinite]"></div>
              </div>
            </div>
          </div>
        )}

        {view === 'result' && result && (
          <ResultScreen 
            recipe={result} 
            prefs={preferences} 
            onBack={handleReset} 
          />
        )}
      </div>

      <style>{`
        @keyframes loading {
          0% { width: 0%; }
          50% { width: 100%; }
          100% { width: 0%; }
        }
      `}</style>
    </div>
  );
};

export default App;

