import React, { useState } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  ResultOption, 
  UserPreferences 
} from '../types';

interface StepFormProps {
  initialData: UserPreferences;
  onSubmit: (data: UserPreferences) => void;
  error: string | null;
}

const StepForm: React.FC<StepFormProps> = ({ initialData, onSubmit, error }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<UserPreferences>(initialData);

  const totalSteps = 5;

  const handleNext = () => {
    if (step === 1 && formData.dietaryFilters.length === 0) {
      alert("Selecione pelo menos um filtro dietético.");
      return;
    }
    if (step < totalSteps) setStep(step + 1);
    else onSubmit(formData);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const toggleDietary = (val: DietaryFilter) => {
    setFormData(prev => ({
      ...prev,
      dietaryFilters: prev.dietaryFilters.includes(val)
        ? prev.dietaryFilters.filter(f => f !== val)
        : [...prev.dietaryFilters, val]
    }));
  };

  const togglePrep = (val: PrepMethod) => {
    setFormData(prev => ({
      ...prev,
      prepMethods: prev.prepMethods.includes(val)
        ? prev.prepMethods.filter(p => p !== val)
        : [...prev.prepMethods, val]
    }));
  };

  const toggleResult = (val: ResultOption) => {
    setFormData(prev => ({
      ...prev,
      resultOptions: prev.resultOptions.includes(val)
        ? prev.resultOptions.filter(r => r !== val)
        : [...prev.resultOptions, val]
    }));
  };

  return (
    <div className="p-6 h-full flex flex-col">
      <div className="mb-8">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-bold text-slate-800">
            Passo {step} de {totalSteps}
          </h2>
          <span className="text-xs font-medium text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full">
            {Math.round((step / totalSteps) * 100)}% concluído
          </span>
        </div>
        <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
          <div 
            className="h-full bg-emerald-500 transition-all duration-300" 
            style={{ width: `${(step / totalSteps) * 100}%` }}
          ></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto pb-24">
        {error && (
          <div className="bg-red-50 text-red-600 p-4 rounded-xl mb-6 text-sm">
            {error}
          </div>
        )}

        {step === 1 && (
          <div className="space-y-6">
            <h3 className="text-2xl font-bold">Filtros Dietéticos</h3>
            <p className="text-slate-500 text-sm">Quais restrições ou escolhas alimentares devemos seguir?</p>
            <div className="grid grid-cols-1 gap-3">
              {Object.values(DietaryFilter).map(f => (
                <label 
                  key={f} 
                  className={`flex items-center justify-between p-4 rounded-xl border-2 transition-all cursor-pointer ${
                    formData.dietaryFilters.includes(f) 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                      : 'border-slate-100 hover:border-slate-200'
                  }`}
                >
                  <span className="font-medium">{f}</span>
                  <input 
                    type="checkbox" 
                    checked={formData.dietaryFilters.includes(f)}
                    onChange={() => toggleDietary(f)}
                    className="w-5 h-5 accent-emerald-500"
                  />
                </label>
              ))}
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <h3 className="text-2xl font-bold">Refeição & Sabor</h3>
            <div className="space-y-4">
              <label className="block">
                <span className="text-sm font-semibold text-slate-700">Tipo de Refeição</span>
                <select 
                  value={formData.mealType}
                  onChange={e => setFormData({...formData, mealType: e.target.value as MealType})}
                  className="mt-1 block w-full p-4 rounded-xl border-2 border-slate-100 focus:border-emerald-500 focus:ring-0 transition-all"
                >
                  {Object.values(MealType).map(m => <option key={m} value={m}>{m}</option>)}
                </select>
              </label>

              <label className="block">
                <span className="text-sm font-semibold text-slate-700">Sabor Predominante</span>
                <div className="grid grid-cols-2 gap-3 mt-1">
                  {Object.values(Flavor).map(f => (
                    <button
                      key={f}
                      onClick={() => setFormData({...formData, flavor: f})}
                      className={`py-4 rounded-xl border-2 font-medium transition-all ${
                        formData.flavor === f 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100'
                      }`}
                    >
                      {f}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6">
            <h3 className="text-2xl font-bold">Quantidade & Calorias</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-sm font-semibold text-slate-700">Para quantas pessoas? (1-10)</span>
                <input 
                  type="number" 
                  min="1" 
                  max="10" 
                  value={formData.peopleCount}
                  onChange={e => setFormData({...formData, peopleCount: parseInt(e.target.value) || 1})}
                  className="mt-1 block w-full p-4 rounded-xl border-2 border-slate-100 focus:border-emerald-500 outline-none"
                />
              </label>

              <label className="block">
                <span className="text-sm font-semibold text-slate-700">Meta Calórica</span>
                <div className="space-y-2 mt-2">
                  {Object.values(CalorieLevel).map(c => (
                    <button
                      key={c}
                      onClick={() => setFormData({...formData, calorieLevel: c})}
                      className={`w-full text-left p-4 rounded-xl border-2 font-medium transition-all ${
                        formData.calorieLevel === c 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100'
                      }`}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6">
            <h3 className="text-2xl font-bold">Ingredientes & Preparo</h3>
            <div className="space-y-4">
              <label className="block">
                <span className="text-sm font-semibold text-slate-700">Ingredientes Específicos ou Tipo</span>
                <input 
                  type="text" 
                  placeholder="Ex: frango, quinoa, abacate, crepe..."
                  value={formData.ingredients}
                  onChange={e => setFormData({...formData, ingredients: e.target.value})}
                  className="mt-1 block w-full p-4 rounded-xl border-2 border-slate-100 focus:border-emerald-500 outline-none"
                />
              </label>

              <label className="block">
                <span className="text-sm font-semibold text-slate-700">Métodos de Preparo Preferidos</span>
                <div className="grid grid-cols-2 gap-2 mt-2">
                  {Object.values(PrepMethod).map(p => (
                    <button
                      key={p}
                      onClick={() => togglePrep(p)}
                      className={`p-3 rounded-xl border-2 text-xs font-semibold transition-all ${
                        formData.prepMethods.includes(p) 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100 text-slate-500'
                      }`}
                    >
                      {p}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 5 && (
          <div className="space-y-6">
            <h3 className="text-2xl font-bold">O que incluir no resultado?</h3>
            <div className="grid grid-cols-1 gap-3">
              {Object.values(ResultOption).map(r => (
                <label 
                  key={r} 
                  className={`flex items-center justify-between p-4 rounded-xl border-2 transition-all cursor-pointer ${
                    formData.resultOptions.includes(r) 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                      : 'border-slate-100'
                  }`}
                >
                  <span className="font-medium">{r}</span>
                  <input 
                    type="checkbox" 
                    checked={formData.resultOptions.includes(r)}
                    onChange={() => toggleResult(r)}
                    className="w-5 h-5 accent-emerald-500"
                  />
                </label>
              ))}
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 w-full p-6 bg-white border-t border-slate-100 flex gap-4">
        {step > 1 && (
          <button 
            onClick={handleBack}
            className="flex-1 py-4 border-2 border-emerald-500 text-emerald-600 rounded-xl font-bold hover:bg-emerald-50 transition-all"
          >
            Voltar
          </button>
        )}
        <button 
          onClick={handleNext}
          className="flex-[2] py-4 bg-emerald-500 text-white rounded-xl font-bold hover:bg-emerald-600 transition-all shadow-lg shadow-emerald-100"
        >
          {step === totalSteps ? 'Gerar Receita' : 'Continuar'}
        </button>
      </div>
    </div>
  );
};

export default StepForm;

import React from 'react';
import { RecipeResult, UserPreferences, ResultOption } from '../types';

interface ResultScreenProps {
  recipe: RecipeResult;
  prefs: UserPreferences;
  onBack: () => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ recipe, prefs, onBack }) => {
  const handleShare = async () => {
    const text = `🥗 *Receita Fit: ${recipe.title}*\n\n${recipe.description}\n\n📊 *Macros:* ${recipe.macros.calories}, P: ${recipe.macros.protein}, C: ${recipe.macros.carbs}, G: ${recipe.macros.fats}\n\nConfira no Receitas Fit Generator!`;

    if (navigator.share) {
      try {
        await navigator.share({
          title: `Receita Fit: ${recipe.title}`,
          text: text,
          url: window.location.href,
        });
      } catch (e) {
        console.log('Error sharing', e);
      }
    } else {
      // Fallback para WhatsApp se o navigator.share falhar (ex: em desktops)
      const encodedText = encodeURIComponent(text);
      window.open(`https://wa.me/?text=${encodedText}`, '_blank');
    }
  };

  const handleDownloadPDF = () => {
    window.print();
  };

  const showIngredients = prefs.resultOptions.includes(ResultOption.INGREDIENTES) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showInstructions = prefs.resultOptions.includes(ResultOption.PREPARO) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showCost = prefs.resultOptions.includes(ResultOption.CUSTO) || prefs.resultOptions.includes(ResultOption.TODOS);

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-32">
      {/* Imagem de Cabeçalho */}
      <div className="relative h-72 flex-shrink-0 print:hidden">
        <img 
          src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} 
          alt={recipe.title}
          className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent"></div>
        <button 
          onClick={onBack}
          className="absolute top-4 left-4 w-10 h-10 bg-white/90 backdrop-blur rounded-full flex items-center justify-center shadow-lg hover:bg-white transition-colors"
        >
          <span className="text-xl">←</span>
        </button>
      </div>

      <div className="px-6 -mt-8 relative bg-white rounded-t-3xl pt-8 space-y-8">
        {/* Título e Meta */}
        <div>
          <div className="flex items-center gap-2 mb-2">
            {prefs.dietaryFilters.map(f => (
              <span key={f} className="text-[10px] bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-full font-bold uppercase tracking-wider">
                {f}
              </span>
            ))}
          </div>
          <h1 className="text-3xl font-extrabold text-slate-800 leading-tight">{recipe.title}</h1>
          <div className="flex items-center gap-4 mt-2 text-slate-500 text-sm font-medium">
            <span className="flex items-center gap-1">👥 {prefs.peopleCount} {prefs.peopleCount > 1 ? 'pessoas' : 'pessoa'}</span>
            <span className="flex items-center gap-1">🍽️ {prefs.mealType}</span>
          </div>
        </div>

        {/* Macronutrientes */}
        <div className="grid grid-cols-4 gap-2 py-5 bg-slate-50 rounded-2xl px-3 border border-slate-100">
          <div className="text-center">
            <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">Calorias</p>
            <p className="text-sm font-bold text-slate-800">{recipe.macros.calories}</p>
          </div>
          <div className="text-center border-l border-slate-200">
            <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">Proteína</p>
            <p className="text-sm font-bold text-slate-800">{recipe.macros.protein}</p>
          </div>
          <div className="text-center border-l border-slate-200">
            <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">Carbs</p>
            <p className="text-sm font-bold text-slate-800">{recipe.macros.carbs}</p>
          </div>
          <div className="text-center border-l border-slate-200">
            <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">Gordura</p>
            <p className="text-sm font-bold text-slate-800">{recipe.macros.fats}</p>
          </div>
        </div>

        {/* Descrição */}
        <div className="space-y-3">
          <h3 className="text-lg font-bold flex items-center gap-2 text-slate-800">
            <span className="w-1.5 h-6 bg-emerald-500 rounded-full"></span>
