                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6">
            <h3 className="text-2xl font-bold text-slate-800">Ingredientes & Preparo</h3>
            <div className="space-y-4">
              <label className="block">
