import React, { useState } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  ResultOption, 
  UserPreferences, 
  RecipeResult 
} from './types';
import { generateRecipe } from './services/geminiService';
import StepForm from './components/StepForm';
import ResultScreen from './components/ResultScreen';
import SplashScreen from './components/SplashScreen';
import FavoritesList from './components/FavoritesList';
import HistoryList from './components/HistoryList';

const App: React.FC = () => {
  const [view, setView] = useState<'splash' | 'form' | 'loading' | 'result' | 'favorites' | 'history'>('splash');
  const [preferences, setPreferences] = useState<UserPreferences>({
    dietaryFilters: [],
    mealType: MealType.ALMOCO,
    peopleCount: 1,
    calorieLevel: CalorieLevel.MEDIO,
    flavor: Flavor.SALGADO,
    ingredients: '',
    prepMethods: [],
    resultOptions: [ResultOption.TODOS]
  });
  const [result, setResult] = useState<RecipeResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleStart = () => setView('form');
  const handleOpenFavorites = () => setView('favorites');
  const handleOpenHistory = () => setView('history');

  const handleGenerate = async (prefs: UserPreferences) => {
    setPreferences(prefs);
    setView('loading');
    setError(null);
    try {
      const data = await generateRecipe(prefs);
      setResult(data);
      setView('result');
    } catch (err) {
      setError('Ocorreu um erro ao gerar sua receita. Tente novamente.');
      setView('form');
    }
  };

  const handleSelectRecipe = (recipe: RecipeResult) => {
    setResult(recipe);
    setView('result');
  };

  const handleReset = () => {
    setView('splash');
    setResult(null);
  };

  const handleSaveToHistory = (recipe: RecipeResult) => {
    const history = JSON.parse(localStorage.getItem('fit_recipes_history') || '[]');
    const exists = history.some((h: RecipeResult) => h.title === recipe.title);
    if (!exists) {
      const newHistory = [recipe, ...history].slice(0, 20); // Limita a 20 itens
      localStorage.setItem('fit_recipes_history', JSON.stringify(newHistory));
    }
    setView('history');
  };

  return (
    <div className="min-h-screen bg-emerald-50 text-slate-800">
      <div className="max-w-xl mx-auto min-h-screen bg-white shadow-xl relative overflow-hidden">
        {view === 'splash' && (
          <SplashScreen 
            onStart={handleStart} 
            onOpenFavorites={handleOpenFavorites} 
            onOpenHistory={handleOpenHistory}
          />
        )}

        {view === 'form' && (
          <StepForm 
            initialData={preferences} 
            onSubmit={handleGenerate} 
            error={error}
          />
        )}

        {view === 'loading' && (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-6 animate-pulse mt-40">
            <div className="w-20 h-20 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
            <h2 className="text-2xl font-bold text-emerald-700">Cozinhando sua ideia...</h2>
            <p className="text-slate-500 italic">"Estamos selecionando os melhores ingredientes e calculando os macros para você."</p>
            <div className="space-y-2 w-full max-w-xs">
              <div className="h-2 bg-emerald-100 rounded-full overflow-hidden">
                <div className="h-full bg-emerald-500 animate-[loading_2s_ease-in-out_infinite]"></div>
              </div>
            </div>
          </div>
        )}

        {view === 'result' && result && (
          <ResultScreen 
            recipe={result} 
            prefs={preferences.dietaryFilters.length ? preferences : undefined} 
            onBack={handleReset} 
            onSaveHistory={handleSaveToHistory}
          />
        )}

        {view === 'favorites' && (
          <FavoritesList 
            onSelect={handleSelectRecipe}
            onBack={() => setView('splash')}
            onGoToHistory={() => setView('history')}
            onNewRecipe={handleStart}
          />
        )}

        {view === 'history' && (
          <HistoryList 
            onSelect={handleSelectRecipe}
            onBack={() => setView('splash')}
            onGoToFavorites={() => setView('favorites')}
            onNewRecipe={handleStart}
          />
        )}
      </div>

      <style>{`
        @keyframes loading {
          0% { width: 0%; }
          50% { width: 100%; }
          100% { width: 0%; }
        }
      `}</style>
    </div>
  );
};

export default App;

