import React, { useState, useEffect } from 'react';
import { RecipeResult, UserPreferences, ResultOption } from '../types';

interface ResultScreenProps {
  recipe: RecipeResult;
  prefs?: UserPreferences;
  onBack: () => void;
  onSaveHistory: (recipe: RecipeResult) => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ recipe, prefs, onBack, onSaveHistory }) => {
  const [isFavorite, setIsFavorite] = useState(false);

  useEffect(() => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    const exists = favorites.some((f: RecipeResult) => f.title === recipe.title);
    setIsFavorite(exists);
  }, [recipe.title]);

  const toggleFavorite = () => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    let newFavorites;
    if (isFavorite) {
      newFavorites = favorites.filter((f: RecipeResult) => f.title !== recipe.title);
    } else {
      newFavorites = [...favorites, recipe];
    }
    localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
    setIsFavorite(!isFavorite);
  };

  const handleShare = async () => {
    const text = `🥗 *Receita Fit: ${recipe.title}*\n\n${recipe.description}\n\n📊 *Macros:* Cal: ${recipe.macros.calories}, P: ${recipe.macros.protein}, C: ${recipe.macros.carbs}, G: ${recipe.macros.fats}\n\nConfira mais no Receitas Fit Generator!`;

    if (navigator.share) {
      try {
        await navigator.share({
          title: `Receita: ${recipe.title}`,
          text: text,
          url: window.location.href,
        });
        return;
      } catch (e) {
        console.log('Error sharing', e);
      }
    } 

    const encodedText = encodeURIComponent(text);
    window.open(`https://wa.me/?text=${encodedText}`, '_blank');
  };

  const handleExportAndHistory = () => {
    // 1. Salva no histórico primeiro
    onSaveHistory(recipe);

    // 2. Aciona a impressão (que permite salvar como PDF, Drive, Dropbox no celular/PC)
    // Usamos um pequeno timeout para garantir que a UI não trave antes do redirecionamento
    setTimeout(() => {
      window.print();
    }, 300);
  };

  const showIngredients = !prefs || prefs.resultOptions.includes(ResultOption.INGREDIENTES) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showInstructions = !prefs || prefs.resultOptions.includes(ResultOption.PREPARO) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showCost = !prefs || prefs.resultOptions.includes(ResultOption.CUSTO) || prefs.resultOptions.includes(ResultOption.TODOS);

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-32 text-slate-800">
      {/* Imagem de Cabeçalho */}
      <div className="relative h-72 flex-shrink-0 print:hidden">
        <img 
          src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} 
          alt={recipe.title}
          className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent"></div>
        <button 
          type="button"
          onClick={onBack}
          className="absolute top-4 left-4 w-10 h-10 bg-white/90 backdrop-blur rounded-full flex items-center justify-center shadow-lg hover:bg-white transition-colors z-10"
        >
          <span className="text-xl text-slate-800 font-bold">←</span>
        </button>
        <button 
          type="button"
          onClick={toggleFavorite}
          className={`absolute top-4 right-4 w-10 h-10 rounded-full flex items-center justify-center shadow-lg transition-all z-10 ${isFavorite ? 'bg-red-500 text-white' : 'bg-white/90 text-red-500 hover:bg-white'}`}
        >
          <span className="text-xl">{isFavorite ? '❤️' : '🤍'}</span>
        </button>
      </div>

      <div className="px-6 -mt-8 relative bg-white rounded-t-3xl pt-8 space-y-8">
        <div>
          {prefs && (
            <div className="flex items-center gap-2 mb-2">
              {prefs.dietaryFilters.map(f => (
                <span key={f} className="text-[10px] bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-full font-bold uppercase tracking-wider">
                  {f}
                </span>
              ))}
            </div>
          )}
          <h1 className="text-3xl font-extrabold text-slate-800 leading-tight">{recipe.title}</h1>
          <div className="flex items-center gap-4 mt-2 text-slate-500 text-sm font-medium">
            {prefs && <span className="flex items-center gap-1">👥 {prefs.peopleCount} {prefs.peopleCount > 1 ? 'pessoas' : 'pessoa'}</span>}
            {prefs && <span className="flex items-center gap-1">🍽️ {prefs.mealType}</span>}
          </div>
        </div>

        {/* Macronutrientes Card */}
        <div className="grid grid-cols-4 gap-2 py-5 bg-slate-50 rounded-2xl px-3 border border-slate-100 shadow-sm">
          <div className="text-center">
            <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">Calorias</p>
            <p className="text-sm font-bold text-slate-800">{recipe.macros.calories}</p>
          </div>
          <div className="text-center border-l border-slate-200">
            <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">Proteína</p>
            <p className="text-sm font-bold text-slate-800">{recipe.macros.protein}</p>
          </div>
          <div className="text-center border-l border-slate-200">
            <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">Carbs</p>
            <p className="text-sm font-bold text-slate-800">{recipe.macros.carbs}</p>
          </div>
          <div className="text-center border-l border-slate-200">
            <p className="text-[10px] text-emerald-600 font-bold uppercase mb-1">Gordura</p>
            <p className="text-sm font-bold text-slate-800">{recipe.macros.fats}</p>
          </div>
        </div>

        {/* Conteúdo da Receita */}
        <div className="space-y-8">
          <div className="space-y-3">
            <h3 className="text-lg font-bold flex items-center gap-2 text-slate-800">
              <span className="w-1.5 h-6 bg-emerald-500 rounded-full"></span>
              Sobre a Receita
            </h3>
            <p className="text-slate-600 text-sm leading-relaxed">{recipe.description}</p>
          </div>

          {showIngredients && recipe.ingredients && (
            <div className="space-y-4">
              <h3 className="text-lg font-bold flex items-center gap-2 text-slate-800">
                <span className="w-1.5 h-6 bg-emerald-500 rounded-full"></span>
                Ingredientes
              </h3>
              <div className="bg-slate-50 rounded-2xl p-4 space-y-3">
                {recipe.ingredients.map((ing, i) => (
                  <div key={i} className="flex items-start gap-3 text-slate-600 text-sm">
                    <div className="mt-1.5 w-1.5 h-1.5 bg-emerald-400 rounded-full flex-shrink-0"></div>
                    <span>{ing}</span>
                  </div>
                ))}
              </div>
            </div>
