    const encodedText = encodeURIComponent(getShareText());
    window.open(`https://wa.me/?text=${encodedText}`, '_blank');
    setShowShareModal(false);
  };

  const handleExportPDF = () => {
    setShowShareModal(false);
    onSaveHistory(recipe);
    setTimeout(() => {
      window.print();
    }, 500);
  };

  const handleNativeShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: recipe.title,
          text: getShareText(),
          url: window.location.href,
        });
        setShowShareModal(false);
      } catch (e) {
        console.log('Error sharing', e);
      }
    } else {
      shareViaWhatsApp();
    }
  };

  const showIngredients = !prefs || prefs.resultOptions.includes(ResultOption.INGREDIENTES) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showInstructions = !prefs || prefs.resultOptions.includes(ResultOption.PREPARO) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showCost = !prefs || prefs.resultOptions.includes(ResultOption.CUSTO) || prefs.resultOptions.includes(ResultOption.TODOS);

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-40 text-slate-800">
      {/* Imagem de Cabeçalho */}
      <div className="relative h-72 flex-shrink-0 print:hidden">
        <img 
          src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} 
          alt={recipe.title}
          className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent"></div>
        <button 
          type="button"
          onClick={onBack}
          className="absolute top-4 left-4 w-10 h-10 bg-white/90 backdrop-blur rounded-full flex items-center justify-center shadow-lg hover:bg-white transition-colors z-10"
        >
          <span className="text-xl text-slate-800 font-bold">←</span>
        </button>
      </div>

      <div className="px-6 -mt-12 relative bg-white rounded-t-[2.5rem] pt-10 space-y-8">
        {/* Favorito - Botão Ultra Proeminente */}
        <div className="print:hidden">
          <button 
            onClick={toggleFavorite}
            className={`w-full py-5 rounded-2xl font-black text-lg flex items-center justify-center gap-4 transition-all transform active:scale-95 shadow-xl ${
              isFavorite 
              ? 'bg-red-500 text-white shadow-red-200' 
              : 'bg-white text-red-500 border-4 border-red-500 hover:bg-red-50'
            }`}
          >
            <span className="text-3xl">{isFavorite ? '❤️' : '🤍'}</span>
            {isFavorite ? 'RECEITA FAVORITADA' : 'SALVAR COMO FAVORITO'}
          </button>
        </div>

        {/* Info Cabeçalho */}
        <div>
          {prefs && prefs.dietaryFilters.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-3">
              {prefs.dietaryFilters.map(f => (
                <span key={f} className="text-[10px] bg-emerald-100 text-emerald-700 px-3 py-1 rounded-full font-bold uppercase tracking-widest">
                  {f}
                </span>
              ))}
            </div>
          )}
          <h1 className="text-3xl font-black text-slate-900 leading-tight mb-2">{recipe.title}</h1>
          <div className="flex items-center gap-5 text-slate-500 text-sm font-bold bg-slate-50 p-3 rounded-xl w-fit">
            <span className="flex items-center gap-2">👥 {prefs?.peopleCount || 1} { (prefs?.peopleCount || 1) > 1 ? 'pessoas' : 'pessoa'}</span>
            <span className="flex items-center gap-2">🍽️ {prefs?.mealType}</span>
          </div>
        </div>

        {/* Macros */}
        <div className="grid grid-cols-4 gap-3 py-6 bg-emerald-900 rounded-[2rem] px-4 shadow-inner text-white">
          <div className="text-center">
            <p className="text-[9px] opacity-70 font-bold uppercase mb-1">Calorias</p>
            <p className="text-sm font-black">{recipe.macros.calories}</p>
          </div>
          <div className="text-center border-l border-white/20">
            <p className="text-[9px] opacity-70 font-bold uppercase mb-1">Proteína</p>
            <p className="text-sm font-black">{recipe.macros.protein}</p>
          </div>
          <div className="text-center border-l border-white/20">
            <p className="text-[9px] opacity-70 font-bold uppercase mb-1">Carbs</p>
            <p className="text-sm font-black">{recipe.macros.carbs}</p>
          </div>
          <div className="text-center border-l border-white/20">
            <p className="text-[9px] opacity-70 font-bold uppercase mb-1">Gorduras</p>
            <p className="text-sm font-black">{recipe.macros.fats}</p>
          </div>
        </div>

        {/* Conteúdo */}
        <div className="space-y-10">
          <section className="space-y-3">
            <h3 className="text-xl font-black text-slate-800 border-b-4 border-emerald-500 w-fit pb-1">Sobre</h3>
            <p className="text-slate-600 text-base leading-relaxed">{recipe.description}</p>
          </section>

          {showIngredients && (
            <section className="space-y-4">
              <h3 className="text-xl font-black text-slate-800 border-b-4 border-emerald-500 w-fit pb-1">Ingredientes</h3>
              <div className="grid gap-3">
                {recipe.ingredients?.map((ing, i) => (
                  <div key={i} className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100">
                    <div className="w-2 h-2 bg-emerald-500 rounded-full"></div>
                    <span className="text-slate-700 font-medium">{ing}</span>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showInstructions && (
            <section className="space-y-6">
              <h3 className="text-xl font-black text-slate-800 border-b-4 border-emerald-500 w-fit pb-1">Preparo</h3>
              <div className="space-y-8">
                {recipe.instructions?.map((step, i) => (
                  <div key={i} className="flex gap-5 relative">
                    <span className="flex-shrink-0 w-10 h-10 rounded-2xl bg-emerald-500 text-white flex items-center justify-center font-black text-lg shadow-lg shadow-emerald-100">
                      {i + 1}
                    </span>
                    <p className="text-slate-600 text-base leading-relaxed pt-1">{step}</p>
                  </div>
                ))}
