import React, { useState } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  ResultOption, 
  UserPreferences 
} from '../types';

interface StepFormProps {
  initialData: UserPreferences;
  onSubmit: (data: UserPreferences) => void;
  error: string | null;
}

const StepForm: React.FC<StepFormProps> = ({ initialData, onSubmit, error }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<UserPreferences>(initialData);

  const totalSteps = 5;

  const handleNext = () => {
    if (step === 1 && formData.dietaryFilters.length === 0) {
      alert("Selecione pelo menos um filtro dietético.");
      return;
    }
    if (step < totalSteps) setStep(step + 1);
    else onSubmit(formData);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const toggleDietary = (val: DietaryFilter) => {
    setFormData(prev => ({
      ...prev,
      dietaryFilters: prev.dietaryFilters.includes(val)
        ? prev.dietaryFilters.filter(f => f !== val)
        : [...prev.dietaryFilters, val]
    }));
  };

  const togglePrep = (val: PrepMethod) => {
    setFormData(prev => ({
      ...prev,
      prepMethods: prev.prepMethods.includes(val)
        ? prev.prepMethods.filter(p => p !== val)
        : [...prev.prepMethods, val]
    }));
  };

  const toggleResult = (val: ResultOption) => {
    setFormData(prev => ({
      ...prev,
      resultOptions: prev.resultOptions.includes(val)
        ? prev.resultOptions.filter(r => r !== val)
        : [...prev.resultOptions, val]
    }));
  };

  return (
    <div className="p-6 h-full flex flex-col bg-white">
      <div className="mb-8 print:hidden">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">
            Passo {step} <span className="text-emerald-500">/ {totalSteps}</span>
          </h2>
          <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full uppercase">
            {Math.round((step / totalSteps) * 100)}%
          </span>
        </div>
        <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
          <div 
            className="h-full bg-emerald-500 transition-all duration-500 ease-out" 
            style={{ width: `${(step / totalSteps) * 100}%` }}
          ></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto pb-24">
        {error && (
          <div className="bg-red-50 text-red-600 p-5 rounded-2xl mb-6 text-sm font-bold border-2 border-red-100">
            ⚠️ {error}
          </div>
        )}

        {step === 1 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Perfil Alimentar</h3>
            <p className="text-slate-500 text-sm font-medium italic">Selecione suas restrições ou escolhas de saúde.</p>
            <div className="grid grid-cols-1 gap-4">
              {Object.values(DietaryFilter).map(f => (
                <label 
                  key={f} 
                  className={`flex items-center justify-between p-5 rounded-[1.5rem] border-4 transition-all cursor-pointer ${
                    formData.dietaryFilters.includes(f) 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                      : 'border-slate-100 hover:border-slate-200 bg-white text-slate-400'
                  }`}
                >
                  <span className="font-black text-lg">{f}</span>
                  <input 
                    type="checkbox" 
                    checked={formData.dietaryFilters.includes(f)}
                    onChange={() => toggleDietary(f)}
                    className="w-6 h-6 accent-emerald-500"
                  />
                </label>
              ))}
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Refeição & Gosto</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-sm font-black text-slate-500 uppercase tracking-widest ml-1">Momento do Dia</span>
                <select 
                  value={formData.mealType}
                  onChange={e => setFormData({...formData, mealType: e.target.value as MealType})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-100 focus:border-emerald-500 focus:ring-0 transition-all bg-white text-slate-800 font-bold text-lg outline-none"
                >
                  {Object.values(MealType).map(m => <option key={m} value={m}>{m}</option>)}
                </select>
              </label>

              <label className="block">
                <span className="text-sm font-black text-slate-500 uppercase tracking-widest ml-1">Sabor Favorito</span>
                <div className="grid grid-cols-2 gap-4 mt-2">
                  {Object.values(Flavor).map(f => (
                    <button
                      type="button"
                      key={f}
                      onClick={() => setFormData({...formData, flavor: f})}
                      className={`py-5 rounded-2xl border-4 font-black transition-all text-lg ${
                        formData.flavor === f 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100 bg-white text-slate-300'
                      }`}
                    >
                      {f}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Porções & Calorias</h3>
            <div className="space-y-8">
              <label className="block">
                <span className="text-sm font-black text-slate-500 uppercase tracking-widest ml-1">Número de Pessoas</span>
                <div className="flex items-center gap-4 mt-3">
                  <button 
                    onClick={() => setFormData(p => ({...p, peopleCount: Math.max(1, p.peopleCount - 1)}))}
                    className="w-14 h-14 rounded-2xl border-4 border-slate-100 flex items-center justify-center text-2xl font-black"
                  > - </button>
                  <span className="flex-1 text-center text-4xl font-black text-emerald-600">{formData.peopleCount}</span>
                  <button 
                    onClick={() => setFormData(p => ({...p, peopleCount: Math.min(10, p.peopleCount + 1)}))}
                    className="w-14 h-14 rounded-2xl border-4 border-slate-100 flex items-center justify-center text-2xl font-black"
                  > + </button>
                </div>
              </label>

              <label className="block">
                <span className="text-sm font-black text-slate-500 uppercase tracking-widest ml-1">Intensidade Energética</span>
                <div className="space-y-3 mt-3">
                  {Object.values(CalorieLevel).map(c => (
                    <button
                      type="button"
                      key={c}
                      onClick={() => setFormData({...formData, calorieLevel: c})}
                      className={`w-full text-left p-5 rounded-2xl border-4 font-bold transition-all ${
                        formData.calorieLevel === c 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100 bg-white text-slate-400'
                      }`}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Ingredientes</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-sm font-black text-slate-500 uppercase tracking-widest ml-1">O que tem na geladeira?</span>
                <textarea 
                  rows={3}
                  placeholder="Ex: frango, brócolis, grão de bico..."
                  value={formData.ingredients}
                  onChange={e => setFormData({...formData, ingredients: e.target.value})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-100 focus:border-emerald-500 outline-none bg-white text-slate-800 font-bold placeholder:text-slate-300"
                />
              </label>

              <label className="block">
                <span className="text-sm font-black text-slate-500 uppercase tracking-widest ml-1">Como prefere preparar?</span>
                <div className="grid grid-cols-2 gap-3 mt-3">
                  {Object.values(PrepMethod).map(p => (
                    <button
                      type="button"
                      key={p}
                      onClick={() => togglePrep(p)}
                      className={`p-3 rounded-xl border-2 text-xs font-black transition-all ${
                        formData.prepMethods.includes(p) 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100 bg-white text-slate-400'
                      }`}
                    >
                      {p}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 5 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Detalhes do Resultado</h3>
            <div className="grid grid-cols-1 gap-4">
              {Object.values(ResultOption).map(r => (
                <label 
                  key={r} 
                  className={`flex items-center justify-between p-5 rounded-[1.5rem] border-4 transition-all cursor-pointer ${
                    formData.resultOptions.includes(r) 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                      : 'border-slate-100 bg-white text-slate-400'
                  }`}
                >
                  <span className="font-black text-lg">{r}</span>
                  <input 
                    type="checkbox" 
                    checked={formData.resultOptions.includes(r)}
                    onChange={() => toggleResult(r)}
                    className="w-6 h-6 accent-emerald-500"
                  />
                </label>
              ))}
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 w-full p-6 bg-white border-t border-slate-100 flex gap-4 z-20">
        {step > 1 && (
          <button 
            type="button"
            onClick={handleBack}
            className="flex-1 py-5 border-4 border-emerald-500 text-emerald-600 rounded-2xl font-black hover:bg-emerald-50 transition-all active:scale-95"
          >
            VOLTAR
          </button>
        )}
        <button 
          type="button"
          onClick={handleNext}
          className="flex-[2] py-5 bg-emerald-500 text-white rounded-2xl font-black text-xl hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-200 active:scale-95 uppercase"
        >
          {step === totalSteps ? 'CRIAR RECEITA 🥗' : 'PRÓXIMO'}
        </button>
      </div>
    </div>
  );
};

