import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { UserPreferences, RecipeResult } from "../types";

const API_KEY = process.env.API_KEY || '';

export const generateRecipe = async (prefs: UserPreferences): Promise<RecipeResult> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const prompt = `Crie uma receita saudável (FIT) com as seguintes preferências:
  - Filtros: ${prefs.dietaryFilters.join(', ')}
  - Tipo de Refeição: ${prefs.mealType}
  - Tipo de Prato desejado: ${prefs.dishType || 'Qualquer um saudável'}
  - Para ${prefs.peopleCount} pessoas
  - Nível de calorias: ${prefs.calorieLevel}
  - Sabor: ${prefs.flavor}
  - Ingrediente(s) Favorito(s): ${prefs.ingredients || 'Qualquer um saudável'}
  - Métodos de preparo preferidos: ${prefs.prepMethods.join(', ') || 'Qualquer um saudável'}

  A receita deve ser balanceada nutricionalmente.
  Se solicitado custo, forneça em Reais (R$) baseado no mercado brasileiro.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          ingredients: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
          instructions: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
          estimatedCost: { type: Type.STRING },
          macros: {
            type: Type.OBJECT,
            properties: {
              protein: { type: Type.STRING },
              carbs: { type: Type.STRING },
              fats: { type: Type.STRING },
              calories: { type: Type.STRING },
            },
            required: ["protein", "carbs", "fats", "calories"]
          }
        },
        required: ["title", "description", "ingredients", "instructions", "macros"]
      },
    },
  });

  const recipeData = JSON.parse(response.text || '{}') as RecipeResult;

  // Optional: Generate image if requested
  if (prefs.resultOptions.includes('Imagem da Receita' as any) || prefs.resultOptions.includes('Todas as Opções' as any)) {
    try {
      const imgResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `Uma foto profissional de comida gourmet saudável e apetitosa de: ${recipeData.title}. Iluminação natural, close-up.` }]
        },
      });

      for (const part of imgResponse.candidates[0].content.parts) {
        if (part.inlineData) {
          recipeData.imageUrl = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }
    } catch (e) {
      console.error("Erro ao gerar imagem", e);
      recipeData.imageUrl = 'https://picsum.photos/800/600?random=1';
    }
  }

  return recipeData;
};

import React, { useState } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  ResultOption, 
  UserPreferences 
} from '../types';

interface StepFormProps {
  initialData: UserPreferences;
  onSubmit: (data: UserPreferences) => void;
  error: string | null;
}

const StepForm: React.FC<StepFormProps> = ({ initialData, onSubmit, error }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<UserPreferences>({
    ...initialData,
    dishType: initialData.dishType || ''
  });

  const totalSteps = 5;

  const handleNext = () => {
    if (step === 1 && formData.dietaryFilters.length === 0) {
      alert("Selecione pelo menos um filtro dietético.");
      return;
    }
    if (step < totalSteps) setStep(step + 1);
    else onSubmit(formData);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const toggleDietary = (val: DietaryFilter) => {
    setFormData(prev => ({
      ...prev,
      dietaryFilters: prev.dietaryFilters.includes(val)
        ? prev.dietaryFilters.filter(f => f !== val)
        : [...prev.dietaryFilters, val]
    }));
  };

  const togglePrep = (val: PrepMethod) => {
    setFormData(prev => ({
      ...prev,
      prepMethods: prev.prepMethods.includes(val)
        ? prev.prepMethods.filter(p => p !== val)
        : [...prev.prepMethods, val]
    }));
  };

  const toggleResult = (val: ResultOption) => {
    setFormData(prev => ({
      ...prev,
      resultOptions: prev.resultOptions.includes(val)
        ? prev.resultOptions.filter(r => r !== val)
        : [...prev.resultOptions, val]
    }));
  };

  return (
    <div className="p-6 h-full flex flex-col bg-white">
      <div className="mb-8 print:hidden">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">
            Passo {step} <span className="text-emerald-500">/ {totalSteps}</span>
          </h2>
          <span className="text-xs font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full uppercase">
            {Math.round((step / totalSteps) * 100)}%
          </span>
        </div>
        <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
          <div 
            className="h-full bg-emerald-500 transition-all duration-500 ease-out" 
            style={{ width: `${(step / totalSteps) * 100}%` }}
          ></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto pb-24">
        {error && (
          <div className="bg-red-50 text-red-600 p-5 rounded-2xl mb-6 text-sm font-bold border-2 border-red-100">
            ⚠️ {error}
          </div>
        )}

        {step === 1 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Perfil Alimentar</h3>
            <p className="text-slate-500 text-base font-medium italic">Selecione suas restrições ou escolhas de saúde.</p>
            <div className="grid grid-cols-1 gap-4">
              {Object.values(DietaryFilter).map(f => (
                <label 
                  key={f} 
                  className={`flex items-center justify-between p-5 rounded-[1.5rem] border-4 transition-all cursor-pointer ${
                    formData.dietaryFilters.includes(f) 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                      : 'border-slate-100 hover:border-slate-200 bg-white text-slate-400'
                  }`}
                >
                  <span className="font-black text-lg">{f}</span>
                  <input 
                    type="checkbox" 
                    checked={formData.dietaryFilters.includes(f)}
                    onChange={() => toggleDietary(f)}
