                  > - </button>
                  <span className="flex-1 text-center text-4xl font-black text-emerald-600">{formData.peopleCount}</span>
                  <button 
                    onClick={() => setFormData(p => ({...p, peopleCount: Math.min(10, p.peopleCount + 1)}))}
                    className="w-14 h-14 rounded-2xl border-4 border-slate-100 flex items-center justify-center text-2xl font-black"
                  > + </button>
                </div>
              </label>

              <label className="block">
                <span className="text-sm font-black text-slate-500 uppercase tracking-widest ml-1">Intensidade Energética</span>
                <div className="space-y-3 mt-3">
                  {Object.values(CalorieLevel).map(c => (
                    <button
                      type="button"
                      key={c}
                      onClick={() => setFormData({...formData, calorieLevel: c})}
                      className={`w-full text-left p-5 rounded-2xl border-4 font-bold transition-all ${
                        formData.calorieLevel === c 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
