import React, { useState, useEffect } from 'react';
import { RecipeResult, UserPreferences, ResultOption } from '../types';

interface ResultScreenProps {
  recipe: RecipeResult;
  prefs?: UserPreferences;
  onBack: () => void;
  onSaveHistory: (recipe: RecipeResult) => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ recipe, prefs, onBack, onSaveHistory }) => {
  const [isFavorite, setIsFavorite] = useState(false);

  useEffect(() => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    const exists = favorites.some((f: RecipeResult) => f.title === recipe.title);
    setIsFavorite(exists);
  }, [recipe.title]);

  const toggleFavorite = () => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    let newFavorites;
    if (isFavorite) {
      newFavorites = favorites.filter((f: RecipeResult) => f.title !== recipe.title);
    } else {
      newFavorites = [...favorites, recipe];
    }
    localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
    setIsFavorite(!isFavorite);
  };

  const getFullRecipeText = () => {
    let text = `🥗 *RECEITA FIT: ${recipe.title.toUpperCase()}*\n\n`;
    text += `${recipe.description}\n\n`;

    if (recipe.ingredients) {
      text += `🛒 *INGREDIENTES:*\n`;
      recipe.ingredients.forEach(ing => text += `• ${ing}\n`);
      text += `\n`;
    }

    if (recipe.instructions) {
      text += `👨‍🍳 *MODO DE PREPARO:*\n`;
      recipe.instructions.forEach((step, i) => text += `${i + 1}. ${step}\n`);
      text += `\n`;
    }

    text += `📊 *MACRONUTRIENTES:*\n`;
    text += `🔥 Calorias: ${recipe.macros.calories}\n`;
    text += `💪 Proteínas: ${recipe.macros.protein}\n`;
    text += `🍞 Carboidratos: ${recipe.macros.carbs}\n`;
    text += `🥑 Gorduras: ${recipe.macros.fats}\n\n`;

    text += `_Gerado por Receitas Fit Generator_`;
    return text;
  };

  const shareViaWhatsApp = () => {
    const encodedText = encodeURIComponent(getFullRecipeText());
    window.open(`https://wa.me/?text=${encodedText}`, '_blank');
  };

  const handleSaveToPhone = () => {
    onSaveHistory(recipe); 
    setTimeout(() => {
      window.print();
    }, 300);
  };

  const showIngredients = !prefs || prefs.resultOptions.includes(ResultOption.INGREDIENTES) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showInstructions = !prefs || prefs.resultOptions.includes(ResultOption.PREPARO) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showCost = !prefs || prefs.resultOptions.includes(ResultOption.CUSTO) || prefs.resultOptions.includes(ResultOption.TODOS);

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-64 text-slate-800">
      {/* Imagem de Cabeçalho - Oculta na impressão */}
      <div className="relative h-72 flex-shrink-0 print:hidden">
        <img 
          src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} 
          alt={recipe.title}
          className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent"></div>
        <button 
          type="button"
          onClick={onBack}
          className="absolute top-4 left-4 w-10 h-10 bg-white/90 backdrop-blur rounded-full flex items-center justify-center shadow-lg hover:bg-white transition-colors z-10"
        >
          <span className="text-xl text-slate-800 font-bold">←</span>
        </button>
      </div>

      <div className="px-6 -mt-12 relative bg-white rounded-t-[2.5rem] pt-10 space-y-8 print:mt-0 print:pt-0">
        {/* Info Cabeçalho */}
        <div className="print:border-b-2 print:border-slate-100 print:pb-4">
          {prefs && prefs.dietaryFilters.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-3 print:hidden">
              {prefs.dietaryFilters.map(f => (
                <span key={f} className="text-sm bg-emerald-100 text-emerald-700 px-3 py-1 rounded-full font-bold uppercase tracking-widest">
                  {f}
                </span>
              ))}
            </div>
          )}
          <h1 className="text-3xl font-black text-slate-900 leading-tight mb-2">{recipe.title}</h1>
          <div className="flex items-center gap-5 text-slate-600 text-base font-bold bg-slate-50 p-3 rounded-xl w-fit print:bg-transparent print:p-0">
            <span className="flex items-center gap-2">👥 {prefs?.peopleCount || 1} { (prefs?.peopleCount || 1) > 1 ? 'pessoas' : 'pessoa'}</span>
            <span className="flex items-center gap-2">🍽️ {prefs?.mealType}</span>
          </div>
        </div>

        {/* Macros */}
        <div className="grid grid-cols-4 gap-3 py-6 bg-emerald-900 rounded-[2rem] px-4 shadow-inner text-white print:bg-slate-100 print:text-slate-900 print:border print:border-slate-200">
          <div className="text-center">
            <p className="text-xs opacity-80 font-bold uppercase mb-1 print:opacity-100">Calorias</p>
            <p className="text-base font-black">{recipe.macros.calories}</p>
          </div>
          <div className="text-center border-l border-white/20 print:border-slate-300">
            <p className="text-xs opacity-80 font-bold uppercase mb-1 print:opacity-100">Proteína</p>
            <p className="text-base font-black">{recipe.macros.protein}</p>
          </div>
          <div className="text-center border-l border-white/20 print:border-slate-300">
            <p className="text-xs opacity-80 font-bold uppercase mb-1 print:opacity-100">Carbs</p>
            <p className="text-base font-black">{recipe.macros.carbs}</p>
          </div>
          <div className="text-center border-l border-white/20 print:border-slate-300">
            <p className="text-xs opacity-80 font-bold uppercase mb-1 print:opacity-100">Gorduras</p>
            <p className="text-base font-black">{recipe.macros.fats}</p>
          </div>
        </div>

        {/* Conteúdo */}
        <div className="space-y-10">
          <section className="space-y-3">
            <h3 className="text-2xl font-black text-slate-800 border-b-4 border-emerald-500 w-fit pb-1">Sobre</h3>
            <p className="text-slate-600 text-lg leading-relaxed">{recipe.description}</p>
          </section>

          {showIngredients && (
            <section className="space-y-4">
              <h3 className="text-2xl font-black text-slate-800 border-b-4 border-emerald-500 w-fit pb-1">Ingredientes</h3>
              <div className="grid gap-3">
                {recipe.ingredients?.map((ing, i) => (
                  <div key={i} className="flex items-center gap-4 p-4 bg-slate-50 rounded-2xl border border-slate-100 print:p-2 print:bg-transparent">
                    <div className="w-2.5 h-2.5 bg-emerald-500 rounded-full print:border print:border-slate-900"></div>
                    <span className="text-slate-700 font-bold text-lg">{ing}</span>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showInstructions && (
            <section className="space-y-6">
              <h3 className="text-2xl font-black text-slate-800 border-b-4 border-emerald-500 w-fit pb-1">Preparo</h3>
              <div className="space-y-8">
                {recipe.instructions?.map((step, i) => (
                  <div key={i} className="flex gap-5 relative">
                    <span className="flex-shrink-0 w-12 h-12 rounded-2xl bg-emerald-500 text-white flex items-center justify-center font-black text-xl shadow-lg print:bg-slate-200 print:text-slate-900 print:shadow-none">
                      {i + 1}
                    </span>
                    <p className="text-slate-600 text-lg leading-relaxed pt-1 font-medium">{step}</p>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showCost && recipe.estimatedCost && (
            <div className="bg-emerald-50 border-2 border-emerald-100 p-6 rounded-3xl flex items-center justify-between print:border print:border-slate-200">
              <div>
                <p className="text-sm text-emerald-600 font-black uppercase tracking-wider">Custo Estimado</p>
                <p className="text-2xl font-black text-emerald-900">{recipe.estimatedCost}</p>
              </div>
              <span className="text-5xl">💰</span>
            </div>
          )}
        </div>
      </div>

      {/* Ações Fixas Rodapé */}
      <div className="fixed bottom-0 left-0 w-full max-w-xl mx-auto p-4 bg-white/90 backdrop-blur-xl border-t border-slate-200 grid grid-cols-2 gap-3 print:hidden z-30 shadow-[0_-10px_30px_rgba(0,0,0,0.05)]">
        <button 
          onClick={shareViaWhatsApp}
          className="col-span-2 py-4 bg-emerald-500 text-white rounded-2xl font-black text-lg flex items-center justify-center gap-3 shadow-lg shadow-emerald-200 active:scale-95 transition-all"
        >
          <span className="text-2xl">💬</span> WHATSAPP COMPLETO
        </button>
        <button 
          onClick={handleSaveToPhone}
          className="py-4 bg-slate-800 text-white rounded-2xl font-black text-base flex items-center justify-center gap-2 active:scale-95 transition-all shadow-lg"
        >
          <span className="text-xl">📱</span> SALVAR NO CELULAR
        </button>
        <button 
          onClick={toggleFavorite}
          className={`py-4 rounded-2xl font-black text-base flex items-center justify-center gap-2 transition-all active:scale-95 shadow-lg ${
