import React, { useState } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  ResultOption, 
  UserPreferences, 
  RecipeResult 
} from './types';
import { generateRecipe } from './services/geminiService';
import StepForm from './components/StepForm';
import ResultScreen from './components/ResultScreen';
import SplashScreen from './components/SplashScreen';
import FavoritesList from './components/FavoritesList';

const App: React.FC = () => {
  const [view, setView] = useState<'splash' | 'form' | 'loading' | 'result' | 'favorites'>('splash');
  const [preferences, setPreferences] = useState<UserPreferences>({
    dietaryFilters: [],
    mealType: MealType.ALMOCO,
    dishType: '',
    peopleCount: 1,
    calorieLevel: CalorieLevel.MEDIO,
    flavor: Flavor.SALGADO,
    ingredients: '',
    prepMethods: [],
    resultOptions: [ResultOption.TODOS]
  });
  const [result, setResult] = useState<RecipeResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleStart = () => setView('form');
  const handleOpenFavorites = () => setView('favorites');

  const handleGenerate = async (prefs: UserPreferences) => {
    setPreferences(prefs);
    setView('loading');
    setError(null);
    try {
      const data = await generateRecipe(prefs);
      setResult(data);
      setView('result');
    } catch (err) {
      setError('Ocorreu um erro ao gerar sua receita. Tente novamente.');
      setView('form');
    }
  };

  const handleSelectRecipe = (recipe: RecipeResult) => {
    setResult(recipe);
    setView('result');
  };

  const handleReset = () => {
    setView('splash');
    setResult(null);
  };

  const handleSaveToHistory = (recipe: RecipeResult) => {
    // Mantendo a lógica interna para o botão 'Salvar no Celular' funcionar (acionando print/PDF)
    // Mas a visualização de histórico foi removida conforme solicitado.
  };

  return (
    <div className="min-h-screen bg-emerald-50 text-slate-800">
      <div className="max-w-xl mx-auto min-h-screen bg-white shadow-xl relative overflow-hidden">
        {view === 'splash' && (
          <SplashScreen 
            onStart={handleStart} 
            onOpenFavorites={handleOpenFavorites} 
          />
        )}

        {view === 'form' && (
          <StepForm 
            initialData={preferences} 
            onSubmit={handleGenerate} 
            error={error}
          />
        )}

        {view === 'loading' && (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-6 animate-pulse mt-40">
            <div className="w-20 h-20 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
            <h2 className="text-3xl font-black text-emerald-700">Cozinhando sua ideia...</h2>
            <p className="text-slate-500 text-lg italic font-medium">"Estamos selecionando os melhores ingredientes e calculando os macros para você."</p>
          </div>
        )}

        {view === 'result' && result && (
          <ResultScreen 
            recipe={result} 
            prefs={preferences} 
            onBack={handleReset} 
            onSaveHistory={handleSaveToHistory}
          />
        )}

        {view === 'favorites' && (
          <FavoritesList 
            onSelect={handleSelectRecipe}
            onBack={() => setView('splash')}
            onNewRecipe={handleStart}
          />
        )}
      </div>

      <style>{`
        @keyframes loading {
          0% { width: 0%; }
          50% { width: 100%; }
          100% { width: 0%; }
        }
      `}</style>
    </div>
  );
};

export default App;

