import React, { useState, useEffect } from 'react';
import { RecipeResult } from '../types';

interface FavoritesListProps {
  onSelect: (recipe: RecipeResult) => void;
  onBack: () => void;
  onNewRecipe: () => void;
}

const FavoritesList: React.FC<FavoritesListProps> = ({ onSelect, onBack, onNewRecipe }) => {
  const [favorites, setFavorites] = useState<RecipeResult[]>([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    setFavorites(stored);
  }, []);

  const removeFavorite = (title: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const newFavorites = favorites.filter(f => f.title !== title);
    localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
    setFavorites(newFavorites);
  };

  return (
    <div className="p-6 h-full flex flex-col bg-slate-50">
      <div className="flex items-center justify-between mb-8">
        <h2 className="text-3xl font-black text-slate-800">Minhas Favoritas</h2>
        <button 
          onClick={onBack}
          className="text-emerald-600 font-black text-xl hover:text-emerald-700 underline uppercase tracking-tight"
        >
          Voltar
        </button>
      </div>

      <div className="flex-1 overflow-y-auto space-y-5">
        {favorites.length === 0 ? (
          <div className="text-center py-20 space-y-6">
            <div className="text-8xl opacity-20">❤️</div>
            <p className="text-slate-400 font-black text-xl uppercase tracking-widest">Nenhuma favorita ainda.</p>
          </div>
        ) : (
          favorites.map((recipe, idx) => (
            <div 
              key={idx}
              onClick={() => onSelect(recipe)}
              className="bg-white p-5 rounded-[2rem] shadow-sm border-2 border-slate-100 flex gap-5 cursor-pointer hover:shadow-xl transition-all group active:scale-95"
            >
              <div className="w-24 h-24 rounded-2xl overflow-hidden flex-shrink-0 shadow-lg">
                <img 
                  src={recipe.imageUrl || 'https://picsum.photos/200'} 
                  alt={recipe.title} 
                  className="w-full h-full object-cover"
                />
              </div>
              <div className="flex-1 min-w-0 flex flex-col justify-center">
                <h4 className="font-black text-xl text-slate-800 truncate group-hover:text-emerald-600 transition-colors">{recipe.title}</h4>
                <div className="flex items-center gap-3 mt-2">
                  <span className="text-sm font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full uppercase">
                    {recipe.macros.calories}
                  </span>
                </div>
              </div>
              <button 
                onClick={(e) => removeFavorite(recipe.title, e)}
                className="self-center text-red-200 hover:text-red-500 transition-colors p-3 text-3xl"
              >
                ✕
              </button>
            </div>
          ))
        )}
      </div>

      <div className="mt-6 p-6 bg-white -mx-6 border-t-4 border-slate-100 shadow-2xl space-y-4">
        <button 
          onClick={onNewRecipe}
          className="w-full py-5 bg-emerald-500 text-white rounded-[1.5rem] font-black text-xl transition-all hover:bg-emerald-600 active:scale-95 uppercase shadow-xl shadow-emerald-100"
        >
          Nova Receita 🥗
        </button>
      </div>
    </div>
  );
};

