import React, { useState, useEffect } from 'react';
import { RecipeResult, UserPreferences, ResultOption } from '../types';

interface ResultScreenProps {
  recipe: RecipeResult;
  prefs?: UserPreferences;
  onBack: () => void;
  onSaveHistory: (recipe: RecipeResult) => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ recipe, prefs, onBack, onSaveHistory }) => {
  const [isFavorite, setIsFavorite] = useState(false);

  useEffect(() => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    const exists = favorites.some((f: RecipeResult) => f.title === recipe.title);
    setIsFavorite(exists);
  }, [recipe.title]);

  const toggleFavorite = () => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    let newFavorites;
    if (isFavorite) {
      newFavorites = favorites.filter((f: RecipeResult) => f.title !== recipe.title);
    } else {
      newFavorites = [...favorites, recipe];
    }
    localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
    setIsFavorite(!isFavorite);
  };

  const getFullRecipeText = () => {
    let text = `🥗 *RECEITA FIT: ${recipe.title.toUpperCase()}*\n\n`;
    text += `${recipe.description}\n\n`;

    if (recipe.ingredients) {
      text += `🛒 *INGREDIENTES:*\n`;
      recipe.ingredients.forEach(ing => text += `• ${ing}\n`);
      text += `\n`;
    }

    if (recipe.instructions) {
      text += `👨‍🍳 *MODO DE PREPARO:*\n`;
      recipe.instructions.forEach((step, i) => text += `${i + 1}. ${step}\n`);
      text += `\n`;
    }

    text += `📊 *MACRONUTRIENTES:*\n`;
    text += `🔥 Calorias: ${recipe.macros.calories}\n`;
    text += `💪 Proteínas: ${recipe.macros.protein}\n`;
    text += `🍞 Carboidratos: ${recipe.macros.carbs}\n`;
    text += `🥑 Gorduras: ${recipe.macros.fats}\n\n`;

    text += `_Gerado por Receitas Fit Generator_`;
    return text;
  };

  const shareViaWhatsApp = () => {
    const encodedText = encodeURIComponent(getFullRecipeText());
    window.open(`https://wa.me/?text=${encodedText}`, '_blank');
  };

  const handleSaveToPhone = () => {
    onSaveHistory(recipe); 
    setTimeout(() => {
      window.print();
    }, 300);
  };

  const showIngredients = !prefs || prefs.resultOptions.includes(ResultOption.INGREDIENTES) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showInstructions = !prefs || prefs.resultOptions.includes(ResultOption.PREPARO) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showCost = !prefs || prefs.resultOptions.includes(ResultOption.CUSTO) || prefs.resultOptions.includes(ResultOption.TODOS);

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-64 text-slate-800">
      {/* Imagem de Cabeçalho - Oculta na impressão */}
      <div className="relative h-72 flex-shrink-0 print:hidden">
        <img 
          src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} 
          alt={recipe.title}
          className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent"></div>
        <button 
          type="button"
          onClick={onBack}
          className="absolute top-4 left-4 w-12 h-12 bg-white/90 backdrop-blur rounded-full flex items-center justify-center shadow-lg hover:bg-white transition-colors z-10"
        >
          <span className="text-2xl text-slate-800 font-bold">←</span>
        </button>
      </div>

      <div className="px-6 -mt-12 relative bg-white rounded-t-[2.5rem] pt-10 space-y-8 print:mt-0 print:pt-0">
        {/* Info Cabeçalho */}
        <div className="print:border-b-2 print:border-slate-100 print:pb-4">
          {prefs && prefs.dietaryFilters.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-3 print:hidden">
              {prefs.dietaryFilters.map(f => (
                <span key={f} className="text-base bg-emerald-100 text-emerald-700 px-4 py-1 rounded-full font-black uppercase tracking-widest">
                  {f}
                </span>
              ))}
            </div>
          )}
          <h1 className="text-4xl font-black text-slate-900 leading-tight mb-2">{recipe.title}</h1>
          <div className="flex items-center gap-5 text-slate-600 text-lg font-black bg-slate-50 p-4 rounded-2xl w-fit print:bg-transparent print:p-0">
            <span className="flex items-center gap-2">👥 {prefs?.peopleCount || 1} { (prefs?.peopleCount || 1) > 1 ? 'pessoas' : 'pessoa'}</span>
            <span className="flex items-center gap-2">🍽️ {prefs?.mealType}</span>
          </div>
        </div>

        {/* Macros */}
        <div className="grid grid-cols-4 gap-3 py-7 bg-emerald-900 rounded-[2.5rem] px-4 shadow-inner text-white print:bg-slate-100 print:text-slate-900 print:border print:border-slate-200">
          <div className="text-center">
            <p className="text-sm opacity-90 font-black uppercase mb-1 print:opacity-100">Calorias</p>
            <p className="text-xl font-black">{recipe.macros.calories}</p>
          </div>
          <div className="text-center border-l border-white/20 print:border-slate-300">
            <p className="text-sm opacity-90 font-black uppercase mb-1 print:opacity-100">Proteína</p>
            <p className="text-xl font-black">{recipe.macros.protein}</p>
          </div>
          <div className="text-center border-l border-white/20 print:border-slate-300">
            <p className="text-sm opacity-90 font-black uppercase mb-1 print:opacity-100">Carbs</p>
            <p className="text-xl font-black">{recipe.macros.carbs}</p>
          </div>
          <div className="text-center border-l border-white/20 print:border-slate-300">
            <p className="text-sm opacity-90 font-black uppercase mb-1 print:opacity-100">Gorduras</p>
            <p className="text-xl font-black">{recipe.macros.fats}</p>
          </div>
        </div>

        {/* Conteúdo */}
        <div className="space-y-12">
          <section className="space-y-4">
            <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Sobre</h3>
            <p className="text-slate-600 text-xl leading-relaxed font-medium">{recipe.description}</p>
          </section>

          {showIngredients && (
            <section className="space-y-5">
              <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Ingredientes</h3>
              <div className="grid gap-4">
                {recipe.ingredients?.map((ing, i) => (
                  <div key={i} className="flex items-center gap-5 p-5 bg-slate-50 rounded-[1.5rem] border-2 border-slate-100 print:p-2 print:bg-transparent">
                    <div className="w-3.5 h-3.5 bg-emerald-500 rounded-full print:border print:border-slate-900"></div>
                    <span className="text-slate-800 font-black text-xl">{ing}</span>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showInstructions && (
            <section className="space-y-8">
              <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Preparo</h3>
              <div className="space-y-10">
                {recipe.instructions?.map((step, i) => (
                  <div key={i} className="flex gap-6 relative">
                    <span className="flex-shrink-0 w-14 h-14 rounded-[1.25rem] bg-emerald-500 text-white flex items-center justify-center font-black text-2xl shadow-xl print:bg-slate-200 print:text-slate-900 print:shadow-none">
                      {i + 1}
                    </span>
                    <p className="text-slate-600 text-xl leading-relaxed pt-1 font-bold">{step}</p>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showCost && recipe.estimatedCost && (
            <div className="bg-emerald-50 border-4 border-emerald-100 p-8 rounded-[2.5rem] flex items-center justify-between print:border print:border-slate-200">
              <div>
                <p className="text-base text-emerald-600 font-black uppercase tracking-widest mb-1">Custo Estimado</p>
                <p className="text-3xl font-black text-emerald-900">{recipe.estimatedCost}</p>
              </div>
              <span className="text-6xl">💰</span>
            </div>
          )}
        </div>
      </div>

      {/* Ações Fixas Rodapé */}
      <div className="fixed bottom-0 left-0 w-full max-w-xl mx-auto p-5 bg-white/95 backdrop-blur-2xl border-t-2 border-slate-100 grid grid-cols-2 gap-4 print:hidden z-30 shadow-[0_-15px_40px_rgba(0,0,0,0.1)]">
        <button 
          onClick={shareViaWhatsApp}
          className="col-span-2 py-5 bg-emerald-500 text-white rounded-[1.5rem] font-black text-xl flex items-center justify-center gap-4 shadow-2xl shadow-emerald-200 active:scale-95 transition-all uppercase"
        >
          <span className="text-3xl">💬</span> Enviar por WhatsApp
        </button>
        <button 
          onClick={handleSaveToPhone}
          className="py-5 bg-slate-900 text-white rounded-[1.5rem] font-black text-lg flex items-center justify-center gap-3 active:scale-95 transition-all shadow-xl uppercase"
        >
          <span className="text-2xl">📱</span> Salvar no Celular
        </button>
        <button 
          onClick={toggleFavorite}
          className={`py-5 rounded-[1.5rem] font-black text-lg flex items-center justify-center gap-3 transition-all active:scale-95 shadow-xl uppercase ${
            isFavorite 
            ? 'bg-red-500 text-white shadow-red-200' 
            : 'bg-white text-red-500 border-4 border-red-500'
          }`}
        >
          <span className="text-2xl">{isFavorite ? '❤️' : '🤍'}</span> 
          {isFavorite ? 'Salva' : 'Salvar Receita'}
        </button>
      </div>

      <style>{`
        @media print {
          .print\\:hidden, #root > div:not(.max-w-xl), .fixed, button, .z-30 { display: none !important; }
          body { background: white !important; margin: 0 !important; padding: 0 !important; }
          .max-w-xl { max-width: 100% !important; border: none !important; box-shadow: none !important; margin: 0 !important; }
          .rounded-t-[2.5rem] { border-radius: 0 !important; margin-top: 0 !important; }
          .bg-emerald-900 { background-color: #f1f5f9 !important; color: #0f172a !important; border: 1px solid #e2e8f0 !important; }
          .text-white { color: #0f172a !important; }
          .shadow-inner, .shadow-xl, .shadow-2xl { box-shadow: none !important; }
          h1, h3 { color: #064e3b !important; }
          .bg-slate-50 { background-color: transparent !important; border: 1px solid #f1f5f9 !important; }
          @page { margin: 1.5cm; }
        }
      `}</style>
    </div>
  );
};

