import { RecipeResult, UserPreferences, ResultOption } from '../types';

interface ResultScreenProps {
  recipe: RecipeResult;
  prefs?: UserPreferences;
  onBack: () => void;
  onSaveHistory: (recipe: RecipeResult) => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ recipe, prefs, onBack, onSaveHistory }) => {
  const [isFavorite, setIsFavorite] = useState(false);

  useEffect(() => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    const exists = favorites.some((f: RecipeResult) => f.title === recipe.title);
    setIsFavorite(exists);
  }, [recipe.title]);

  const toggleFavorite = () => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    let newFavorites;
    if (isFavorite) {
      newFavorites = favorites.filter((f: RecipeResult) => f.title !== recipe.title);
    } else {
      newFavorites = [...favorites, recipe];
    }
    localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
    setIsFavorite(!isFavorite);
  };

  const getFullRecipeText = () => {
    let text = `🥗 *RECEITA FIT: ${recipe.title.toUpperCase()}*\n\n`;
    text += `${recipe.description}\n\n`;

    if (recipe.ingredients) {
      text += `🛒 *INGREDIENTES:*\n`;
      recipe.ingredients.forEach(ing => text += `• ${ing}\n`);
      text += `\n`;
    }

    if (recipe.instructions) {
      text += `👨‍🍳 *MODO DE PREPARO:*\n`;
      recipe.instructions.forEach((step, i) => text += `${i + 1}. ${step}\n`);
      text += `\n`;
    }

    text += `📊 *MACRONUTRIENTES:*\n`;
    text += `🔥 Calorias: ${recipe.macros.calories}\n`;
    text += `💪 Proteínas: ${recipe.macros.protein}\n`;
    text += `🍞 Carboidratos: ${recipe.macros.carbs}\n`;
    text += `🥑 Gorduras: ${recipe.macros.fats}\n\n`;

    text += `_Gerado por Receitas Fit Generator_`;
    return text;
  };

  const shareViaWhatsApp = () => {
    const encodedText = encodeURIComponent(getFullRecipeText());
    window.open(`https://wa.me/?text=${encodedText}`, '_blank');
  };

  const handleSaveToPhone = () => {
    onSaveHistory(recipe); 
    setTimeout(() => {
      window.print();
    }, 300);
  };

  const showIngredients = !prefs || prefs.resultOptions.includes(ResultOption.INGREDIENTES) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showInstructions = !prefs || prefs.resultOptions.includes(ResultOption.PREPARO) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showCost = !prefs || prefs.resultOptions.includes(ResultOption.CUSTO) || prefs.resultOptions.includes(ResultOption.TODOS);

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-64 text-slate-800">
      {/* Imagem de Cabeçalho - Oculta na impressão */}
      <div className="relative h-72 flex-shrink-0 print:hidden">
        <img 
          src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} 
          alt={recipe.title}
          className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent"></div>
        <button 
          type="button"
          onClick={onBack}
          className="absolute top-4 left-4 w-12 h-12 bg-white/90 backdrop-blur rounded-full flex items-center justify-center shadow-lg hover:bg-white transition-colors z-10"
        >
          <span className="text-2xl text-slate-800 font-bold">←</span>
        </button>
      </div>

      <div className="px-6 -mt-12 relative bg-white rounded-t-[2.5rem] pt-10 space-y-8 print:mt-0 print:pt-0">
        {/* Info Cabeçalho */}
        <div className="print:border-b-2 print:border-slate-100 print:pb-4">
          {prefs && prefs.dietaryFilters.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-3 print:hidden">
              {prefs.dietaryFilters.map(f => (
                <span key={f} className="text-base bg-emerald-100 text-emerald-700 px-4 py-1 rounded-full font-black uppercase tracking-widest">
                  {f}
                </span>
              ))}
            </div>
          )}
          <h1 className="text-4xl font-black text-slate-900 leading-tight mb-2">{recipe.title}</h1>
          <div className="flex items-center gap-5 text-slate-600 text-lg font-black bg-slate-50 p-4 rounded-2xl w-fit print:bg-transparent print:p-0">
            <span className="flex items-center gap-2">👥 {prefs?.peopleCount || 1} { (prefs?.peopleCount || 1) > 1 ? 'pessoas' : 'pessoa'}</span>
            <span className="flex items-center gap-2">🍽️ {prefs?.mealType}</span>
          </div>
        </div>

        {/* Macros */}
        <div className="grid grid-cols-4 gap-3 py-7 bg-emerald-900 rounded-[2.5rem] px-4 shadow-inner text-white print:bg-slate-100 print:text-slate-900 print:border print:border-slate-200">
