      newFavorites = favorites.filter((f: RecipeResult) => f.title !== recipe.title);
    } else {
      newFavorites = [...favorites, recipe];
    }
    localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
    setIsFavorite(!isFavorite);
  };

  const getFullRecipeText = () => {
    let text = `🥗 RECEITA FIT: ${recipe.title.toUpperCase()}\n\n`;
    text += `${recipe.description}\n\n`;

    text += `⏱️ TEMPO DE PREPARO: ${recipe.estimatedTime || 'N/A'}\n`;
    if (recipe.estimatedCost) {
      text += `💰 CUSTO ESTIMADO: ${recipe.estimatedCost}\n`;
    }
    text += `\n`;

    if (recipe.ingredients) {
      text += `🛒 INGREDIENTES:\n`;
      recipe.ingredients.forEach(ing => text += `• ${ing}\n`);
      text += `\n`;
    }

    if (recipe.instructions) {
      text += `👨‍🍳 MODO DE PREPARO:\n`;
      recipe.instructions.forEach((step, i) => text += `${i + 1}. ${step}\n`);
      text += `\n`;
    }

    text += `📊 MACRONUTRIENTES:\n`;
    text += `🔥 Calorias: ${recipe.macros.calories}\n`;
    text += `💪 Proteínas: ${recipe.macros.protein}\n`;
    text += `🍞 Carboidratos: ${recipe.macros.carbs}\n`;
    text += `🥑 Gorduras: ${recipe.macros.fats}\n\n`;

    text += `Gerado por Receitas Fit Generator`;
    return text;
  };

  const shareViaWhatsApp = () => {
    const encodedText = encodeURIComponent(getFullRecipeText().replace(/\*/g, ''));
    window.open(`https://wa.me/?text=${encodedText}`, '_blank');
  };

  const showIngredients = !prefs || prefs.resultOptions.includes(ResultOption.INGREDIENTES) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showInstructions = !prefs || prefs.resultOptions.includes(ResultOption.PREPARO) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showCost = !prefs || prefs.resultOptions.includes(ResultOption.CUSTO) || prefs.resultOptions.includes(ResultOption.TODOS);

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-64 text-slate-800">
      {/* Zoom Overlay - Fullscreen with X button on top right */}
      {isImageZoomed && (
        <div 
          className="fixed inset-0 z-[100] bg-black flex items-center justify-center animate-in fade-in duration-300 overflow-hidden"
          onClick={() => setIsImageZoomed(false)}
        >
          <img 
            src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} 
            alt={recipe.title}
            className="w-full h-full object-contain"
          />
          <button 
            className="absolute top-8 right-8 text-white w-14 h-14 rounded-full bg-black/40 backdrop-blur-md flex items-center justify-center text-4xl font-light border border-white/20 active:scale-90 transition-transform"
            onClick={(e) => {
                e.stopPropagation();
                setIsImageZoomed(false);
            }}
          >
            ✕
          </button>
        </div>
      )}

      {/* Imagem de Cabeçalho - Oculta na impressão */}
      <div className="relative h-96 flex-shrink-0 print:hidden cursor-zoom-in group">
        <img 
          src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} 
          alt={recipe.title}
          onClick={() => setIsImageZoomed(true)}
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-black/20"></div>

        {/* Botão de Retorno Ampliado (INÍCIO) */}
        <button 
          type="button"
          onClick={onBack}
          className="absolute top-6 left-6 px-8 py-4 bg-white/95 backdrop-blur-xl rounded-2xl flex items-center justify-center shadow-2xl hover:bg-white hover:scale-105 active:scale-95 transition-all z-10 border-2 border-emerald-100 group/back"
        >
          <span className="text-xl text-emerald-600 font-black uppercase tracking-tighter flex items-center gap-2">
            <span className="text-2xl transition-transform group-hover/back:-translate-x-1">←</span> INÍCIO
          </span>
        </button>
      </div>

      <div className="px-6 -mt-12 relative bg-white rounded-t-[3rem] pt-10 space-y-8 print:mt-0 print:pt-0">
        {/* Info Cabeçalho */}
        <div className="print:border-b-2 print:border-slate-100 print:pb-4">
          {prefs && prefs.dietaryFilters.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-3 print:hidden">
              {prefs.dietaryFilters.map(f => (
                <span key={f} className="text-base bg-emerald-100 text-emerald-700 px-4 py-1 rounded-full font-black uppercase tracking-widest">
                  {f}
                </span>
              ))}
            </div>
          )}
          <h1 className="text-5xl font-black text-slate-900 leading-tight mb-2 tracking-tighter">{recipe.title}</h1>
          <div className="flex flex-wrap items-center gap-3 text-slate-600 text-lg font-black bg-slate-50 p-4 rounded-2xl w-fit print:bg-transparent print:p-0">
            <span className="flex items-center gap-2 whitespace-nowrap">👥 {prefs?.peopleCount || 1} { (prefs?.peopleCount || 1) > 1 ? 'pessoas' : 'pessoa'}</span>
            <span className="flex items-center gap-2 whitespace-nowrap">🍽️ {prefs?.mealType}</span>
            <span className="flex items-center gap-2 whitespace-nowrap">⏱️ {recipe.estimatedTime}</span>
          </div>
        </div>

        {/* Macros */}
        <div className="grid grid-cols-4 gap-3 py-8 bg-emerald-900 rounded-[2.5rem] px-4 shadow-2xl text-white print:bg-slate-100 print:text-slate-900 print:border print:border-slate-200">
          <div className="text-center">
            <p className="text-xs opacity-70 font-black uppercase mb-1 print:opacity-100 tracking-widest">Calorias</p>
            <p className="text-2xl font-black">{recipe.macros.calories}</p>
          </div>
          <div className="text-center border-l border-white/20 print:border-slate-300">
            <p className="text-xs opacity-70 font-black uppercase mb-1 print:opacity-100 tracking-widest">Proteína</p>
            <p className="text-2xl font-black">{recipe.macros.protein}</p>
          </div>
          <div className="text-center border-l border-white/20 print:border-slate-300">
            <p className="text-xs opacity-70 font-black uppercase mb-1 print:opacity-100 tracking-widest">Carbs</p>
            <p className="text-2xl font-black">{recipe.macros.carbs}</p>
          </div>
          <div className="text-center border-l border-white/20 print:border-slate-300">
            <p className="text-xs opacity-70 font-black uppercase mb-1 print:opacity-100 tracking-widest">Gorduras</p>
            <p className="text-2xl font-black">{recipe.macros.fats}</p>
          </div>
        </div>

        {/* Conteúdo */}
        <div className="space-y-12">
          <section className="space-y-4">
            <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Sobre</h3>
            <p className="text-slate-600 text-xl leading-relaxed font-medium">{recipe.description}</p>
          </section>

          {showIngredients && (
            <section className="space-y-5">
              <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Ingredientes</h3>
              <div className="grid gap-4">
                {recipe.ingredients?.map((ing, i) => (
                  <div key={i} className="flex items-center gap-5 p-5 bg-slate-50 rounded-[1.5rem] border-2 border-slate-100 print:p-2 print:bg-transparent">
                    <div className="w-3.5 h-3.5 bg-emerald-500 rounded-full print:border print:border-slate-900"></div>
                    <span className="text-slate-800 font-black text-xl">{ing}</span>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showInstructions && (
            <section className="space-y-8">
              <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Preparo</h3>
              <div className="space-y-10">
                {recipe.instructions?.map((step, i) => (
                  <div key={i} className="flex gap-6 relative">
                    <span className="flex-shrink-0 w-14 h-14 rounded-[1.25rem] bg-emerald-500 text-white flex items-center justify-center font-black text-2xl shadow-xl print:bg-slate-200 print:text-slate-900 print:shadow-none">
                      {i + 1}
                    </span>
                    <p className="text-slate-600 text-xl leading-relaxed pt-1 font-bold">{step}</p>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showCost && recipe.estimatedCost && (
            <div className="bg-emerald-50 border-4 border-emerald-100 p-8 rounded-[2.5rem] flex items-center justify-between print:border print:border-slate-200">
              <div>
                <p className="text-base text-emerald-600 font-black uppercase tracking-widest mb-1">Custo Estimado</p>
                <p className="text-3xl font-black text-emerald-900">{recipe.estimatedCost}</p>
              </div>
              <span className="text-6xl">💰</span>
            </div>
          )}
        </div>
      </div>

      {/* Ações Fixas Rodapé */}
      <div className="fixed bottom-0 left-0 w-full max-w-xl mx-auto p-5 bg-white/95 backdrop-blur-2xl border-t-2 border-slate-100 grid grid-cols-1 gap-4 print:hidden z-30 shadow-[0_-15px_40px_rgba(0,0,0,0.1)]">
        <button 
          onClick={shareViaWhatsApp}
          className="w-full py-5 bg-emerald-500 text-white rounded-[1.5rem] font-black text-xl flex items-center justify-center gap-4 shadow-2xl shadow-emerald-200 active:scale-95 transition-all uppercase"
        >
          Enviar por WhatsApp
        </button>
        <button 
          onClick={toggleFavorite}
          className={`w-full py-5 rounded-[1.5rem] font-black text-lg flex items-center justify-center gap-3 transition-all active:scale-95 shadow-xl uppercase ${
            isFavorite 
            ? 'bg-emerald-600 text-white shadow-emerald-200' 
            : 'bg-white text-emerald-600 border-4 border-emerald-600'
          }`}
        >
          {isFavorite ? 'Salva' : 'Salvar Receita'}
        </button>
      </div>

      <style>{`
        @media print {
          .print\\:hidden, #root > div:not(.max-w-xl), .fixed, button, .z-30 { display: none !important; }
          body { background: white !important; margin: 0 !important; padding: 0 !important; }
          .max-w-xl { max-width: 100% !important; border: none !important; box-shadow: none !important; margin: 0 !important; }
          .rounded-t-[2.5rem], .rounded-t-[3rem] { border-radius: 0 !important; margin-top: 0 !important; }
          .bg-emerald-900 { background-color: #f1f5f9 !important; color: #0f172a !important; border: 1px solid #e2e8f0 !important; }
          .text-white { color: #0f172a !important; }
          .shadow-inner, .shadow-xl, .shadow-2xl { box-shadow: none !important; }
          h1, h3 { color: #064e3b !important; }
          .bg-slate-50 { background-color: transparent !important; border: 1px solid #f1f5f9 !important; }
          @page { margin: 1.5cm; }
        }
      `}</style>
    </div>
  );
};

export default ResultScreen;

import React, { useState } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  ResultOption, 
  UserPreferences 
} from '../types';

interface StepFormProps {
  initialData: UserPreferences;
  onSubmit: (data: UserPreferences) => void;
  error: string | null;
}

const StepForm: React.FC<StepFormProps> = ({ initialData, onSubmit, error }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<UserPreferences>({
    ...initialData,
    dishType: initialData.dishType || ''
  });

  const totalSteps = 5;

  const handleNext = () => {
    if (step === 1 && formData.dietaryFilters.length === 0) {
      alert("Selecione pelo menos um filtro dietético.");
      return;
    }
    if (step < totalSteps) setStep(step + 1);
    else onSubmit(formData);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const toggleDietary = (val: DietaryFilter) => {
    setFormData(prev => ({
      ...prev,
      dietaryFilters: prev.dietaryFilters.includes(val)
        ? prev.dietaryFilters.filter(f => f !== val)
        : [...prev.dietaryFilters, val]
    }));
  };

  const togglePrep = (val: PrepMethod) => {
    setFormData(prev => ({
      ...prev,
      prepMethods: prev.prepMethods.includes(val)
        ? prev.prepMethods.filter(p => p !== val)
        : [...prev.prepMethods, val]
    }));
  };

  const toggleResult = (val: ResultOption) => {
    setFormData(prev => ({
      ...prev,
      resultOptions: prev.resultOptions.includes(val)
        ? prev.resultOptions.filter(r => r !== val)
        : [...prev.resultOptions, val]
    }));
  };

  return (
    <div className="p-6 h-full flex flex-col bg-white">
      <div className="mb-8 print:hidden">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">
            Passo {step} <span className="text-emerald-500">/ {totalSteps}</span>
          </h2>
          <span className="text-sm font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full uppercase">
            {Math.round((step / totalSteps) * 100)}%
          </span>
        </div>
        <div className="h-3 w-full bg-slate-100 rounded-full overflow-hidden">
          <div 
            className="h-full bg-emerald-500 transition-all duration-500 ease-out" 
            style={{ width: `${(step / totalSteps) * 100}%` }}
          ></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto pb-24">
        {error && (
          <div className="bg-red-50 text-red-600 p-5 rounded-2xl mb-6 text-base font-bold border-2 border-red-100">
            ⚠️ {error}
          </div>
        )}

        {step === 1 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Perfil Alimentar</h3>
            <p className="text-slate-600 text-lg font-medium italic">Selecione suas restrições ou escolhas de saúde.</p>
            <div className="grid grid-cols-2 gap-3">
              {Object.values(DietaryFilter).map(f => (
                <label 
                  key={f} 
                  className={`flex items-center justify-between p-4 rounded-[1.25rem] border-4 transition-all cursor-pointer ${
                    formData.dietaryFilters.includes(f) 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                      : 'border-slate-100 hover:border-slate-200 bg-white text-slate-400'
                  }`}
                >
                  <span className="font-black text-base leading-tight">{f}</span>
                  <input 
                    type="checkbox" 
                    checked={formData.dietaryFilters.includes(f)}
                    onChange={() => toggleDietary(f)}
                    className="w-5 h-5 accent-emerald-500 flex-shrink-0 ml-2"
                  />
                </label>
              ))}
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Refeição & Gosto</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Momento do Dia</span>
                <select 
                  value={formData.mealType}
                  onChange={e => setFormData({...formData, mealType: e.target.value as MealType})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-100 focus:border-emerald-500 focus:ring-0 transition-all bg-white text-slate-800 font-black text-xl outline-none"
                >
                  {Object.values(MealType).map(m => <option key={m} value={m}>{m}</option>)}
                </select>
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Tipo de Prato</span>
                <input 
                  type="text"
                  placeholder="Ex: Cookie, Massa, Shake, Panqueca, Torta..."
                  value={formData.dishType}
                  onChange={e => setFormData({...formData, dishType: e.target.value})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-100 focus:border-emerald-500 outline-none bg-white text-slate-800 font-black text-xl placeholder:text-slate-300 shadow-sm"
                />
                <p className="text-xs text-slate-400 mt-2 font-bold uppercase ml-1 italic">Exemplos: Cookie, Massa, Shake, Panqueca...</p>
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Sabor Predominante</span>
                <div className="grid grid-cols-2 gap-4 mt-2">
                  {Object.values(Flavor).map(f => (
                    <button
                      type="button"
                      key={f}
                      onClick={() => setFormData({...formData, flavor: f})}
                      className={`py-5 rounded-2xl border-4 font-black transition-all text-xl ${
                        formData.flavor === f 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100 bg-white text-slate-300'
                      }`}
                    >
                      {f}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Porções & Calorias</h3>
            <div className="space-y-8">
              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Número de Pessoas</span>
                <div className="flex items-center gap-4 mt-3">
                  <button 
                    onClick={() => setFormData(p => ({...p, peopleCount: Math.max(1, p.peopleCount - 1)}))}
                    className="w-16 h-16 rounded-2xl border-4 border-slate-100 flex items-center justify-center text-3xl font-black"
                  > - </button>
                  <span className="flex-1 text-center text-5xl font-black text-emerald-600">{formData.peopleCount}</span>
                  <button 
                    onClick={() => setFormData(p => ({...p, peopleCount: Math.min(10, p.peopleCount + 1)}))}
                    className="w-16 h-16 rounded-2xl border-4 border-slate-100 flex items-center justify-center text-3xl font-black"
                  > + </button>
                </div>
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Intensidade Energética</span>
                <div className="grid grid-cols-2 gap-2 mt-3">
                  {Object.values(CalorieLevel).map(c => (
                    <button
                      type="button"
                      key={c}
                      onClick={() => setFormData({...formData, calorieLevel: c})}
                      className={`w-full text-left p-3 rounded-xl border-2 font-bold transition-all text-xs leading-tight ${
                        formData.calorieLevel === c 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100 bg-white text-slate-400'
                      }`}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Ingredientes</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Ingrediente Favorito</span>
                <textarea 
                  rows={2}
                  placeholder="Ex: frango, brócolis, aveia, chocolate 70%..."
                  value={formData.ingredients}
                  onChange={e => setFormData({...formData, ingredients: e.target.value})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-100 focus:border-emerald-500 outline-none bg-white text-slate-800 font-black text-xl placeholder:text-slate-300 shadow-sm"
                />
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-900 uppercase tracking-widest ml-1">Ingredientes Dispensáveis</span>
                <textarea 
                  rows={2}
                  placeholder="O que você NÃO quer na receita? Ex: cebola, pimenta, coentro..."
                  value={formData.dispensableIngredients}
                  onChange={e => setFormData({...formData, dispensableIngredients: e.target.value})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-100 focus:border-slate-900 outline-none bg-white text-slate-800 font-black text-xl placeholder:text-slate-300 shadow-sm"
                />
                <p className="text-xs text-slate-400 mt-2 font-bold uppercase ml-1 italic">Itens listados aqui serão evitados pela IA.</p>
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Como prefere preparar?</span>
                <div className="grid grid-cols-1 gap-3 mt-3">
                  {Object.values(PrepMethod).map(p => (
                    <button
                      type="button"
                      key={p}
                      onClick={() => togglePrep(p)}
                      className={`p-6 rounded-2xl border-4 text-2xl font-black transition-all ${
                        formData.prepMethods.includes(p) 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-100 bg-white text-slate-400'
                      }`}
                    >
                      {p}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 5 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Detalhes do Resultado</h3>
            <div className="grid grid-cols-1 gap-4">
              {Object.values(ResultOption).map(r => (
                <label 
                  key={r} 
                  className={`flex items-center justify-between p-6 rounded-[1.5rem] border-4 transition-all cursor-pointer ${
                    formData.resultOptions.includes(r) 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                      : 'border-slate-100 hover:border-slate-200 bg-white text-slate-400'
                  }`}
                >
                  <span className="font-black text-xl">{r}</span>
                  <input 
                    type="checkbox" 
                    checked={formData.resultOptions.includes(r)}
                    onChange={() => toggleResult(r)}
                    className="w-7 h-7 accent-emerald-500"
                  />
                </label>
              ))}
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 w-full p-6 bg-white border-t border-slate-100 flex gap-4 z-20">
        {step > 1 && (
          <button 
            type="button"
            onClick={handleBack}
            className="flex-1 py-5 border-4 border-emerald-500 text-emerald-600 rounded-2xl font-black text-lg hover:bg-emerald-50 transition-all active:scale-95 uppercase"
          >
            VOLTAR
          </button>
        )}
        <button 
          type="button"
          onClick={handleNext}
          className="flex-[2] py-5 bg-emerald-500 text-white rounded-2xl font-black text-2xl hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-200 active:scale-95 uppercase"
        >
          {step === totalSteps ? 'CRIAR RECEITA' : 'PRÓXIMO'}
        </button>
      </div>
    </div>
  );
