  SOBREMESA = 'Sobremesa'
}

export enum CalorieLevel {
  BAIXISSIMO = 'Baixíssimo (até 200 kcal)',
  BAIXO = 'Baixo (201-400 kcal)',
  MEDIO = 'Médio (401-600 kcal)',
  ALTO = 'Alto (601-800 kcal)',
