                      }`}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Preparo</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Como prefere preparar?</span>
                <div className="grid grid-cols-1 gap-3 mt-3">
                  {prepOptions.map(p => (
                    <button
                      type="button"
                      key={p}
                      onClick={() => togglePrep(p)}
                      className={`w-full text-center p-5 rounded-[1.25rem] border-4 font-black transition-all text-lg leading-tight ${
                        formData.prepMethods.includes(p) 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                        : 'border-slate-300 bg-white text-slate-400 hover:border-slate-400'
                      }`}
                    >
                      {p}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 5 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Ingredientes</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Ingredientes favoritos</span>
                <textarea 
                  rows={3}
                  placeholder="Ex: frango, brócolis, aveia, chocolate 70%..."
                  value={formData.ingredients}
                  onChange={e => setFormData({...formData, ingredients: e.target.value})}
