          </button>
        )}
        <button 
          type="button"
          onClick={handleNext}
          className="flex-[2] py-5 bg-emerald-500 text-white rounded-2xl font-black text-2xl hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-200 active:scale-95 uppercase"
        >
          {step === totalSteps ? 'CRIAR RECEITA' : 'PRÓXIMO'}
        </button>
      </div>
    </div>
  );
};

export default StepForm;

import React, { useState } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  ResultOption, 
  UserPreferences 
} from '../types';

interface StepFormProps {
  initialData: UserPreferences;
  onSubmit: (data: UserPreferences) => void;
  error: string | null;
}

const StepForm: React.FC<StepFormProps> = ({ initialData, onSubmit, error }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<UserPreferences>({
    ...initialData,
    dishType: initialData.dishType || '',
    // Garante que por padrão traga todos os detalhes já que o passo 6 foi removido
    resultOptions: [ResultOption.TODOS]
  });

  const totalSteps = 5;

  const handleNext = () => {
    if (step === 1 && formData.dietaryFilters.length === 0) {
      alert("Selecione pelo menos um filtro dietético.");
      return;
    }
    if (step < totalSteps) setStep(step + 1);
    else onSubmit(formData);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const toggleDietary = (val: DietaryFilter) => {
    setFormData(prev => {
      let newFilters: DietaryFilter[];

      if (val === DietaryFilter.SEM_RESTRICAO) {
        newFilters = [val];
      } else {
        const filtered = prev.dietaryFilters.filter(f => f !== DietaryFilter.SEM_RESTRICAO);
        newFilters = filtered.includes(val)
          ? filtered.filter(f => f !== val)
          : [...filtered, val];
      }

      return {
        ...prev,
        dietaryFilters: newFilters
      };
    });
  };

  const togglePrep = (val: PrepMethod) => {
    setFormData(prev => ({
      ...prev,
      prepMethods: prev.prepMethods.includes(val)
        ? prev.prepMethods.filter(p => p !== val)
        : [...prev.prepMethods, val]
    }));
  };

  // Reorder dietary filters to put "Sem Restrição" at the end
  const dietaryOptions = Object.values(DietaryFilter).filter(f => f !== DietaryFilter.SEM_RESTRICAO);
  dietaryOptions.push(DietaryFilter.SEM_RESTRICAO);

  // Alphabetical sort for PrepMethod
  const prepOptions = Object.values(PrepMethod).sort((a, b) => a.localeCompare(b));

  return (
    <div className="p-6 h-full flex flex-col bg-white">
      <div className="mb-8 print:hidden">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">
            Passo {step} <span className="text-emerald-500">/ {totalSteps}</span>
          </h2>
          <span className="text-sm font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full uppercase">
            {Math.round((step / totalSteps) * 100)}%
          </span>
        </div>
        <div className="h-3 w-full bg-slate-100 rounded-full overflow-hidden">
          <div 
            className="h-full bg-emerald-500 transition-all duration-500 ease-out" 
            style={{ width: `${(step / totalSteps) * 100}%` }}
          ></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto pb-24">
        {error && (
          <div className="bg-red-50 text-red-600 p-5 rounded-2xl mb-6 text-base font-bold border-2 border-red-300">
            ⚠️ {error}
          </div>
        )}

        {step === 1 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Perfil Alimentar</h3>
            <p className="text-slate-600 text-lg font-medium italic">Selecione suas restrições ou escolhas de saúde.</p>
            <div className="grid grid-cols-2 gap-3">
              {dietaryOptions.map(f => (
                <div 
                  key={f} 
                  onClick={() => toggleDietary(f)}
                  className={`flex items-center justify-center text-center p-6 rounded-[1.25rem] border-4 transition-all cursor-pointer ${
                    f === DietaryFilter.SEM_RESTRICAO ? 'col-span-2' : ''
                  } ${
                    formData.dietaryFilters.includes(f) 
                      ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                      : 'border-slate-300 hover:border-slate-400 bg-white text-slate-400'
                  }`}
                >
                  <span className="font-black text-base leading-tight uppercase tracking-tight">{f}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Refeição & Gosto</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Momento do Dia</span>
                <select 
                  value={formData.mealType}
                  onChange={e => setFormData({...formData, mealType: e.target.value as MealType})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-300 focus:border-emerald-500 focus:ring-0 transition-all bg-white text-slate-800 font-black text-xl outline-none"
                >
                  {Object.values(MealType).map(m => <option key={m} value={m}>{m}</option>)}
                </select>
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Tipo de Prato</span>
                <input 
                  type="text"
                  placeholder="Ex: Cookie, Massa, Shake, Panqueca, Torta..."
                  value={formData.dishType}
                  onChange={e => setFormData({...formData, dishType: e.target.value})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-300 focus:border-emerald-500 outline-none bg-white text-slate-800 font-black text-xl placeholder:text-slate-400 shadow-sm"
                />
                <p className="text-xs text-slate-400 mt-2 font-bold uppercase ml-1 italic">Exemplos: Cookie, Massa, Shake, Panqueca...</p>
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Sabor Predominante</span>
                <div className="grid grid-cols-2 gap-4 mt-2">
                  {Object.values(Flavor).map(f => (
                    <button
                      type="button"
                      key={f}
                      onClick={() => setFormData({...formData, flavor: f})}
                      className={`py-5 rounded-2xl border-4 font-black transition-all text-xl ${
                        formData.flavor === f 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-700' 
                        : 'border-slate-300 bg-white text-slate-400'
                      }`}
                    >
                      {f}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Porções & Calorias</h3>
            <div className="space-y-8">
              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Número de Pessoas</span>
                <div className="flex items-center gap-4 mt-3">
                  <button 
                    onClick={() => setFormData(p => ({...p, peopleCount: Math.max(1, p.peopleCount - 1)}))}
                    className="w-16 h-16 rounded-2xl border-4 border-slate-300 flex items-center justify-center text-3xl font-black"
                  > - </button>
                  <span className="flex-1 text-center text-5xl font-black text-emerald-600">{formData.peopleCount}</span>
                  <button 
                    onClick={() => setFormData(p => ({...p, peopleCount: Math.min(10, p.peopleCount + 1)}))}
                    className="w-16 h-16 rounded-2xl border-4 border-slate-300 flex items-center justify-center text-3xl font-black"
                  > + </button>
                </div>
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Intensidade Energética</span>
                <div className="grid grid-cols-1 gap-3 mt-3">
                  {Object.values(CalorieLevel).map(c => (
                    <button
                      type="button"
                      key={c}
                      onClick={() => setFormData({...formData, calorieLevel: c})}
                      className={`w-full text-center p-5 rounded-[1.25rem] border-4 font-black transition-all text-lg leading-tight ${
                        formData.calorieLevel === c 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                        : 'border-slate-300 bg-white text-slate-400 hover:border-slate-400'
                      }`}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Preparo</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Como prefere preparar?</span>
                <div className="grid grid-cols-1 gap-3 mt-3">
                  {prepOptions.map(p => (
                    <button
                      type="button"
                      key={p}
                      onClick={() => togglePrep(p)}
                      className={`w-full text-center p-5 rounded-[1.25rem] border-4 font-black transition-all text-lg leading-tight ${
                        formData.prepMethods.includes(p) 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                        : 'border-slate-300 bg-white text-slate-400 hover:border-slate-400'
                      }`}
                    >
                      {p}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 5 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Ingredientes</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Ingredientes favoritos</span>
                <textarea 
                  rows={3}
                  placeholder="Ex: frango, brócolis, aveia, chocolate 70%..."
                  value={formData.ingredients}
                  onChange={e => setFormData({...formData, ingredients: e.target.value})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-300 focus:border-emerald-500 outline-none bg-white text-slate-800 font-black text-xl placeholder:text-slate-400 shadow-sm"
                />
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Ingredientes Dispensáveis</span>
                <textarea 
                  rows={3}
                  placeholder="O que você NÃO quer na receita? Ex: cebola, pimenta, coentro..."
                  value={formData.dispensableIngredients}
                  onChange={e => setFormData({...formData, dispensableIngredients: e.target.value})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-300 focus:border-slate-900 outline-none bg-white text-slate-800 font-black text-xl placeholder:text-slate-400 shadow-sm"
                />
                <p className="text-xs text-slate-400 mt-2 font-bold uppercase ml-1 italic">Itens listados aqui serão evitados pela IA.</p>
              </label>
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 w-full p-6 bg-white border-t border-slate-100 flex gap-4 z-20">
        {step > 1 && (
          <button 
            type="button"
            onClick={handleBack}
            className="flex-1 py-5 border-4 border-emerald-500 text-emerald-600 rounded-2xl font-black text-lg hover:bg-emerald-50 transition-all active:scale-95 uppercase"
          >
            VOLTAR
          </button>
        )}
        <button 
          type="button"
          onClick={handleNext}
          className="flex-[2] py-5 bg-emerald-500 text-white rounded-2xl font-black text-2xl hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-200 active:scale-95 uppercase"
        >
          {step === totalSteps ? 'CRIAR RECEITA' : 'PRÓXIMO'}
        </button>
      </div>
    </div>
  );
};

