          onClick={() => setIsImageZoomed(false)}
        >
          <img 
            src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} 
            alt={recipe.title}
            className="w-full h-full object-contain"
          />
          <button 
            className="absolute top-8 right-8 text-white w-14 h-14 rounded-full bg-black/40 backdrop-blur-md flex items-center justify-center text-4xl font-light border border-white/20 active:scale-90 transition-transform"
            onClick={(e) => {
                e.stopPropagation();
                setIsImageZoomed(false);
            }}
          >
            ✕
          </button>
        </div>
      )}

      {/* Imagem de Cabeçalho */}
      <div className="relative h-96 flex-shrink-0 print:hidden cursor-zoom-in group">
