          {prefs && prefs.dietaryFilters.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-3 print:hidden">
              {prefs.dietaryFilters.map(f => (
                <span key={f} className="text-base bg-emerald-100 text-emerald-700 px-4 py-1 rounded-full font-black uppercase tracking-widest">
                  {f}
                </span>
              ))}
            </div>
          )}
          <h1 className="text-5xl font-black text-slate-900 leading-tight mb-2 tracking-tighter">{recipe.title}</h1>
          <div className="flex flex-wrap items-center gap-3 text-slate-600 text-lg font-black bg-slate-50 p-4 rounded-2xl w-fit print:bg-transparent print:p-0">
            <span className="flex items-center gap-2 whitespace-nowrap">👥 {prefs?.peopleCount || 1} { (prefs?.peopleCount || 1) > 1 ? 'pessoas' : 'pessoa'}</span>
            <span className="flex items-center gap-2 whitespace-nowrap">🍽️ {prefs?.mealType}</span>
            <span className="flex items-center gap-2 whitespace-nowrap">⏱️ {recipe.estimatedTime}</span>
