          <SplashScreen 
            onStart={handleStart} 
            onOpenFavorites={handleOpenFavorites} 
          />
        )}

        {view === 'form' && (
          <StepForm 
            initialData={preferences} 
            onSubmit={handleGenerate} 
            error={error}
          />
        )}

        {view === 'loading' && (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-6 animate-pulse mt-40">
            <div className="w-20 h-20 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
            <h2 className="text-3xl font-black text-emerald-700">Cozinhando sua ideia...</h2>
            <p className="text-slate-500 text-lg italic font-medium">"Estamos selecionando os melhores ingredientes e calculando os macros para você."</p>
          </div>
        )}

        {view === 'result' && result && (
          <ResultScreen 
            recipe={result} 
            prefs={preferences} 
            onBack={handleReset} 
            onViewFavorites={handleOpenFavorites}
            onSaveHistory={handleSaveToHistory}
          />
        )}

        {view === 'favorites' && (
          <FavoritesList 
            onSelect={handleSelectRecipe}
            onBack={() => setView('splash')}
            onNewRecipe={handleStart}
          />
        )}
      </div>

      <style>{`
        @keyframes loading {
          0% { width: 0%; }
          50% { width: 100%; }
          100% { width: 0%; }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  ResultOption, 
  UserPreferences, 
  RecipeResult 
} from './types';
import { generateRecipe } from './services/geminiService';
import StepForm from './components/StepForm';
import ResultScreen from './components/ResultScreen';
import SplashScreen from './components/SplashScreen';
import FavoritesList from './components/FavoritesList';
import HistoryList from './components/HistoryList';

const App: React.FC = () => {
  const [view, setView] = useState<'splash' | 'form' | 'loading' | 'result' | 'favorites' | 'history'>('splash');
  const [preferences, setPreferences] = useState<UserPreferences>({
    dietaryFilters: [],
    mealType: MealType.ALMOCO,
    dishType: '',
    peopleCount: 1,
    calorieLevel: CalorieLevel.MEDIO,
    flavor: Flavor.SALGADO,
    ingredients: '',
    dispensableIngredients: '',
    prepMethods: [],
    resultOptions: [ResultOption.TODOS]
  });
  const [result, setResult] = useState<RecipeResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleStart = () => setView('form');
  const handleOpenFavorites = () => setView('favorites');
  const handleOpenHistory = () => setView('history');

  const handleGenerate = async (prefs: UserPreferences) => {
    setPreferences(prefs);
    setView('loading');
    setError(null);
    try {
      const data = await generateRecipe(prefs);

      // Salva no histórico automaticamente
      const history = JSON.parse(localStorage.getItem('fit_recipes_history') || '[]');
      const newHistory = [data, ...history].slice(0, 50); // Mantém as últimas 50
      localStorage.setItem('fit_recipes_history', JSON.stringify(newHistory));

      setResult(data);
      setView('result');
    } catch (err) {
      setError('Ocorreu um erro ao gerar sua receita. Tente novamente.');
      setView('form');
    }
  };

  const handleSelectRecipe = (recipe: RecipeResult) => {
    setResult(recipe);
    setView('result');
  };

  const handleReset = () => {
    setView('splash');
    setResult(null);
  };

  return (
    <div className="min-h-screen bg-emerald-50 text-slate-800">
      <div className="max-w-xl mx-auto min-h-screen bg-white shadow-xl relative overflow-hidden">
        {view === 'splash' && (
          <SplashScreen 
            onStart={handleStart} 
            onOpenFavorites={handleOpenFavorites} 
            onOpenHistory={handleOpenHistory}
          />
        )}

        {view === 'form' && (
          <StepForm 
            initialData={preferences} 
            onSubmit={handleGenerate} 
            error={error}
          />
        )}

        {view === 'loading' && (
          <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-6 animate-pulse mt-40">
            <div className="w-20 h-20 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
            <h2 className="text-3xl font-black text-emerald-700">Cozinhando sua ideia...</h2>
            <p className="text-slate-500 text-lg italic font-medium">"Estamos selecionando os melhores ingredientes e calculando os macros para você."</p>
          </div>
        )}

        {view === 'result' && result && (
          <ResultScreen 
            recipe={result} 
            prefs={preferences} 
            onBack={handleReset} 
            onViewFavorites={handleOpenFavorites}
            onSaveHistory={() => {}} 
          />
        )}

        {view === 'favorites' && (
          <FavoritesList 
            onSelect={handleSelectRecipe}
            onBack={() => setView('splash')}
            onNewRecipe={handleStart}
          />
        )}

        {view === 'history' && (
          <HistoryList 
            onSelect={handleSelectRecipe}
            onBack={() => setView('splash')}
            onGoToFavorites={handleOpenFavorites}
            onNewRecipe={handleStart}
          />
        )}
      </div>

      <style>{`
        @keyframes loading {
          0% { width: 0%; }
          50% { width: 100%; }
          100% { width: 0%; }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { RecipeResult, UserPreferences, ResultOption } from '../types';

interface ResultScreenProps {
  recipe: RecipeResult;
  prefs?: UserPreferences;
  onBack: () => void;
  onViewFavorites: () => void;
  onSaveHistory: (recipe: RecipeResult) => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ recipe, prefs, onBack, onViewFavorites, onSaveHistory }) => {
  const [isFavorite, setIsFavorite] = useState(false);
  const [isImageZoomed, setIsImageZoomed] = useState(false);

  useEffect(() => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    const exists = favorites.some((f: RecipeResult) => f.title === recipe.title);
    setIsFavorite(exists);
  }, [recipe.title]);

  const handleAction = () => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');

    if (isFavorite) {
      // Se já é favorito, ação é APAGAR
      if (window.confirm("Deseja realmente apagar esta receita das suas salvas?")) {
        const newFavorites = favorites.filter((f: RecipeResult) => f.title !== recipe.title);
        localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
        setIsFavorite(false);
        onViewFavorites(); // Volta para a lista
      }
    } else {
      // Se não é favorito, ação é SALVAR
      const newFavorites = [...favorites, recipe];
      localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
      setIsFavorite(true);
      onViewFavorites(); // Vai para a lista de salvas
    }
  };

  const getFullRecipeText = () => {
    let text = `🥗 RECEITA FIT: ${recipe.title.toUpperCase()}\n\n`;
    text += `${recipe.description}\n\n`;
    text += `⏱️ TEMPO DE PREPARO: ${recipe.estimatedTime || 'N/A'}\n`;
    if (recipe.estimatedCost) text += `💰 CUSTO ESTIMADO: ${recipe.estimatedCost}\n`;
    text += `\n`;
    if (recipe.ingredients) {
      text += `🛒 INGREDIENTES:\n`;
      recipe.ingredients.forEach(ing => text += `• ${ing}\n`);
      text += `\n`;
    }
    if (recipe.instructions) {
      text += `👨‍🍳 MODO DE PREPARO:\n`;
      recipe.instructions.forEach((step, i) => text += `${i + 1}. ${step}\n`);
      text += `\n`;
    }
    text += `📊 MACRONUTRIENTES:\n`;
    text += `🔥 Calorias: ${recipe.macros.calories}\n`;
    text += `💪 Proteínas: ${recipe.macros.protein}\n`;
    text += `🍞 Carboidratos: ${recipe.macros.carbs}\n`;
    text += `🥑 Gorduras: ${recipe.macros.fats}\n\n`;
    text += `Gerado por Receitas Fit Generator`;
    return text;
  };

  const shareViaWhatsApp = () => {
    const encodedText = encodeURIComponent(getFullRecipeText().replace(/\*/g, ''));
    window.open(`https://wa.me/?text=${encodedText}`, '_blank');
  };

  const showIngredients = !prefs || prefs.resultOptions.includes(ResultOption.INGREDIENTES) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showInstructions = !prefs || prefs.resultOptions.includes(ResultOption.PREPARO) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showCost = !prefs || prefs.resultOptions.includes(ResultOption.CUSTO) || prefs.resultOptions.includes(ResultOption.TODOS);

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-72 text-slate-800">
      {isImageZoomed && (
        <div className="fixed inset-0 z-[100] bg-black flex items-center justify-center animate-in fade-in duration-300" onClick={() => setIsImageZoomed(false)}>
          <img src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} alt={recipe.title} className="w-full h-full object-contain" />
          <button className="absolute top-8 right-8 text-white w-14 h-14 rounded-full bg-black/40 backdrop-blur-md text-4xl font-light" onClick={() => setIsImageZoomed(false)}>✕</button>
        </div>
      )}

      <div className="relative h-96 flex-shrink-0 cursor-zoom-in group">
        <img src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} alt={recipe.title} onClick={() => setIsImageZoomed(true)} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-black/20"></div>
      </div>

      <div className="px-6 -mt-12 relative bg-white rounded-t-[3rem] pt-10 space-y-8">
        <div>
          {prefs && prefs.dietaryFilters.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-3">
              {prefs.dietaryFilters.map(f => (
                <span key={f} className="text-base bg-emerald-100 text-emerald-700 px-4 py-1 rounded-full font-black uppercase tracking-widest">{f}</span>
              ))}
            </div>
          )}
          <h1 className="text-5xl font-black text-slate-900 leading-tight mb-2 tracking-tighter">{recipe.title}</h1>
          <div className="flex flex-wrap items-center gap-3 text-slate-600 text-lg font-black bg-slate-50 p-4 rounded-2xl w-fit">
            <span>👥 {prefs?.peopleCount || 1} { (prefs?.peopleCount || 1) > 1 ? 'pessoas' : 'pessoa'}</span>
            <span>🍽️ {prefs?.mealType}</span>
            <span>⏱️ {recipe.estimatedTime}</span>
          </div>
        </div>

        <div className="grid grid-cols-4 gap-3 py-8 bg-emerald-900 rounded-[2.5rem] px-4 shadow-2xl text-white">
          <div className="text-center">
            <p className="text-xs opacity-70 font-black uppercase mb-1 tracking-widest">Calorias</p>
            <p className="text-2xl font-black">{recipe.macros.calories}</p>
          </div>
          <div className="text-center border-l border-white/20">
            <p className="text-xs opacity-70 font-black uppercase mb-1 tracking-widest">Proteína</p>
            <p className="text-2xl font-black">{recipe.macros.protein}</p>
          </div>
          <div className="text-center border-l border-white/20">
            <p className="text-xs opacity-70 font-black uppercase mb-1 tracking-widest">Carbs</p>
            <p className="text-2xl font-black">{recipe.macros.carbs}</p>
          </div>
          <div className="text-center border-l border-white/20">
            <p className="text-xs opacity-70 font-black uppercase mb-1 tracking-widest">Gorduras</p>
            <p className="text-2xl font-black">{recipe.macros.fats}</p>
          </div>
        </div>

        <div className="space-y-12">
          <section className="space-y-4">
            <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Sobre</h3>
            <p className="text-slate-600 text-xl leading-relaxed font-medium">{recipe.description}</p>
          </section>

          {showIngredients && (
            <section className="space-y-5">
              <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Ingredientes</h3>
              <div className="grid gap-4">
                {recipe.ingredients?.map((ing, i) => (
                  <div key={i} className="flex items-center gap-5 p-5 bg-slate-50 rounded-[1.5rem] border-2 border-slate-100">
                    <div className="w-3.5 h-3.5 bg-emerald-500 rounded-full"></div>
                    <span className="text-slate-800 font-black text-xl">{ing}</span>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showInstructions && (
            <section className="space-y-8">
              <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Preparo</h3>
              <div className="space-y-10">
                {recipe.instructions?.map((step, i) => (
                  <div key={i} className="flex gap-6 relative">
                    <span className="flex-shrink-0 w-14 h-14 rounded-[1.25rem] bg-emerald-500 text-white flex items-center justify-center font-black text-2xl shadow-xl">
                      {i + 1}
                    </span>
                    <p className="text-slate-600 text-xl leading-relaxed pt-1 font-bold">{step}</p>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showCost && recipe.estimatedCost && (
            <div className="bg-emerald-50 border-4 border-emerald-100 p-8 rounded-[2.5rem] flex items-center justify-between">
              <div>
                <p className="text-base text-emerald-600 font-black uppercase tracking-widest mb-1">Custo Estimado</p>
                <p className="text-3xl font-black text-emerald-900">{recipe.estimatedCost}</p>
              </div>
              <span className="text-6xl">💰</span>
            </div>
          )}
        </div>
      </div>

      <div className="fixed bottom-0 left-0 w-full max-w-xl mx-auto p-5 bg-white/95 backdrop-blur-2xl border-t-2 border-slate-100 grid grid-cols-1 gap-4 z-30 shadow-[0_-15px_40px_rgba(0,0,0,0.1)]">
        <button onClick={shareViaWhatsApp} className="w-full py-5 bg-emerald-500 text-white rounded-[1.5rem] font-black text-xl uppercase shadow-2xl shadow-emerald-200 active:scale-95 transition-all">
          Enviar por WhatsApp
        </button>

        <div className="grid grid-cols-2 gap-4">
          <button onClick={onBack} className="w-full py-5 bg-white text-emerald-600 border-4 border-emerald-600 rounded-[1.5rem] font-black text-lg transition-all active:scale-95 shadow-xl uppercase">
            Voltar ao Início
          </button>

          <button 
            onClick={handleAction}
            className={`w-full py-5 rounded-[1.5rem] font-black text-lg flex items-center justify-center gap-3 transition-all active:scale-95 shadow-xl uppercase ${
              isFavorite 
              ? 'bg-red-500 text-white shadow-red-100' 
              : 'bg-white text-emerald-600 border-4 border-emerald-600'
            }`}
          >
            {isFavorite ? 'Apagar' : 'Salvar'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default ResultScreen;

import React, { useState, useEffect } from 'react';
import { RecipeResult } from '../types';

interface FavoritesListProps {
  onSelect: (recipe: RecipeResult) => void;
  onBack: () => void;
  onNewRecipe: () => void;
}

const FavoritesList: React.FC<FavoritesListProps> = ({ onSelect, onBack, onNewRecipe }) => {
  const [favorites, setFavorites] = useState<RecipeResult[]>([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    setFavorites(stored);
  }, []);

  return (
    <div className="p-6 h-full flex flex-col bg-slate-50">
      <div className="flex items-center justify-center mb-10">
        <h2 className="text-4xl font-black text-slate-800 tracking-tighter">Minhas Receitas</h2>
      </div>

      <div className="flex-1 overflow-y-auto space-y-5 pb-24">
        {favorites.length === 0 ? (
          <div className="text-center py-20 space-y-6">
            <div className="text-8xl opacity-20">📖</div>
            <p className="text-slate-400 font-black text-xl uppercase tracking-widest">Nenhuma receita salva.</p>
          </div>
        ) : (
          favorites.map((recipe, idx) => (
            <div 
              key={idx}
              onClick={() => onSelect(recipe)}
              className="bg-white p-5 rounded-[2.5rem] shadow-sm border-2 border-slate-100 flex gap-5 cursor-pointer hover:shadow-xl transition-all group active:scale-95"
            >
              <div className="w-24 h-24 rounded-3xl overflow-hidden flex-shrink-0 shadow-lg">
                <img 
                  src={recipe.imageUrl || 'https://picsum.photos/200'} 
                  alt={recipe.title} 
                  className="w-full h-full object-cover"
                />
              </div>
              <div className="flex-1 min-w-0 flex flex-col justify-center">
                <h4 className="font-black text-xl text-slate-800 truncate group-hover:text-emerald-600 transition-colors">
                  {recipe.title}
                </h4>
                <div className="flex items-center gap-3 mt-2">
                  <span className="text-sm font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full uppercase">
                    {recipe.macros.calories}
                  </span>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      <div className="fixed bottom-0 left-0 w-full max-w-xl mx-auto p-6 bg-white/95 backdrop-blur-xl border-t-4 border-slate-100 shadow-[0_-15px_40px_rgba(0,0,0,0.05)]">
        <button 
          onClick={onBack}
          className="w-full py-5 bg-emerald-500 text-white rounded-[1.5rem] font-black text-xl transition-all hover:bg-emerald-600 active:scale-95 uppercase shadow-xl shadow-emerald-100"
        >
          Voltar ao Início
        </button>
      </div>
    </div>
  );
};

export default FavoritesList;

import React, { useState, useEffect } from 'react';
import { RecipeResult } from '../types';

interface HistoryListProps {
  onSelect: (recipe: RecipeResult) => void;
  onBack: () => void;
  onGoToFavorites: () => void;
  onNewRecipe: () => void;
}

const HistoryList: React.FC<HistoryListProps> = ({ onSelect, onBack, onGoToFavorites, onNewRecipe }) => {
  const [history, setHistory] = useState<RecipeResult[]>([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem('fit_recipes_history') || '[]');
    setHistory(stored);
  }, []);

  const clearHistory = () => {
    if (window.confirm('Deseja realmente limpar todo seu histórico de gerações?')) {
      localStorage.removeItem('fit_recipes_history');
      setHistory([]);
    }
  };

  return (
    <div className="p-6 h-full flex flex-col bg-slate-50">
      <div className="flex items-center justify-between mb-8">
        <h2 className="text-4xl font-black text-slate-800 tracking-tighter">Histórico</h2>
        {history.length > 0 && (
          <button 
            onClick={clearHistory}
            className="text-red-500 font-black uppercase text-sm tracking-widest"
          >
            Limpar
          </button>
        )}
      </div>

      <div className="flex-1 overflow-y-auto space-y-4 pb-32">
        {history.length === 0 ? (
          <div className="text-center py-20 space-y-6">
            <div className="text-8xl opacity-20">📜</div>
            <p className="text-slate-400 font-black text-xl uppercase tracking-widest">Nenhuma receita gerada ainda.</p>
          </div>
        ) : (
          history.map((recipe, idx) => (
            <div 
              key={idx}
              onClick={() => onSelect(recipe)}
              className="bg-white p-4 rounded-[2rem] shadow-sm border-2 border-slate-100 flex gap-4 cursor-pointer hover:shadow-md transition-all active:scale-95 group"
            >
              <div className="w-20 h-20 rounded-2xl overflow-hidden flex-shrink-0 shadow-sm">
                <img 
                  src={recipe.imageUrl || 'https://picsum.photos/200'} 
                  alt={recipe.title} 
                  className="w-full h-full object-cover"
                />
              </div>
              <div className="flex-1 min-w-0 flex flex-col justify-center">
                <h4 className="font-black text-lg text-slate-800 truncate group-hover:text-emerald-600 transition-colors">{recipe.title}</h4>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full uppercase tracking-tighter">
                    {recipe.macros.calories}
                  </span>
                  <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">
                    {recipe.estimatedTime}
                  </span>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      <div className="fixed bottom-0 left-0 w-full max-w-xl mx-auto p-6 bg-white/95 backdrop-blur-xl border-t-4 border-slate-100 shadow-[0_-15px_40px_rgba(0,0,0,0.05)] space-y-3">
