import React, { useState, useEffect } from 'react';
import { RecipeResult, UserPreferences, ResultOption } from '../types';

interface ResultScreenProps {
  recipe: RecipeResult;
  prefs?: UserPreferences;
  onBack: () => void;
  onViewFavorites: () => void;
  onSaveHistory: (recipe: RecipeResult) => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ recipe, prefs, onBack, onViewFavorites, onSaveHistory }) => {
  const [isFavorite, setIsFavorite] = useState(false);
  const [isImageZoomed, setIsImageZoomed] = useState(false);

  useEffect(() => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    const exists = favorites.some((f: RecipeResult) => f.title === recipe.title);
    setIsFavorite(exists);
  }, [recipe.title]);

  const handleAction = () => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');

    if (isFavorite) {
      // Se já é favorito, ação é APAGAR
      if (window.confirm("Deseja realmente apagar esta receita das suas salvas?")) {
        const newFavorites = favorites.filter((f: RecipeResult) => f.title !== recipe.title);
        localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
        setIsFavorite(false);
        onViewFavorites(); // Volta para a lista
      }
    } else {
      // Se não é favorito, ação é SALVAR
      const newFavorites = [...favorites, recipe];
      localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
      setIsFavorite(true);
      onViewFavorites(); // Vai para a lista de salvas
    }
  };

  const getFullRecipeText = () => {
    let text = `🥗 RECEITA FIT: ${recipe.title.toUpperCase()}\n\n`;
    text += `${recipe.description}\n\n`;
    text += `⏱️ TEMPO DE PREPARO: ${recipe.estimatedTime || 'N/A'}\n`;
    if (recipe.estimatedCost) text += `💰 CUSTO ESTIMADO: ${recipe.estimatedCost}\n`;
    text += `\n`;
    if (recipe.ingredients) {
      text += `🛒 INGREDIENTES:\n`;
      recipe.ingredients.forEach(ing => text += `• ${ing}\n`);
      text += `\n`;
    }
    if (recipe.instructions) {
      text += `👨‍🍳 MODO DE PREPARO:\n`;
      recipe.instructions.forEach((step, i) => text += `${i + 1}. ${step}\n`);
      text += `\n`;
    }
    text += `📊 MACRONUTRIENTES:\n`;
    text += `🔥 Calorias: ${recipe.macros.calories}\n`;
    text += `💪 Proteínas: ${recipe.macros.protein}\n`;
    text += `🍞 Carboidratos: ${recipe.macros.carbs}\n`;
    text += `🥑 Gorduras: ${recipe.macros.fats}\n\n`;
    text += `Gerado por Receitas Fit Generator`;
    return text;
  };

  const shareViaWhatsApp = () => {
    const encodedText = encodeURIComponent(getFullRecipeText().replace(/\*/g, ''));
    window.open(`https://wa.me/?text=${encodedText}`, '_blank');
  };

  const showIngredients = !prefs || prefs.resultOptions.includes(ResultOption.INGREDIENTES) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showInstructions = !prefs || prefs.resultOptions.includes(ResultOption.PREPARO) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showCost = !prefs || prefs.resultOptions.includes(ResultOption.CUSTO) || prefs.resultOptions.includes(ResultOption.TODOS);

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-72 text-slate-800">
      {isImageZoomed && (
        <div className="fixed inset-0 z-[100] bg-black flex items-center justify-center animate-in fade-in duration-300" onClick={() => setIsImageZoomed(false)}>
          <img src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} alt={recipe.title} className="w-full h-full object-contain" />
          <button className="absolute top-8 right-8 text-white w-14 h-14 rounded-full bg-black/40 backdrop-blur-md text-4xl font-light" onClick={() => setIsImageZoomed(false)}>✕</button>
        </div>
      )}

      <div className="relative h-96 flex-shrink-0 cursor-zoom-in group">
        <img src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} alt={recipe.title} onClick={() => setIsImageZoomed(true)} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-black/20"></div>
      </div>

      <div className="px-6 -mt-12 relative bg-white rounded-t-[3rem] pt-10 space-y-8">
        <div>
          {prefs && prefs.dietaryFilters.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-3">
              {prefs.dietaryFilters.map(f => (
                <span key={f} className="text-base bg-emerald-100 text-emerald-700 px-4 py-1 rounded-full font-black uppercase tracking-widest">{f}</span>
              ))}
            </div>
          )}
          <h1 className="text-5xl font-black text-slate-900 leading-tight mb-2 tracking-tighter">{recipe.title}</h1>
          <div className="flex flex-wrap items-center gap-3 text-slate-600 text-lg font-black bg-slate-50 p-4 rounded-2xl w-fit">
            <span>👥 {prefs?.peopleCount || 1} { (prefs?.peopleCount || 1) > 1 ? 'pessoas' : 'pessoa'}</span>
            <span>🍽️ {prefs?.mealType}</span>
            <span>⏱️ {recipe.estimatedTime}</span>
          </div>
        </div>

        <div className="grid grid-cols-4 gap-3 py-8 bg-emerald-900 rounded-[2.5rem] px-4 shadow-2xl text-white">
          <div className="text-center">
            <p className="text-xs opacity-70 font-black uppercase mb-1 tracking-widest">Calorias</p>
            <p className="text-2xl font-black">{recipe.macros.calories}</p>
          </div>
          <div className="text-center border-l border-white/20">
            <p className="text-xs opacity-70 font-black uppercase mb-1 tracking-widest">Proteína</p>
