                <div className="grid grid-cols-3 gap-2 mt-3">
                  {Object.values(SkillLevel).map(s => (
                    <button
                      type="button"
                      key={s}
                      onClick={() => setFormData({...formData, skillLevel: s})}
                      className={`py-4 rounded-[1.25rem] border-4 font-black transition-all text-sm leading-tight uppercase ${
                        formData.skillLevel === s 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                        : 'border-slate-300 bg-white text-slate-400 hover:border-slate-400'
                      }`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Como prefere preparar?</span>
                <div className="grid grid-cols-1 gap-3 mt-3">
                  {prepOptions.map(p => (
                    <button
                      type="button"
                      key={p}
                      onClick={() => togglePrep(p)}
                      className={`w-full text-center p-5 rounded-[1.25rem] border-4 font-black transition-all text-lg leading-tight ${
                        formData.prepMethods.includes(p) 
                        ? 'border-emerald-500 bg-emerald-50 text-emerald-800' 
                        : 'border-slate-300 bg-white text-slate-400 hover:border-slate-400'
                      }`}
                    >
                      {p}
                    </button>
                  ))}
                </div>
              </label>
            </div>
          </div>
        )}

        {step === 5 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
            <h3 className="text-3xl font-black text-slate-900 leading-tight">Ingredientes</h3>
            <div className="space-y-6">
              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Ingredientes favoritos</span>
                <textarea 
                  rows={3}
                  placeholder="Ex: frango, brócolis, aveia, chocolate 70%..."
                  value={formData.ingredients}
                  onChange={e => setFormData({...formData, ingredients: e.target.value})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-300 focus:border-emerald-500 outline-none bg-white text-slate-800 font-black text-xl placeholder:text-slate-400 shadow-sm"
                />
              </label>

              <label className="block">
                <span className="text-base font-black text-slate-500 uppercase tracking-widest ml-1">Ingredientes Dispensáveis</span>
                <textarea 
                  rows={3}
                  placeholder="O que você NÃO quer na receita? Ex: cebola, pimenta, coentro..."
                  value={formData.dispensableIngredients}
                  onChange={e => setFormData({...formData, dispensableIngredients: e.target.value})}
                  className="mt-2 block w-full p-5 rounded-2xl border-4 border-slate-300 focus:border-slate-900 outline-none bg-white text-slate-800 font-black text-xl placeholder:text-slate-400 shadow-sm"
                />
                <p className="text-xs text-slate-400 mt-2 font-bold uppercase ml-1 italic">Itens listados aqui serão evitados pela IA.</p>
              </label>
            </div>
          </div>
        )}
      </div>

      <div className="absolute bottom-0 left-0 w-full p-6 bg-white border-t border-slate-100 flex gap-4 z-20">
        {step > 1 && (
          <button 
            type="button"
            onClick={handleBack}
            className="flex-1 py-5 border-4 border-emerald-500 text-emerald-600 rounded-2xl font-black text-lg hover:bg-emerald-50 transition-all active:scale-95 uppercase"
          >
            VOLTAR
          </button>
        )}
        <button 
          type="button"
          onClick={handleNext}
          className="flex-[2] py-5 bg-emerald-500 text-white rounded-2xl font-black text-2xl hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-200 active:scale-95 uppercase"
        >
          {step === totalSteps ? 'CRIAR RECEITA' : 'PRÓXIMO'}
        </button>
      </div>
    </div>
  );
};

