import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { UserPreferences, RecipeResult } from "../types";

export const generateRecipe = async (prefs: UserPreferences): Promise<RecipeResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("Chave de API não configurada.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `Aja como um nutricionista sênior e chef especializado em gastronomia saudável.
  Crie uma receita FIT detalhada com estas especificações:
  - Objetivo: ${prefs.dietaryFilters.join(', ')}
  - Refeição: ${prefs.mealType}
  - Desejo: ${prefs.dishType || 'Refeição equilibrada'}
  - Porções: ${prefs.peopleCount} pessoa(s)
  - Calorias: ${prefs.calorieLevel}
  - Sabor: ${prefs.flavor}
  - Habilidade do Cozinheiro: ${prefs.skillLevel}
  - Ingredientes para usar: ${prefs.ingredients || 'Ingredientes sazonais saudáveis'}
  - Ingredientes para evitar: ${prefs.dispensableIngredients || 'Nenhum'}
  - Métodos de preparo: ${prefs.prepMethods.join(', ') || 'Qualquer método saudável'}

  Certifique-se de que a complexidade das instruções seja compatível com a habilidade "${prefs.skillLevel}".
  Certifique-se de que os macronutrientes sejam coerentes com o nível de calorias escolhido.
  O custo deve ser uma estimativa em R$ (Real Brasileiro).`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            ingredients: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            instructions: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            estimatedCost: { type: Type.STRING },
            estimatedTime: { type: Type.STRING },
            macros: {
              type: Type.OBJECT,
              properties: {
                protein: { type: Type.STRING },
                carbs: { type: Type.STRING },
                fats: { type: Type.STRING },
                calories: { type: Type.STRING },
              },
              required: ["protein", "carbs", "fats", "calories"]
            }
          },
          required: ["title", "description", "ingredients", "instructions", "macros", "estimatedTime"]
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("Resposta vazia do modelo.");

    const recipeData = JSON.parse(text) as RecipeResult;

    // Geração de imagem com fallback seguro
    if (prefs.resultOptions.includes('Imagem da Receita' as any) || prefs.resultOptions.includes('Todas as Opções' as any)) {
      try {
        const imgResponse = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [{ text: `High-quality professional food photography of ${recipeData.title}, clean background, gourmet plating, natural light.` }]
          },
        });

        if (imgResponse.candidates?.[0]?.content?.parts) {
          for (const part of imgResponse.candidates[0].content.parts) {
            if (part.inlineData) {
              recipeData.imageUrl = `data:image/png;base64,${part.inlineData.data}`;
              break;
            }
          }
        }
      } catch (e) {
        console.warn("Falha na geração da imagem, usando placeholder.", e);
      }
    }

    if (!recipeData.imageUrl) {
      recipeData.imageUrl = `https://picsum.photos/seed/${encodeURIComponent(recipeData.title)}/800/600`;
    }

    return recipeData;
  } catch (error) {
    console.error("Erro na geração da receita:", error);
    throw error;
  }
};

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
