/**
 * Função utilitária para limpar a string de resposta da IA.
 * Remove possíveis blocos de código markdown (```json ... ```) que podem quebrar o JSON.parse.
 */
const cleanJsonString = (str: string): string => {
  return str.replace(/```json\n?|```/g, "").trim();
};

export const generateRecipe = async (prefs: UserPreferences): Promise<RecipeResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("Chave de API não configurada no ambiente.");
  }

  // Inicializa a API dentro da função para garantir o uso da chave mais recente
  const ai = new GoogleGenAI({ apiKey });

  const prompt = `Aja como um nutricionista sênior e chef especializado em gastronomia saudável.
  Crie uma receita FIT detalhada com estas especificações exatas:
  - Objetivo: ${prefs.dietaryFilters.join(', ')}
  - Refeição: ${prefs.mealType}
  - Tipo de Prato: ${prefs.dishType || 'Refeição equilibrada'}
  - Porções: ${prefs.peopleCount} pessoa(s)
  - Calorias: ${prefs.calorieLevel}
  - Perfil de Sabor: ${prefs.flavor}
  - Habilidade do Cozinheiro: ${prefs.skillLevel}
  - Ingredientes desejados: ${prefs.ingredients || 'Ingredientes sazonais saudáveis'}
  - Ingredientes proibidos: ${prefs.dispensableIngredients || 'Nenhum'}
  - Métodos de preparo: ${prefs.prepMethods.join(', ') || 'Qualquer método saudável'}

  REGRAS OBRIGATÓRIAS:
  1. As instruções devem ser adequadas para o nível de habilidade "${prefs.skillLevel}".
  2. Os macronutrientes DEVEM ser coerentes com o nível de calorias "${prefs.calorieLevel}".
  3. O custo deve ser uma estimativa realista em R$.
  4. Retorne APENAS o JSON, sem explicações extras.`;

  try {
    // Chamada para geração de texto (Receita)
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            ingredients: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            instructions: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            estimatedCost: { type: Type.STRING },
            estimatedTime: { type: Type.STRING },
            macros: {
              type: Type.OBJECT,
              properties: {
                protein: { type: Type.STRING },
                carbs: { type: Type.STRING },
                fats: { type: Type.STRING },
                calories: { type: Type.STRING },
              },
              required: ["protein", "carbs", "fats", "calories"]
            }
          },
          required: ["title", "description", "ingredients", "instructions", "macros", "estimatedTime"]
        },
      },
    });

    const rawText = response.text;
    if (!rawText) throw new Error("A IA retornou uma resposta vazia.");

    const cleanedText = cleanJsonString(rawText);
    const recipeData = JSON.parse(cleanedText) as RecipeResult;

    // Geração de imagem com fallback e tratamento de erros silencioso
    if (prefs.resultOptions.includes('Imagem da Receita' as any) || prefs.resultOptions.includes('Todas as Opções' as any)) {
      try {
        const imgResponse = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: {
            parts: [{ text: `Professional food photography of ${recipeData.title}, healthy fitness meal, clean gourmet presentation, 4k, natural lighting.` }]
          },
        });

        const candidate = imgResponse.candidates?.[0];
        if (candidate?.content?.parts) {
          for (const part of candidate.content.parts) {
            if (part.inlineData?.data) {
              recipeData.imageUrl = `data:image/png;base64,${part.inlineData.data}`;
              break;
            }
          }
        }
      } catch (imgError) {
        console.warn("Falha na geração da imagem (filtros ou timeout). Usando placeholder.", imgError);
      }
    }

    // Fallback final se nenhuma imagem foi gerada
    if (!recipeData.imageUrl) {
      recipeData.imageUrl = `https://images.unsplash.com/photo-1490645935967-10de6ba17061?auto=format&fit=crop&q=80&w=800&sig=${Math.random()}`;
    }

    return recipeData;
  } catch (error) {
    console.error("Erro crítico no geminiService:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { RecipeResult, UserPreferences, ResultOption } from '../types';

interface ResultScreenProps {
  recipe: RecipeResult;
  prefs?: UserPreferences;
  onBack: () => void;
  onViewFavorites: () => void;
  onSaveHistory: (recipe: RecipeResult) => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ recipe, prefs, onBack, onViewFavorites, onSaveHistory }) => {
  const [isFavorite, setIsFavorite] = useState(false);
  const [isImageZoomed, setIsImageZoomed] = useState(false);

  useEffect(() => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    const exists = favorites.some((f: RecipeResult) => f.title === recipe.title);
    setIsFavorite(exists);
  }, [recipe.title]);

  const handleAction = () => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');

    if (isFavorite) {
      if (window.confirm("Deseja realmente apagar esta receita das suas salvas?")) {
        const newFavorites = favorites.filter((f: RecipeResult) => f.title !== recipe.title);
        localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
        setIsFavorite(false);
        onViewFavorites();
      }
    } else {
      const newFavorites = [...favorites, recipe];
      localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
      setIsFavorite(true);
      onViewFavorites();
    }
  };

  const getFullRecipeText = () => {
    let text = `🥗 RECEITA FIT: ${recipe.title.toUpperCase()}\n\n`;
    text += `${recipe.description}\n\n`;
    text += `⏱️ TEMPO DE PREPARO: ${recipe.estimatedTime || 'N/A'}\n`;
    if (recipe.estimatedCost) text += `💰 CUSTO ESTIMADO: ${recipe.estimatedCost}\n`;
    text += `\n`;
    if (recipe.ingredients) {
      text += `🛒 INGREDIENTES:\n`;
      recipe.ingredients.forEach(ing => text += `• ${ing}\n`);
      text += `\n`;
    }
    if (recipe.instructions) {
      text += `👨‍🍳 MODO DE PREPARO:\n`;
      recipe.instructions.forEach((step, i) => text += `${i + 1}. ${step}\n`);
      text += `\n`;
    }
    text += `📊 MACRONUTRIENTES:\n`;
    text += `🔥 Calorias: ${recipe.macros.calories}\n`;
    text += `💪 Proteínas: ${recipe.macros.protein}\n`;
    text += `🍞 Carboidratos: ${recipe.macros.carbs}\n`;
    text += `🥑 Gorduras: ${recipe.macros.fats}\n\n`;
    text += `Gerado por Receitas Fit Generator`;
    return text;
  };

  const handleShare = async () => {
    const text = getFullRecipeText().replace(/\*/g, '');

    // Tenta usar a API de compartilhamento nativa (melhor para mobile, suporta arquivos)
    if (navigator.share) {
      try {
        const shareData: ShareData = {
          title: recipe.title,
          text: text,
        };

        if (recipe.imageUrl) {
          // Converte URL ou Base64 em um arquivo para compartilhamento
          const response = await fetch(recipe.imageUrl);
          const blob = await response.blob();
          const file = new File([blob], 'receita-fit.png', { type: blob.type });

          // Verifica se o navegador suporta o compartilhamento deste arquivo específico
          if (navigator.canShare && navigator.canShare({ files: [file] })) {
            shareData.files = [file];
          }
        }

        await navigator.share(shareData);
        return; // Sucesso no compartilhamento nativo
      } catch (err) {
        console.error("Erro ao usar Web Share:", err);
        // Se falhar ou for cancelado, cai no fallback do link direto
      }
    }

    // Fallback: Link direto do WhatsApp (apenas texto, ou URL da imagem se for link público)
    let whatsappText = text;
    if (recipe.imageUrl && !recipe.imageUrl.startsWith('data:')) {
      whatsappText += `\n\n🖼️ Foto da receita: ${recipe.imageUrl}`;
    }

    const encodedText = encodeURIComponent(whatsappText);
    window.open(`https://wa.me/?text=${encodedText}`, '_blank');
  };

  const showIngredients = !prefs || prefs.resultOptions.includes(ResultOption.INGREDIENTES) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showInstructions = !prefs || prefs.resultOptions.includes(ResultOption.PREPARO) || prefs.resultOptions.includes(ResultOption.TODOS);
  const showCost = !prefs || prefs.resultOptions.includes(ResultOption.CUSTO) || prefs.resultOptions.includes(ResultOption.TODOS);

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-72 text-slate-800">
      {isImageZoomed && (
        <div className="fixed inset-0 z-[100] bg-black flex items-center justify-center animate-in fade-in duration-300" onClick={() => setIsImageZoomed(false)}>
          <img src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} alt={recipe.title} className="w-full h-full object-contain" />
          <button className="absolute top-8 right-8 text-white w-14 h-14 rounded-full bg-black/40 backdrop-blur-md text-4xl font-light" onClick={() => setIsImageZoomed(false)}>✕</button>
        </div>
      )}

      <div className="relative h-96 flex-shrink-0 cursor-zoom-in group">
        <img src={recipe.imageUrl || 'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&q=80&w=800'} alt={recipe.title} onClick={() => setIsImageZoomed(true)} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-black/20"></div>
      </div>

      <div className="px-6 -mt-12 relative bg-white rounded-t-[3rem] pt-10 space-y-8">
        <div>
          {prefs && prefs.dietaryFilters.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-3">
              {prefs.dietaryFilters.map(f => (
                <span key={f} className="text-base bg-emerald-100 text-emerald-700 px-4 py-1 rounded-full font-black uppercase tracking-widest">{f}</span>
              ))}
            </div>
          )}
          <h1 className="text-5xl font-black text-slate-900 leading-tight mb-2 tracking-tighter">{recipe.title}</h1>
          <div className="flex flex-wrap items-center gap-3 text-slate-600 text-lg font-black bg-slate-50 p-4 rounded-2xl w-fit">
            <span>👥 {prefs?.peopleCount || 1} { (prefs?.peopleCount || 1) > 1 ? 'pessoas' : 'pessoa'}</span>
            <span>🍽️ {prefs?.mealType}</span>
            <span>⏱️ {recipe.estimatedTime}</span>
          </div>
        </div>

        <div className="grid grid-cols-4 gap-3 py-8 bg-emerald-900 rounded-[2.5rem] px-4 shadow-2xl text-white">
          <div className="text-center">
            <p className="text-xs opacity-70 font-black uppercase mb-1 tracking-widest">Calorias</p>
            <p className="text-2xl font-black">{recipe.macros.calories}</p>
          </div>
          <div className="text-center border-l border-white/20">
            <p className="text-xs opacity-70 font-black uppercase mb-1 tracking-widest">Proteína</p>
            <p className="text-2xl font-black">{recipe.macros.protein}</p>
          </div>
          <div className="text-center border-l border-white/20">
            <p className="text-xs opacity-70 font-black uppercase mb-1 tracking-widest">Carbs</p>
            <p className="text-2xl font-black">{recipe.macros.carbs}</p>
          </div>
          <div className="text-center border-l border-white/20">
            <p className="text-xs opacity-70 font-black uppercase mb-1 tracking-widest">Gorduras</p>
            <p className="text-2xl font-black">{recipe.macros.fats}</p>
          </div>
        </div>

        <div className="space-y-12">
          <section className="space-y-4">
            <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Sobre</h3>
            <p className="text-slate-600 text-xl leading-relaxed font-medium">{recipe.description}</p>
          </section>

          {showIngredients && (
            <section className="space-y-5">
              <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Ingredientes</h3>
              <div className="grid gap-4">
                {recipe.ingredients?.map((ing, i) => (
                  <div key={i} className="flex items-center gap-5 p-5 bg-slate-50 rounded-[1.5rem] border-2 border-slate-100">
                    <div className="w-3.5 h-3.5 bg-emerald-500 rounded-full"></div>
                    <span className="text-slate-800 font-black text-xl">{ing}</span>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showInstructions && (
            <section className="space-y-8">
              <h3 className="text-3xl font-black text-slate-800 border-b-6 border-emerald-500 w-fit pb-1">Preparo</h3>
              <div className="space-y-10">
                {recipe.instructions?.map((step, i) => (
                  <div key={i} className="flex gap-6 relative">
                    <span className="flex-shrink-0 w-14 h-14 rounded-[1.25rem] bg-emerald-500 text-white flex items-center justify-center font-black text-2xl shadow-xl">
                      {i + 1}
                    </span>
                    <p className="text-slate-600 text-xl leading-relaxed pt-1 font-bold">{step}</p>
                  </div>
                ))}
              </div>
            </section>
          )}

          {showCost && recipe.estimatedCost && (
            <div className="bg-emerald-50 border-4 border-emerald-100 p-8 rounded-[2.5rem] flex items-center justify-between">
              <div>
                <p className="text-base text-emerald-600 font-black uppercase tracking-widest mb-1">Custo Estimado</p>
                <p className="text-3xl font-black text-emerald-900">{recipe.estimatedCost}</p>
              </div>
              <span className="text-6xl">💰</span>
            </div>
          )}
        </div>
      </div>

      <div className="fixed bottom-0 left-0 w-full max-w-xl mx-auto p-5 bg-white/95 backdrop-blur-2xl border-t-2 border-slate-100 grid grid-cols-1 gap-4 z-30 shadow-[0_-15px_40px_rgba(0,0,0,0.1)]">
        <button onClick={handleShare} className="w-full py-5 bg-emerald-500 text-white rounded-[1.5rem] font-black text-xl uppercase shadow-2xl shadow-emerald-200 active:scale-95 transition-all">
          Enviar por WhatsApp
        </button>

        <div className="grid grid-cols-2 gap-4">
          <button onClick={onBack} className="w-full py-5 bg-white text-emerald-600 border-4 border-emerald-600 rounded-[1.5rem] font-black text-lg transition-all active:scale-95 shadow-xl uppercase">
            Voltar ao Início
          </button>

          <button 
            onClick={handleAction}
            className={`w-full py-5 rounded-[1.5rem] font-black text-lg flex items-center justify-center gap-3 transition-all active:scale-95 shadow-xl uppercase bg-white border-4 ${
              isFavorite 
              ? 'text-red-600 border-red-600 shadow-red-50' 
              : 'text-emerald-600 border-emerald-600 shadow-emerald-50'
            }`}
          >
            {isFavorite ? 'Apagar' : 'Salvar'}
          </button>
        </div>
      </div>
    </div>
  );
};

