  const ai = new GoogleGenAI({ apiKey });

  // Instrução de sistema para garantir que a IA se comporte como esperado
  const systemInstruction = `Você é um nutricionista sênior e chef especializado em nutrição funcional. 
  Sua tarefa é criar receitas saudáveis e detalhadas. 
  Você DEVE retornar a resposta EXCLUSIVAMENTE em formato JSON, seguindo rigorosamente o esquema fornecido.
  Não inclua textos explicativos fora do JSON. 
  As receitas devem ser realistas, saborosas e adaptadas ao nível de habilidade do usuário.`;

  const prompt = `Gere uma receita FIT com:
  - Objetivo: ${prefs.dietaryFilters.join(', ')}
  - Tipo: ${prefs.dishType || prefs.mealType}
  - Calorias: ${prefs.calorieLevel}
  - Sabor: ${prefs.flavor}
  - Habilidade: ${prefs.skillLevel}
  - Usar: ${prefs.ingredients || 'Ingredientes saudáveis'}
  - Evitar: ${prefs.dispensableIngredients || 'Nada'}
  - Métodos: ${prefs.prepMethods.join(', ')}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
            instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
            estimatedCost: { type: Type.STRING },
            estimatedTime: { type: Type.STRING },
            macros: {
              type: Type.OBJECT,
              properties: {
                protein: { type: Type.STRING },
                carbs: { type: Type.STRING },
                fats: { type: Type.STRING },
                calories: { type: Type.STRING },
              },
              required: ["protein", "carbs", "fats", "calories"]
            }
          },
          required: ["title", "description", "ingredients", "instructions", "macros", "estimatedTime"]
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("Resposta vazia da IA.");

    const recipeData = JSON.parse(cleanJsonString(text)) as RecipeResult;

    // Geração de imagem com resiliência
    try {
      const imgResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `Foto profissional gastronômica de: ${recipeData.title}. Prato saudável, iluminação natural, fundo limpo, alta resolução.` }]
        },
        config: {
          imageConfig: { aspectRatio: "1:1" }
        }
      });

      const candidate = imgResponse.candidates?.[0];
      if (candidate?.content?.parts) {
        for (const part of candidate.content.parts) {
          if (part.inlineData?.data) {
            recipeData.imageUrl = `data:image/png;base64,${part.inlineData.data}`;
            break;
          }
        }
      }
    } catch (e) {
      console.warn("Falha na imagem:", e);
    }

    if (!recipeData.imageUrl) {
      recipeData.imageUrl = `https://images.unsplash.com/photo-1547592166-23ac45744acd?auto=format&fit=crop&q=80&w=800`;
    }

    return recipeData;
  } catch (error) {
    console.error("Erro na geração:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { RecipeResult, UserPreferences, ResultOption } from '../types';

interface ResultScreenProps {
  recipe: RecipeResult;
  prefs?: UserPreferences;
  onBack: () => void;
  onViewFavorites: () => void;
  onSaveHistory: (recipe: RecipeResult) => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ recipe, prefs, onBack, onViewFavorites, onSaveHistory }) => {
  const [isFavorite, setIsFavorite] = useState(false);
  const [isImageZoomed, setIsImageZoomed] = useState(false);
  const [isSharing, setIsSharing] = useState(false);

  useEffect(() => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    const exists = favorites.some((f: RecipeResult) => f.title === recipe.title);
    setIsFavorite(exists);
  }, [recipe.title]);

  const handleAction = () => {
    const favorites = JSON.parse(localStorage.getItem('fit_recipes_favorites') || '[]');
    if (isFavorite) {
      if (window.confirm("Remover dos favoritos?")) {
        const newFavorites = favorites.filter((f: RecipeResult) => f.title !== recipe.title);
        localStorage.setItem('fit_recipes_favorites', JSON.stringify(newFavorites));
        setIsFavorite(false);
      }
    } else {
      localStorage.setItem('fit_recipes_favorites', JSON.stringify([...favorites, recipe]));
      setIsFavorite(true);
    }
  };

  const getFullRecipeText = () => {
    let text = `*🥗 RECEITA FIT: ${recipe.title.toUpperCase()}*\n\n`;
    text += `_${recipe.description}_\n\n`;
    text += `⏱️ *Tempo:* ${recipe.estimatedTime}\n`;
    if (recipe.estimatedCost) text += `💰 *Custo:* ${recipe.estimatedCost}\n`;
    text += `\n*🛒 INGREDIENTES:*\n`;
    recipe.ingredients?.forEach(ing => text += `• ${ing}\n`);
    text += `\n*👨‍🍳 MODO DE PREPARO:*\n`;
    recipe.instructions?.forEach((step, i) => text += `*${i + 1}.* ${step}\n`);
    text += `\n*📊 MACROS:*\n`;
    text += `🔥 Cal: ${recipe.macros.calories} | 💪 Prot: ${recipe.macros.protein}\n`;
    text += `🍞 Carb: ${recipe.macros.carbs} | 🥑 Gord: ${recipe.macros.fats}\n\n`;
    text += `_Gerado por Receita Fit Gen_`;
    return text;
  };

  const handleShare = async () => {
    setIsSharing(true);
    const text = getFullRecipeText();

    try {
      // Prepara o arquivo de imagem para compartilhamento
      let files: File[] = [];
      if (recipe.imageUrl && navigator.share && navigator.canShare) {
        try {
          const response = await fetch(recipe.imageUrl);
          const blob = await response.blob();
          const file = new File([blob], 'receita.png', { type: 'image/png' });
          if (navigator.canShare({ files: [file] })) {
            files = [file];
          }
        } catch (e) {
          console.error("Erro ao preparar imagem para share:", e);
        }
      }

      if (navigator.share) {
        await navigator.share({
          title: recipe.title,
          text: text,
          files: files.length > 0 ? files : undefined
        });
      } else {
        // Fallback WhatsApp Web/App
        const encodedText = encodeURIComponent(text);
        window.open(`https://wa.me/?text=${encodedText}`, '_blank');
      }
    } catch (err) {
      console.error("Erro ao compartilhar:", err);
    } finally {
      setIsSharing(false);
    }
  };

  return (
    <div className="h-full flex flex-col bg-white overflow-y-auto pb-48 text-slate-800">
      {isImageZoomed && (
        <div className="fixed inset-0 z-[100] bg-black flex items-center justify-center" onClick={() => setIsImageZoomed(false)}>
          <img src={recipe.imageUrl} className="max-w-full max-h-full object-contain" alt="Zoom" />
          <button className="absolute top-6 right-6 text-white text-4xl">×</button>
        </div>
      )}

      <div className="relative h-80 flex-shrink-0">
        <img 
          src={recipe.imageUrl} 
          alt={recipe.title} 
          onClick={() => setIsImageZoomed(true)}
          className="w-full h-full object-cover" 
        />
        <div className="absolute inset-0 bg-gradient-to-t from-white via-transparent to-transparent"></div>
      </div>

      <div className="px-6 -mt-10 relative bg-white rounded-t-[2.5rem] pt-8 space-y-6">
        <div className="space-y-2">
          <h1 className="text-4xl font-black text-slate-900 leading-tight">{recipe.title}</h1>
          <div className="flex gap-2 flex-wrap">
            <span className="px-3 py-1 bg-emerald-100 text-emerald-700 rounded-full text-xs font-black uppercase">{recipe.estimatedTime}</span>
            <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-xs font-black uppercase">{recipe.macros.calories}</span>
          </div>
        </div>

        <div className="grid grid-cols-4 gap-2 p-4 bg-slate-900 rounded-3xl text-white text-center">
          <div><p className="text-[10px] opacity-60 uppercase font-bold">Cal</p><p className="font-black">{recipe.macros.calories}</p></div>
          <div><p className="text-[10px] opacity-60 uppercase font-bold">Prot</p><p className="font-black">{recipe.macros.protein}</p></div>
          <div><p className="text-[10px] opacity-60 uppercase font-bold">Carb</p><p className="font-black">{recipe.macros.carbs}</p></div>
          <div><p className="text-[10px] opacity-60 uppercase font-bold">Fat</p><p className="font-black">{recipe.macros.fats}</p></div>
        </div>

        <div className="space-y-6">
          <p className="text-slate-600 leading-relaxed italic">"{recipe.description}"</p>

          <section>
            <h3 className="text-xl font-black mb-3 text-emerald-600 uppercase tracking-wider">Ingredientes</h3>
            <ul className="space-y-2">
              {recipe.ingredients?.map((ing, i) => (
                <li key={i} className="flex gap-3 text-slate-700 font-medium">
                  <span className="text-emerald-500">•</span> {ing}
                </li>
              ))}
            </ul>
          </section>

          <section>
            <h3 className="text-xl font-black mb-4 text-emerald-600 uppercase tracking-wider">Modo de Preparo</h3>
            <div className="space-y-4">
              {recipe.instructions?.map((step, i) => (
                <div key={i} className="flex gap-4">
                  <span className="flex-shrink-0 w-8 h-8 rounded-lg bg-emerald-500 text-white flex items-center justify-center font-black text-sm">
                    {i + 1}
                  </span>
                  <p className="text-slate-700 leading-relaxed">{step}</p>
                </div>
              ))}
            </div>
          </section>
        </div>
      </div>

      <div className="fixed bottom-0 left-0 w-full max-w-xl mx-auto p-5 bg-white/90 backdrop-blur-md border-t border-slate-100 grid grid-cols-2 gap-3 z-30">
        <button 
          onClick={handleShare} 
          disabled={isSharing}
          className="col-span-2 py-4 bg-emerald-500 text-white rounded-2xl font-black uppercase shadow-lg shadow-emerald-200 active:scale-95 disabled:opacity-50"
        >
          {isSharing ? 'Preparando...' : 'Enviar por WhatsApp'}
        </button>
        <button onClick={onBack} className="py-3 bg-slate-100 text-slate-600 rounded-2xl font-black uppercase text-sm">Voltar</button>
        <button onClick={handleAction} className={`py-3 border-2 rounded-2xl font-black uppercase text-sm ${isFavorite ? 'border-red-500 text-red-500' : 'border-emerald-500 text-emerald-500'}`}>
          {isFavorite ? 'Remover' : 'Salvar'}
        </button>
      </div>
    </div>
  );
};

