      <div ref={recipeRef} className="bg-white">
        {/* Hero Image */}
        <div className="relative h-80 flex-shrink-0">
          <img 
            src={recipe.imageUrl} 
            alt={recipe.title} 
            crossOrigin="anonymous"
            onClick={() => setIsImageZoomed(true)}
            className="w-full h-full object-cover" 
          />
          <div className="absolute inset-0 bg-gradient-to-t from-white via-transparent to-transparent"></div>
        </div>

        <div className="px-6 -mt-10 relative bg-white rounded-t-[2.5rem] pt-8 space-y-6">
          <div className="space-y-2">
            <h1 className="text-4xl font-black text-slate-900 leading-tight">{recipe.title}</h1>
            <div className="flex gap-2 flex-wrap">
              <span className="px-3 py-1 bg-emerald-100 text-emerald-700 rounded-full text-xs font-black uppercase border border-emerald-200">{recipe.estimatedTime}</span>
              <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-xs font-black uppercase border border-slate-200">{recipe.macros.calories}</span>
              {recipe.estimatedCost && (
                <span className="px-3 py-1 bg-amber-50 text-amber-700 rounded-full text-xs font-black uppercase border border-amber-200">{recipe.estimatedCost}</span>
              )}
            </div>
          </div>

          <div className="grid grid-cols-4 gap-2 p-4 bg-slate-900 rounded-3xl text-white text-center shadow-lg">
            <div><p className="text-[10px] opacity-60 uppercase font-bold">Cal</p><p className="font-black text-lg">{recipe.macros.calories}</p></div>
            <div><p className="text-[10px] opacity-60 uppercase font-bold">Prot</p><p className="font-black text-lg">{recipe.macros.protein}</p></div>
            <div><p className="text-[10px] opacity-60 uppercase font-bold">Carb</p><p className="font-black text-lg">{recipe.macros.carbs}</p></div>
            <div><p className="text-[10px] opacity-60 uppercase font-bold">Fat</p><p className="font-black text-lg">{recipe.macros.fats}</p></div>
          </div>

          <div className="space-y-8 pb-10">
            <p className="text-slate-600 leading-relaxed italic text-lg">"{recipe.description}"</p>

            <section>
              <h3 className="text-xl font-black mb-3 text-emerald-600 uppercase tracking-wider border-b-2 border-emerald-100 pb-1">Ingredientes</h3>
              <ul className="space-y-2">
                {recipe.ingredients?.map((ing, i) => (
                  <li key={i} className="flex gap-3 text-slate-700 font-medium text-lg">
                    <span className="text-emerald-500 font-bold">•</span> {ing}
                  </li>
                ))}
              </ul>
            </section>

            <section>
              <h3 className="text-xl font-black mb-4 text-emerald-600 uppercase tracking-wider border-b-2 border-emerald-100 pb-1">Modo de Preparo</h3>
              <div className="space-y-5">
                {recipe.instructions?.map((step, i) => (
                  <div key={i} className="flex gap-4">
                    <span className="flex-shrink-0 w-8 h-8 rounded-lg bg-emerald-500 text-white flex items-center justify-center font-black text-sm">
                      {i + 1}
                    </span>
                    <p className="text-slate-700 leading-relaxed text-lg">{step}</p>
                  </div>
                ))}
              </div>
            </section>
          </div>
        </div>
      </div>

      {/* Footer de Ações Fixas */}
      <div className="fixed bottom-0 left-0 w-full max-w-xl mx-auto p-5 bg-white/95 backdrop-blur-md border-t border-slate-100 grid grid-cols-2 gap-3 z-30 shadow-[0_-10px_30px_rgba(0,0,0,0.05)]">
        <button 
          onClick={handleWhatsAppShare} 
          className="col-span-1 py-4 bg-emerald-500 text-white rounded-2xl font-black uppercase text-sm shadow-lg shadow-emerald-100 active:scale-95 transition-transform"
        >
          WhatsApp
        </button>
        <button 
          onClick={handleDownloadPDF} 
          disabled={isGeneratingPDF}
          className="col-span-1 py-4 bg-slate-800 text-white rounded-2xl font-black uppercase text-sm shadow-lg shadow-slate-200 active:scale-95 transition-transform disabled:opacity-50"
        >
          {isGeneratingPDF ? 'Gerando...' : 'Baixar PDF'}
