          onClick={handleToggleFavorite} 
          className={`py-3 border-2 rounded-2xl font-black uppercase text-xs transition-colors ${
            isFavorite ? 'border-red-500 text-red-500 bg-red-50' : 'border-emerald-500 text-emerald-500 bg-white'
          }`}
        >
          {isFavorite ? 'Remover' : 'Salvar'}
        </button>
      </div>
    </div>
  );
