import { GoogleGenAI, Type } from "@google/genai";
import { UserPreferences, RecipeResult } from "../types";

const cleanJsonString = (str: string): string => {
  return str.replace(/```json\n?|```/g, "").trim();
};

export const generateRecipe = async (prefs: UserPreferences): Promise<RecipeResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("Chave de API não configurada.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const systemInstruction = `Você é um nutricionista sênior e chef especializado em culinária saudável e funcional. 
  Sua missão é criar receitas "Fit" que sejam nutritivas, saborosas e fáceis de seguir.
  Você DEVE retornar a resposta estritamente em formato JSON.
  Não inclua nenhuma conversa ou explicação fora do bloco JSON.
  Calcule os valores nutricionais (macros) de forma realista para 1 porção média.`;

  const prompt = `Gere uma receita FIT detalhada com as seguintes preferências:
  - Objetivo Dietético: ${prefs.dietaryFilters.join(', ')}
  - Tipo de Refeição: ${prefs.mealType}
  - Prato Específico: ${prefs.dishType || 'Qualquer prato saudável'}
  - Nível de Calorias: ${prefs.calorieLevel}
  - Sabor: ${prefs.flavor}
  - Nível de Dificuldade: ${prefs.skillLevel}
  - Ingredientes para usar: ${prefs.ingredients || 'Ingredientes naturais e saudáveis'}
  - Ingredientes para EVITAR: ${prefs.dispensableIngredients || 'Nenhum'}
  - Métodos de Preparo Sugeridos: ${prefs.prepMethods.join(', ')}
  - Rendimento: ${prefs.peopleCount} pessoa(s).

  A receita deve incluir:
  - Título atraente.
  - Breve descrição ressaltando os benefícios.
  - Lista de ingredientes com medidas precisas.
  - Passo a passo numerado e claro.
  - Estimativa de custo (ex: "Baixo", "Médio", "Alto").
  - Tempo de preparo total.
  - Macronutrientes por porção (Calorias, Proteínas, Carboidratos, Gorduras).`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
            instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
            estimatedCost: { type: Type.STRING },
            estimatedTime: { type: Type.STRING },
            macros: {
              type: Type.OBJECT,
              properties: {
                protein: { type: Type.STRING },
                carbs: { type: Type.STRING },
                fats: { type: Type.STRING },
                calories: { type: Type.STRING },
              },
              required: ["protein", "carbs", "fats", "calories"]
            }
          },
          required: ["title", "description", "ingredients", "instructions", "macros", "estimatedTime"]
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("A IA não retornou conteúdo.");

    const recipeData = JSON.parse(cleanJsonString(text)) as RecipeResult;

    // Geração de imagem via Gemini 2.5 Flash Image
    try {
      const imagePrompt = `Foto gastronômica profissional em close-up de: ${recipeData.title}. Estilo clean, luz do dia, prato decorado de forma saudável, fundo desfocado, 4k.`;
      const imgResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: imagePrompt,
        config: {
          imageConfig: { aspectRatio: "1:1" }
        }
      });

      const parts = imgResponse.candidates?.[0]?.content?.parts;
      if (parts) {
        for (const part of parts) {
          if (part.inlineData?.data) {
            recipeData.imageUrl = `data:image/png;base64,${part.inlineData.data}`;
            break;
          }
        }
      }
    } catch (e) {
      console.warn("Falha ao gerar imagem personalizada:", e);
    }

    if (!recipeData.imageUrl) {
      recipeData.imageUrl = `https://images.unsplash.com/photo-1490645935967-10de6ba17061?auto=format&fit=crop&q=80&w=800`;
    }

    return recipeData;
  } catch (error) {
    console.error("Erro na geração da receita:", error);
    throw error;
  }
};

