  skillLevel: SkillLevel;
}

interface RecipeResult {
  title: string;
  description: string;
  ingredients: string[];
  instructions: string[];
  estimatedCost: string;
  estimatedTime: string;
  imageUrl?: string;
  macros: {
    protein: string;
    carbs: string;
    fats: string;
    calories: string;
  };
}

// --- 2. SERVIÇOS (GEMINI API) ---

const generateRecipeData = async (prefs: UserPreferences): Promise<RecipeResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const systemInstruction = `Você é um nutricionista sênior e chef especializado em culinária saudável. 
  Crie receitas FIT nutritivas e saborosas. Retorne APENAS o JSON conforme o schema solicitado.`;

  const prompt = `Gere uma receita FIT para ${prefs.peopleCount} pessoa(s).
  Tipo: ${prefs.mealType} (${prefs.dishType || 'Qualquer'}). 
  Filtros: ${prefs.dietaryFilters.join(', ')}. Calorias: ${prefs.calorieLevel}. 
  Sabor: ${prefs.flavor}. Habilidade: ${prefs.skillLevel}.
  Usar: ${prefs.ingredients || 'Ingredientes saudáveis'}. Evitar: ${prefs.dispensableIngredients || 'Nada'}.
  Métodos: ${prefs.prepMethods.join(', ')}.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
          instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
          estimatedCost: { type: Type.STRING },
          estimatedTime: { type: Type.STRING },
          macros: {
            type: Type.OBJECT,
            properties: {
              protein: { type: Type.STRING },
              carbs: { type: Type.STRING },
              fats: { type: Type.STRING },
              calories: { type: Type.STRING },
            },
            required: ["protein", "carbs", "fats", "calories"]
          }
        },
        required: ["title", "description", "ingredients", "instructions", "macros", "estimatedTime"]
      },
    },
  });

  const recipeData = JSON.parse(response.text) as RecipeResult;

  // Geração de Imagem
  try {
    const imgResp = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: `Close-up profissional de prato: ${recipeData.title}, fundo clean, iluminação natural, 4k.`,
      config: { imageConfig: { aspectRatio: "1:1" } }
    });
    const part = imgResp.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (part?.inlineData) recipeData.imageUrl = `data:image/png;base64,${part.inlineData.data}`;
  } catch (e) {
    recipeData.imageUrl = "https://images.unsplash.com/photo-1490645935967-10de6ba17061?auto=format&fit=crop&q=80&w=800";
  }

  return recipeData;
};

