          <div className="text-xs font-bold text-slate-400 uppercase">{Math.round((step/5)*100)}%</div>
        </div>
        <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
          <div className="h-full bg-emerald-500 transition-all" style={{ width: `${(step/5)*100}%` }}></div>
