            <h3 className="text-3xl font-black text-slate-900">O que vamos comer?</h3>
            <select className="w-full p-5 bg-slate-50 rounded-2xl border-4 border-slate-100 font-bold outline-none" value={data.mealType} onChange={e => setData({...data, mealType: e.target.value as MealType})}>
