            <div className="flex items-center gap-4 bg-slate-50 p-4 rounded-2xl border-4 border-slate-100">
              <button onClick={() => setData(p => ({...p, peopleCount: Math.max(1, p.peopleCount-1)}))} className="w-12 h-12 bg-white rounded-xl shadow-sm font-black">-</button>
              <span className="flex-1 text-center font-black text-2xl">{data.peopleCount} Pessoa(s)</span>
              <button onClick={() => setData(p => ({...p, peopleCount: p.peopleCount+1}))} className="w-12 h-12 bg-white rounded-xl shadow-sm font-black">+</button>
