            <textarea placeholder="O que VOCÊ TEM em casa?" className="w-full p-5 bg-slate-50 rounded-2xl border-4 border-slate-100 font-bold outline-none h-32" value={data.ingredients} onChange={e => setData({...data, ingredients: e.target.value})} />
            <textarea placeholder="O que EVITAR?" className="w-full p-5 bg-slate-50 rounded-2xl border-4 border-slate-100 font-bold outline-none h-32" value={data.dispensableIngredients} onChange={e => setData({...data, dispensableIngredients: e.target.value})} />
