  const shareWA = () => {
    const text = encodeURIComponent(`*🥗 RECEITA FIT: ${recipe.title}*\n\n${recipe.description}\n\n*🛒 INGREDIENTES:*\n${recipe.ingredients.join('\n')}\n\n*🔥 CALORIAS:* ${recipe.macros.calories}`);
    window.open(`https://wa.me/?text=${text}`, '_blank');
  };

  return (
    <div className="h-screen bg-white overflow-y-auto pb-32 relative">
      <div className="relative h-72">
        <img src={recipe.imageUrl} className="w-full h-full object-cover" alt={recipe.title} />
        <div className="absolute inset-0 bg-gradient-to-t from-white"></div>
        <button onClick={toggleFav} className={`absolute top-6 right-6 w-14 h-14 rounded-full flex items-center justify-center shadow-xl ${isFav ? 'bg-red-500 text-white' : 'bg-white text-slate-400'}`}>
          <svg className="w-6 h-6" fill={isFav ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24"><path d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
        </button>
      </div>

      <div className="px-6 -mt-8 relative space-y-6">
        <h1 className="text-3xl font-black text-slate-900 leading-tight">{recipe.title}</h1>
        <div className="flex gap-2">
          <span className="px-3 py-1 bg-emerald-100 text-emerald-700 rounded-full text-[10px] font-black uppercase">{recipe.estimatedTime}</span>
          <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-[10px] font-black uppercase">{recipe.macros.calories}</span>
        </div>

        <div className="grid grid-cols-4 gap-2 p-4 bg-slate-900 rounded-2xl text-white text-center">
          <div><p className="text-[8px] opacity-60 uppercase font-bold">Prot</p><p className="font-black text-sm">{recipe.macros.protein}</p></div>
          <div><p className="text-[8px] opacity-60 uppercase font-bold">Carb</p><p className="font-black text-sm">{recipe.macros.carbs}</p></div>
          <div><p className="text-[8px] opacity-60 uppercase font-bold">Fat</p><p className="font-black text-sm">{recipe.macros.fats}</p></div>
          <div><p className="text-[8px] opacity-60 uppercase font-bold">Cal</p><p className="font-black text-sm">{recipe.macros.calories}</p></div>
        </div>

        <p className="text-slate-500 italic font-medium">"{recipe.description}"</p>

        <section>
          <h3 className="font-black text-emerald-600 uppercase mb-3 border-b-2 border-emerald-50 pb-1">Ingredientes</h3>
          <ul className="space-y-2">{recipe.ingredients.map((ing, i) => <li key={i} className="text-slate-700">• {ing}</li>)}</ul>
        </section>

        <section>
          <h3 className="font-black text-emerald-600 uppercase mb-3 border-b-2 border-emerald-50 pb-1">Preparo</h3>
          <div className="space-y-4">{recipe.instructions.map((step, i) => <div key={i} className="flex gap-3"><span className="w-6 h-6 bg-emerald-500 text-white rounded flex items-center justify-center font-bold text-xs">{i+1}</span><p className="text-slate-700 flex-1">{step}</p></div>)}</div>
        </section>
      </div>

      <div className="fixed bottom-0 left-0 w-full p-6 bg-white/95 backdrop-blur-md border-t border-slate-50 grid grid-cols-2 gap-4">
        <button onClick={onBack} className="py-5 bg-slate-100 text-slate-500 font-black rounded-2xl active:scale-95 transition-all">INÍCIO</button>
        <button onClick={shareWA} className="py-5 bg-emerald-500 text-white font-black rounded-2xl shadow-lg active:scale-95 transition-all">WHATSAPP</button>
