const App: React.FC = () => {
  const [view, setView] = useState<'splash' | 'form' | 'loading' | 'result' | 'favs' | 'hist'>('splash');
  const [result, setResult] = useState<RecipeResult | null>(null);
  const [history, setHistory] = useState<RecipeResult[]>([]);
  const [favorites, setFavorites] = useState<RecipeResult[]>([]);

  useEffect(() => {
    setHistory(JSON.parse(localStorage.getItem('fit_gen_hist') || '[]'));
    setFavorites(JSON.parse(localStorage.getItem('fit_gen_favs') || '[]'));
  }, []);

  const handleGenerate = async (prefs: UserPreferences) => {
    setView('loading');
    try {
      const data = await generateRecipeData(prefs);
      const newHist = [data, ...history].slice(0, 50);
      localStorage.setItem('fit_gen_hist', JSON.stringify(newHist));
      setHistory(newHist);
      setResult(data);
      setView('result');
    } catch (e) {
      alert("Falha na IA. Verifique sua conexão e tente novamente.");
      setView('form');
    }
  };

  const selectRecipe = (r: RecipeResult) => {
    setResult(r);
    setView('result');
  };

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-slate-50 relative overflow-hidden shadow-2xl">
      {view === 'splash' && <SplashScreen onStart={() => setView('form')} onOpenFavs={() => setView('favs')} onOpenHist={() => setView('hist')} />}
      {view === 'form' && <StepForm onBack={() => setView('splash')} onSubmit={handleGenerate} />}
      {view === 'loading' && (
        <div className="h-screen flex flex-col items-center justify-center bg-white p-8 text-center space-y-6">
          <div className="w-20 h-20 border-8 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
          <h2 className="text-3xl font-black text-slate-900 uppercase">Criando sua Receita...</h2>
          <p className="text-slate-400 italic">"Balanceando os macronutrientes..."</p>
        </div>
      )}
      {view === 'result' && result && <ResultScreen recipe={result} onBack={() => setView('splash')} />}
      {(view === 'favs' || view === 'hist') && (
        <div className="h-screen bg-slate-50 flex flex-col p-6">
          <h2 className="text-3xl font-black mb-6 text-slate-900 uppercase">{view === 'favs' ? 'Salvas' : 'Histórico'}</h2>
          <div className="flex-1 overflow-y-auto space-y-3 pb-24">
            {(view === 'favs' ? favorites : history).map((r, i) => (
              <div key={i} onClick={() => selectRecipe(r)} className="bg-white p-4 rounded-2xl flex gap-4 cursor-pointer active:scale-95 transition-all shadow-sm">
                <img src={r.imageUrl} className="w-16 h-16 object-cover rounded-xl" />
                <div className="flex-1 truncate">
                  <h4 className="font-black truncate text-slate-800 uppercase text-sm">{r.title}</h4>
                  <p className="text-[10px] text-slate-400 font-bold uppercase">{r.macros.calories} | {r.estimatedTime}</p>
                </div>
              </div>
            ))}
            {(view === 'favs' ? favorites : history).length === 0 && <p className="text-center py-20 text-slate-300 font-bold italic">Nada por aqui ainda.</p>}
          </div>
          <div className="fixed bottom-0 left-0 w-full p-6 bg-white border-t border-slate-100">
            <button onClick={() => setView('splash')} className="w-full py-5 bg-emerald-500 text-white font-black rounded-2xl active:scale-95">VOLTAR AO INÍCIO</button>
          </div>
        </div>
      )}
    </div>
  );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

