import { GoogleGenAI, Type } from "@google/genai";
import { UserPreferences, RecipeResult } from "../types";

export const generateRecipe = async (prefs: UserPreferences): Promise<RecipeResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("Chave de API não configurada no ambiente.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const systemInstruction = `Você é um nutricionista sênior e chef de cozinha especializado em culinária saudável e funcional. 
  Sua missão é criar receitas "Fit" que sejam altamente nutritivas, saborosas e fáceis de seguir.
  Calcule os macronutrientes (macros) de forma realista por porção.
  Você deve retornar apenas o JSON conforme o esquema solicitado, sem texto adicional.`;

  const prompt = `Gere uma receita FIT detalhada para ${prefs.peopleCount} pessoa(s) com as seguintes preferências:
  - Momento: ${prefs.mealType}
  - Prato sugerido: ${prefs.dishType || 'Qualquer prato saudável'}
  - Restrições: ${prefs.dietaryFilters.join(', ')}
  - Calorias desejadas: ${prefs.calorieLevel}
  - Gosto: ${prefs.flavor}
  - Habilidade do cozinheiro: ${prefs.skillLevel}
  - Ingredientes disponíveis: ${prefs.ingredients || 'Ingredientes naturais e saudáveis'}
  - Ingredientes proibidos: ${prefs.dispensableIngredients || 'Nenhum'}
  - Métodos preferidos: ${prefs.prepMethods.join(', ')}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
            instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
            estimatedCost: { type: Type.STRING },
            estimatedTime: { type: Type.STRING },
            macros: {
              type: Type.OBJECT,
              properties: {
                protein: { type: Type.STRING },
                carbs: { type: Type.STRING },
                fats: { type: Type.STRING },
                calories: { type: Type.STRING },
              },
              required: ["protein", "carbs", "fats", "calories"]
            }
          },
          required: ["title", "description", "ingredients", "instructions", "macros", "estimatedTime"]
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("Resposta da IA vazia.");

    const recipeData = JSON.parse(text) as RecipeResult;

    // Geração de imagem com Gemini 2.5 Flash Image
    try {
      const imagePrompt = `Foto gastronômica profissional e apetitosa de: ${recipeData.title}. Estilo clean, iluminação natural, prato decorado, fundo desfocado, alta resolução.`;
      const imgResponse = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: imagePrompt,
        config: {
          imageConfig: { aspectRatio: "1:1" }
        }
      });

      const part = imgResponse.candidates?.[0]?.content?.parts.find(p => p.inlineData);
      if (part?.inlineData) {
        recipeData.imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      }
    } catch (e) {
      console.warn("Falha ao gerar imagem personalizada, usando fallback.", e);
      recipeData.imageUrl = `https://images.unsplash.com/photo-1490645935967-10de6ba17061?auto=format&fit=crop&q=80&w=800`;
    }

    return recipeData;
  } catch (error) {
    console.error("Erro na geração da receita:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  SkillLevel,
  UserPreferences 
} from '../types';

interface StepFormProps {
  initialData: UserPreferences;
  onSubmit: (data: UserPreferences) => void;
  error: string | null;
}

const StepForm: React.FC<StepFormProps> = ({ initialData, onSubmit, error }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<UserPreferences>(initialData);
  const totalSteps = 5;

  const handleNext = () => {
    if (step < totalSteps) setStep(step + 1);
    else onSubmit(formData);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const toggleDietary = (val: DietaryFilter) => {
    setFormData(prev => {
      if (val === DietaryFilter.SEM_RESTRICAO) return { ...prev, dietaryFilters: [val] };
      const filters = prev.dietaryFilters.filter(f => f !== DietaryFilter.SEM_RESTRICAO);
      return {
        ...prev,
        dietaryFilters: filters.includes(val) ? filters.filter(f => f !== val) : [...filters, val]
      };
    });
  };

  return (
    <div className="p-6 h-screen flex flex-col bg-white">
      <div className="mb-8">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-2xl font-black text-slate-900 uppercase">Passo {step}<span className="text-emerald-500">/{totalSteps}</span></h2>
          <span className="text-xs font-black text-emerald-500 bg-emerald-50 px-3 py-1 rounded-full">{Math.round((step/totalSteps)*100)}%</span>
        </div>
        <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
          <div className="h-full bg-emerald-500 transition-all duration-500" style={{ width: `${(step/totalSteps)*100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto pb-32">
        {error && <div className="p-4 bg-red-50 text-red-600 rounded-2xl mb-6 font-bold text-sm border-2 border-red-100">⚠️ {error}</div>}

        {step === 1 && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-4xl font-black text-slate-900 leading-tight">Perfil Alimentar</h3>
            <div className="grid grid-cols-2 gap-3">
              {Object.values(DietaryFilter).map(f => (
                <button 
                  key={f} 
                  onClick={() => toggleDietary(f)}
                  className={`p-5 rounded-[1.5rem] border-4 font-black text-sm uppercase transition-all ${
                    formData.dietaryFilters.includes(f) ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-50 bg-white text-slate-300'
                  }`}
                >
                  {f}
                </button>
              ))}
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-4xl font-black text-slate-900 leading-tight">Refeição</h3>
            <select 
              value={formData.mealType}
              onChange={e => setFormData({...formData, mealType: e.target.value as MealType})}
              className="w-full p-6 bg-slate-50 rounded-[1.5rem] border-4 border-slate-50 font-black text-xl outline-none"
            >
              {Object.values(MealType).map(m => <option key={m}>{m}</option>)}
            </select>
            <input 
              placeholder="Ex: Panqueca de Aveia, Bowl..."
              value={formData.dishType}
              onChange={e => setFormData({...formData, dishType: e.target.value})}
              className="w-full p-6 bg-slate-50 rounded-[1.5rem] border-4 border-slate-50 font-black text-xl outline-none"
            />
          </div>
