        {step === 3 && (
          <div className="space-y-8 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-4xl font-black text-slate-900 leading-tight">Porções & Foco</h3>
            <div className="flex items-center gap-6 p-6 bg-slate-50 rounded-[1.5rem]">
              <button onClick={() => setFormData(p => ({...p, peopleCount: Math.max(1, p.peopleCount-1)}))} className="w-16 h-16 bg-white rounded-2xl shadow-md font-black text-2xl">-</button>
              <span className="flex-1 text-center font-black text-4xl text-emerald-500">{formData.peopleCount}</span>
