        {step === 5 && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-4xl font-black text-slate-900 leading-tight">Toque Final</h3>
            <div className="grid grid-cols-2 gap-4">
              {Object.values(Flavor).map(f => (
                <button 
                  key={f} 
                  onClick={() => setFormData({...formData, flavor: f})}
                  className={`p-6 rounded-[1.5rem] border-4 font-black transition-all ${
                    formData.flavor === f ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-50 bg-white text-slate-300'
