      <div className="fixed bottom-0 left-0 w-full p-6 bg-white border-t border-slate-50 flex gap-4 z-20">
        <button onClick={handleBack} className="flex-1 py-5 border-4 border-emerald-500 text-emerald-500 rounded-[1.5rem] font-black uppercase active:scale-95 transition-all">Voltar</button>
        <button onClick={handleNext} className="flex-[2] py-5 bg-emerald-500 text-white rounded-[1.5rem] font-black text-xl shadow-xl active:scale-95 transition-all uppercase">
          {step === totalSteps ? 'Gerar Receita' : 'Próximo'}
        </button>
      </div>
    </div>
  );
};

