import React, { useState, useEffect } from 'react';
import { RecipeResult } from '../types';

interface ResultScreenProps {
  recipe: RecipeResult;
  onBack: () => void;
}

const ResultScreen: React.FC<ResultScreenProps> = ({ recipe, onBack }) => {
  const [isFav, setIsFav] = useState(false);

  useEffect(() => {
    const favs = JSON.parse(localStorage.getItem('fit_gen_favs') || '[]');
    setIsFav(favs.some((f: RecipeResult) => f.title === recipe.title));
  }, [recipe.title]);

  const toggleFav = () => {
    const favs = JSON.parse(localStorage.getItem('fit_gen_favs') || '[]');
    const newFavs = isFav ? favs.filter((f: RecipeResult) => f.title !== recipe.title) : [...favs, recipe];
    localStorage.setItem('fit_gen_favs', JSON.stringify(newFavs));
    setIsFav(!isFav);
  };

  const shareWA = () => {
    const text = `*🥗 RECEITA FIT: ${recipe.title.toUpperCase()}*\n\n${recipe.description}\n\n*🔥 Macros:* Cal: ${recipe.macros.calories} | Prot: ${recipe.macros.protein}\n\n*🛒 Ingredientes:*\n${recipe.ingredients.join('\n')}\n\n*👨‍🍳 Preparo:*\n${recipe.instructions.join('\n')}`;
    window.open(`https://wa.me/?text=${encodeURIComponent(text)}`, '_blank');
  };

  return (
    <div className="h-screen bg-white overflow-y-auto pb-32">
      <div className="relative h-80">
        <img src={recipe.imageUrl} className="w-full h-full object-cover" alt={recipe.title} />
        <div className="absolute inset-0 bg-gradient-to-t from-white via-transparent"></div>
        <button 
          onClick={toggleFav}
          className={`absolute top-6 right-6 w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all ${
            isFav ? 'bg-red-500 text-white' : 'bg-white text-slate-300'
          }`}
        >
          <svg className="w-7 h-7" fill={isFav ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
          </svg>
        </button>
      </div>

      <div className="px-6 -mt-10 relative space-y-8">
        <div className="space-y-2">
          <h1 className="text-4xl font-black text-slate-900 leading-tight">{recipe.title}</h1>
          <div className="flex gap-2">
            <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-black uppercase">{recipe.estimatedTime}</span>
            <span className="px-3 py-1 bg-slate-50 text-slate-500 rounded-full text-[10px] font-black uppercase">{recipe.macros.calories}</span>
          </div>
        </div>

        <div className="grid grid-cols-4 gap-2 p-4 bg-slate-900 rounded-[2rem] text-white text-center shadow-xl">
          <div><p className="text-[8px] opacity-40 uppercase font-black">Prot</p><p className="font-black text-lg">{recipe.macros.protein}</p></div>
          <div><p className="text-[8px] opacity-40 uppercase font-black">Carb</p><p className="font-black text-lg">{recipe.macros.carbs}</p></div>
          <div><p className="text-[8px] opacity-40 uppercase font-black">Fat</p><p className="font-black text-lg">{recipe.macros.fats}</p></div>
          <div><p className="text-[8px] opacity-40 uppercase font-black">Cal</p><p className="font-black text-lg">{recipe.macros.calories}</p></div>
        </div>

        <p className="text-slate-500 italic font-medium text-lg leading-relaxed">"{recipe.description}"</p>

        <section>
          <h3 className="text-xl font-black text-emerald-600 uppercase mb-4 border-b-4 border-emerald-50 pb-1">Ingredientes</h3>
          <ul className="space-y-3">
            {recipe.ingredients.map((ing, i) => <li key={i} className="text-slate-700 font-medium flex gap-3"><span className="text-emerald-500">•</span> {ing}</li>)}
          </ul>
        </section>

        <section>
          <h3 className="text-xl font-black text-emerald-600 uppercase mb-5 border-b-4 border-emerald-50 pb-1">Preparo</h3>
          <div className="space-y-6">
            {recipe.instructions.map((step, i) => (
              <div key={i} className="flex gap-4">
                <span className="w-8 h-8 flex-shrink-0 bg-emerald-500 text-white rounded-lg flex items-center justify-center font-black text-sm">{i+1}</span>
                <p className="text-slate-700 leading-relaxed font-medium">{step}</p>
              </div>
            ))}
          </div>
        </section>
      </div>

      <div className="fixed bottom-0 left-0 w-full p-6 bg-white/90 backdrop-blur-md border-t border-slate-50 grid grid-cols-2 gap-4 z-20">
        <button onClick={onBack} className="py-5 bg-slate-50 text-slate-400 font-black rounded-[1.5rem] uppercase active:scale-95 transition-all">Início</button>
        <button onClick={shareWA} className="py-5 bg-emerald-500 text-white font-black rounded-[1.5rem] shadow-xl active:scale-95 transition-all uppercase">WhatsApp</button>
      </div>
    </div>
  );
};

