import React, { useState, useEffect } from 'react';
import { 
  MealType, 
  CalorieLevel, 
  Flavor, 
  SkillLevel,
  ResultOption, 
  UserPreferences, 
  RecipeResult 
} from './types';
import { generateRecipe } from './services/geminiService';
import SplashScreen from './components/SplashScreen';
import StepForm from './components/StepForm';
import ResultScreen from './components/ResultScreen';
import FavoritesList from './components/FavoritesList';
import HistoryList from './components/HistoryList';

const App: React.FC = () => {
  const [view, setView] = useState<'splash' | 'form' | 'loading' | 'result' | 'favs' | 'hist'>('splash');
  const [prefs, setPrefs] = useState<UserPreferences>({
    dietaryFilters: [],
    mealType: MealType.ALMOCO,
    dishType: '',
    peopleCount: 1,
    calorieLevel: CalorieLevel.MEDIO,
    flavor: Flavor.SALGADO,
    ingredients: '',
    dispensableIngredients: '',
    prepMethods: [],
    skillLevel: SkillLevel.BASICA,
    resultOptions: [ResultOption.TODOS]
  });
  const [result, setResult] = useState<RecipeResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGenerate = async (data: UserPreferences) => {
    setPrefs(data);
    setView('loading');
    setError(null);
    try {
      const recipe = await generateRecipe(data);
      setResult(recipe);

      // Salvar no histórico
      const history = JSON.parse(localStorage.getItem('fit_gen_hist') || '[]');
      const newHistory = [recipe, ...history].slice(0, 50);
      localStorage.setItem('fit_gen_hist', JSON.stringify(newHistory));

      setView('result');
    } catch (e: any) {
      setError(e.message || "Erro inesperado. Tente novamente.");
      setView('form');
    }
  };

  const handleSelect = (r: RecipeResult) => {
    setResult(r);
    setView('result');
  };

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-slate-50 relative overflow-hidden shadow-2xl">
      {view === 'splash' && (
        <SplashScreen 
          onStart={() => setView('form')} 
          onOpenFavorites={() => setView('favs')} 
          onOpenHistory={() => setView('hist')} 
        />
      )}

      {view === 'form' && (
        <StepForm 
          initialData={prefs} 
          onSubmit={handleGenerate} 
          error={error} 
        />
      )}

      {view === 'loading' && (
        <div className="h-screen flex flex-col items-center justify-center bg-white p-8 space-y-8 animate-in fade-in duration-500">
          <div className="w-24 h-24 border-[12px] border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
          <div className="text-center space-y-2">
            <h2 className="text-3xl font-black text-slate-900 uppercase">Gerando sua <span className="text-emerald-500">Refeição</span></h2>
            <p className="text-slate-400 font-medium italic">"A IA está selecionando os melhores ingredientes..."</p>
          </div>
        </div>
      )}

      {view === 'result' && result && (
        <ResultScreen recipe={result} onBack={() => setView('splash')} />
      )}

      {view === 'favs' && (
        <FavoritesList onSelect={handleSelect} onBack={() => setView('splash')} />
      )}

      {view === 'hist' && (
        <HistoryList onSelect={handleSelect} onBack={() => setView('splash')} />
      )}
    </div>
  );
};

export default App;

