import React, { useState } from 'react';
import { 
  DietaryFilter, 
  MealType, 
  CalorieLevel, 
  Flavor, 
  PrepMethod, 
  SkillLevel,
  UserPreferences 
} from '../types';

interface StepFormProps {
  initialData: UserPreferences;
  onSubmit: (data: UserPreferences) => void;
  error: string | null;
}

const StepForm: React.FC<StepFormProps> = ({ initialData, onSubmit, error }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<UserPreferences>(initialData);
  const totalSteps = 5;

  const handleNext = () => {
    if (step < totalSteps) setStep(step + 1);
    else onSubmit(formData);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const toggleDietary = (val: DietaryFilter) => {
    setFormData(prev => {
      if (val === DietaryFilter.SEM_RESTRICAO) return { ...prev, dietaryFilters: [val] };
      const filters = prev.dietaryFilters.filter(f => f !== DietaryFilter.SEM_RESTRICAO);
      return {
        ...prev,
        dietaryFilters: filters.includes(val) ? filters.filter(f => f !== val) : [...filters, val]
      };
    });
  };

  return (
    <div className="p-6 h-screen flex flex-col bg-white">
      <div className="mb-8">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-2xl font-black text-slate-900 uppercase">Passo {step}<span className="text-emerald-500">/{totalSteps}</span></h2>
          <span className="text-xs font-black text-emerald-500 bg-emerald-50 px-3 py-1 rounded-full">{Math.round((step/totalSteps)*100)}%</span>
        </div>
        <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
          <div className="h-full bg-emerald-500 transition-all duration-500" style={{ width: `${(step/totalSteps)*100}%` }}></div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto pb-32">
        {error && <div className="p-4 bg-red-50 text-red-600 rounded-2xl mb-6 font-bold text-sm border-2 border-red-100">⚠️ {error}</div>}

        {step === 1 && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-4xl font-black text-slate-900 leading-tight">Perfil Alimentar</h3>
            <div className="grid grid-cols-2 gap-3">
              {Object.values(DietaryFilter).map(f => (
                <button 
                  key={f} 
                  onClick={() => toggleDietary(f)}
                  className={`p-5 rounded-[1.5rem] border-2 font-black text-sm uppercase transition-all ${
                    formData.dietaryFilters.includes(f) ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-200 bg-white text-slate-600 hover:border-emerald-200'
                  }`}
                >
                  {f}
                </button>
              ))}
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-4xl font-black text-slate-900 leading-tight">Refeição</h3>
            <select 
              value={formData.mealType}
              onChange={e => setFormData({...formData, mealType: e.target.value as MealType})}
              className="w-full p-6 bg-slate-50 rounded-[1.5rem] border-2 border-slate-200 font-black text-xl outline-none text-slate-800"
            >
              {Object.values(MealType).map(m => <option key={m}>{m}</option>)}
            </select>
            <input 
              placeholder="Ex: Panqueca de Aveia, Bowl..."
              value={formData.dishType}
              onChange={e => setFormData({...formData, dishType: e.target.value})}
              className="w-full p-6 bg-slate-50 rounded-[1.5rem] border-2 border-slate-200 font-black text-xl outline-none text-slate-800 placeholder-slate-400"
            />
          </div>
        )}

        {step === 3 && (
          <div className="space-y-8 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-4xl font-black text-slate-900 leading-tight">Porções & Foco</h3>
            <div className="flex items-center gap-6 p-6 bg-slate-50 rounded-[1.5rem] border-2 border-slate-100">
              <button onClick={() => setFormData(p => ({...p, peopleCount: Math.max(1, p.peopleCount-1)}))} className="w-16 h-16 bg-white rounded-2xl shadow-md font-black text-2xl text-slate-700 active:bg-slate-50">-</button>
              <span className="flex-1 text-center font-black text-4xl text-emerald-600">{formData.peopleCount}</span>
              <button onClick={() => setFormData(p => ({...p, peopleCount: p.peopleCount+1}))} className="w-16 h-16 bg-white rounded-2xl shadow-md font-black text-2xl text-slate-700 active:bg-slate-50">+</button>
            </div>
            <div className="space-y-3">
              {Object.values(CalorieLevel).map(c => (
                <button 
                  key={c} 
                  onClick={() => setFormData({...formData, calorieLevel: c})}
                  className={`w-full p-5 rounded-[1.5rem] border-2 font-black text-sm uppercase text-left transition-all ${
                    formData.calorieLevel === c ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-200 bg-white text-slate-600 hover:border-emerald-200'
                  }`}
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
        )}

        {step === 4 && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-4xl font-black text-slate-900 leading-tight">Ingredientes</h3>
            <textarea 
              rows={4}
