import { GoogleGenAI, Type } from "@google/genai";
import { UserPreferences, RecipeResult } from "../types";

export const generateRecipe = async (prefs: UserPreferences): Promise<RecipeResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const systemInstruction = `Você é um nutricionista sênior e chef celebridade especializado em gastronomia funcional. 
  Crie receitas FIT que sejam nutritivas e visualmente atraentes. 
  Retorne APENAS o JSON conforme o esquema solicitado.`;

  const prompt = `Gere uma receita FIT para ${prefs.peopleCount} pessoa(s).
  Refeição: ${prefs.mealType} ${prefs.dishType ? `(Estilo: ${prefs.dishType})` : ''}
  Restrições: ${prefs.dietaryFilters.join(', ')}
  Calorias: ${prefs.calorieLevel}
  Sabor dominante: ${prefs.flavor}
  Dificuldade: ${prefs.skillLevel}
  Usar preferencialmente: ${prefs.ingredients || 'Ingredientes frescos'}
  Evitar: ${prefs.dispensableIngredients || 'Nada específico'}`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
          instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
          estimatedCost: { type: Type.STRING },
          estimatedTime: { type: Type.STRING },
          macros: {
            type: Type.OBJECT,
            properties: {
              protein: { type: Type.STRING },
              carbs: { type: Type.STRING },
              fats: { type: Type.STRING },
              calories: { type: Type.STRING },
            },
            required: ["protein", "carbs", "fats", "calories"]
          }
        },
        required: ["title", "description", "ingredients", "instructions", "macros", "estimatedTime"]
      },
    },
  });

  const recipeData = JSON.parse(response.text) as RecipeResult;

  // Gerar imagem do prato
  try {
    const imgResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: `Fotografia profissional de culinária: ${recipeData.title}, iluminação de estúdio, prato gourmet, fundo neutro, 4k.`,
      config: { imageConfig: { aspectRatio: "1:1" } }
    });
    const part = imgResponse.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (part?.inlineData) {
      recipeData.imageUrl = `data:image/png;base64,${part.inlineData.data}`;
    }
  } catch (e) {
    recipeData.imageUrl = "https://images.unsplash.com/photo-1490645935967-10de6ba17061?auto=format&fit=crop&q=80&w=800";
  }

  return recipeData;
};

import React, { useState } from 'react';
import { DietaryFilter, MealType, CalorieLevel, Flavor, SkillLevel, UserPreferences } from '../types';

interface StepFormProps {
  initialData: UserPreferences;
  onSubmit: (data: UserPreferences) => void;
  onCancel: () => void;
}

const StepForm: React.FC<StepFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<UserPreferences>(initialData);
  const totalSteps = 5;

  const handleNext = () => step < totalSteps ? setStep(step + 1) : onSubmit(formData);
  const handleBack = () => step > 1 ? setStep(step - 1) : onCancel();

  const toggleDietary = (f: DietaryFilter) => {
    setFormData(p => ({
      ...p,
      dietaryFilters: p.dietaryFilters.includes(f) ? p.dietaryFilters.filter(x => x !== f) : [...p.dietaryFilters, f]
    }));
  };

  return (
    <div className="flex flex-col h-screen bg-white">
      {/* Header */}
      <div className="p-6 pb-2">
        <div className="flex justify-between items-end mb-4">
          <div>
            <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Etapa {step} de {totalSteps}</p>
            <h2 className="text-2xl font-black text-slate-900">PERSONALIZAR</h2>
          </div>
          <div className="text-emerald-500 font-black text-xl">{Math.round((step/totalSteps)*100)}%</div>
        </div>
        <div className="h-3 w-full bg-slate-100 rounded-full overflow-hidden">
          <div className="h-full bg-emerald-500 transition-all duration-500" style={{ width: `${(step/totalSteps)*100}%` }}></div>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto px-6 py-4 space-y-6 pb-32">
        {step === 1 && (
          <div className="space-y-4 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-3xl font-black text-slate-900">Qual seu perfil?</h3>
            <div className="grid grid-cols-2 gap-3">
              {Object.values(DietaryFilter).map(f => (
                <button 
                  key={f} 
                  onClick={() => toggleDietary(f)}
                  className={`p-5 rounded-[1.5rem] border-2 font-bold text-sm uppercase transition-all ${
                    formData.dietaryFilters.includes(f) ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-300 bg-white text-slate-700 shadow-sm'
                  }`}
                >
                  {f}
                </button>
              ))}
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-4 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-3xl font-black text-slate-900">Momento do dia</h3>
            <div className="space-y-3">
              {Object.values(MealType).map(m => (
                <button 
                  key={m} 
                  onClick={() => setFormData({...formData, mealType: m})}
                  className={`w-full p-5 rounded-[1.5rem] border-2 font-bold text-left transition-all ${
                    formData.mealType === m ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-300 bg-white text-slate-700 shadow-sm'
                  }`}
                >
                  {m}
                </button>
              ))}
            </div>
            <input 
              placeholder="Ex: Panqueca, Poke, Wrap..."
              className="w-full p-5 bg-slate-50 border-2 border-slate-300 rounded-[1.5rem] font-bold text-slate-800 outline-none focus:border-emerald-500 transition-colors"
              value={formData.dishType}
              onChange={e => setFormData({...formData, dishType: e.target.value})}
            />
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-3xl font-black text-slate-900">Porções e Calorias</h3>
            <div className="flex items-center gap-6 p-6 bg-slate-50 rounded-[2rem] border-2 border-slate-200">
