              <div className="flex-1 text-center">
                <p className="text-[10px] font-black text-slate-400 uppercase">Pessoas</p>
                <p className="text-4xl font-black text-emerald-600">{formData.peopleCount}</p>
              </div>
              <button onClick={() => setFormData(p => ({...p, peopleCount: p.peopleCount+1}))} className="w-16 h-16 bg-white border-2 border-slate-300 rounded-2xl shadow-sm text-2xl font-black text-slate-700">+</button>
            </div>
            <div className="grid grid-cols-1 gap-2">
              {Object.values(CalorieLevel).map(c => (
                <button 
