import React, { useState } from 'react';
import { DietaryFilter, MealType, CalorieLevel, Flavor, SkillLevel, UserPreferences, RecipeResult } from './types';
import { generateRecipe } from './services/geminiService';
import SplashScreen from './components/SplashScreen';
import StepForm from './components/StepForm';
import ResultScreen from './components/ResultScreen';
import FavoritesList from './components/FavoritesList';
import HistoryList from './components/HistoryList';

const App: React.FC = () => {
  const [view, setView] = useState<'splash' | 'form' | 'loading' | 'result' | 'favs' | 'hist'>('splash');
  const [prefs, setPrefs] = useState<UserPreferences>({
    dietaryFilters: [],
    mealType: MealType.ALMOCO,
    dishType: '',
    peopleCount: 1,
    calorieLevel: CalorieLevel.MEDIO,
    flavor: Flavor.SALGADO,
    ingredients: '',
    dispensableIngredients: '',
    skillLevel: SkillLevel.BASICA
  });
  const [result, setResult] = useState<RecipeResult | null>(null);

  const handleGenerate = async (data: UserPreferences) => {
    setPrefs(data);
    setView('loading');
    try {
      const recipe = await generateRecipe(data);
      setResult(recipe);

      const history = JSON.parse(localStorage.getItem('fit_gen_hist') || '[]');
      localStorage.setItem('fit_gen_hist', JSON.stringify([recipe, ...history].slice(0, 50)));

      setView('result');
    } catch (e) {
      alert("Ops! Houve um erro na geração. Tente novamente.");
      setView('form');
    }
  };

  return (
    <div className="max-w-xl mx-auto min-h-screen bg-slate-50 relative shadow-2xl overflow-hidden">
      {view === 'splash' && <SplashScreen onStart={() => setView('form')} onOpenFavorites={() => setView('favs')} onOpenHistory={() => setView('hist')} />}

      {view === 'form' && <StepForm initialData={prefs} onCancel={() => setView('splash')} onSubmit={handleGenerate} />}

      {view === 'loading' && (
        <div className="h-screen flex flex-col items-center justify-center bg-white p-10 space-y-12 animate-in fade-in duration-700">
          <div className="relative">
            <div className="w-32 h-32 border-[12px] border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
            <div className="absolute inset-0 flex items-center justify-center font-black text-emerald-500">FIT</div>
          </div>
          <div className="text-center space-y-4">
            <h2 className="text-4xl font-black text-slate-900 uppercase leading-none">Criando sua<br/><span className="text-emerald-500">Refeição</span></h2>
            <p className="text-slate-400 font-bold italic text-lg px-8">"Equilibrando os macros e selecionando ingredientes frescos..."</p>
          </div>
        </div>
      )}

      {view === 'result' && result && <ResultScreen recipe={result} onBack={() => setView('splash')} />}

      {view === 'favs' && <FavoritesList onSelect={(r) => { setResult(r); setView('result'); }} onBack={() => setView('splash')} />}

      {view === 'hist' && <HistoryList onSelect={(r) => { setResult(r); setView('result'); }} onBack={() => setView('splash')} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { DietaryFilter, MealType, CalorieLevel, Flavor, SkillLevel, UserPreferences } from '../types';

interface StepFormProps {
  initialData: UserPreferences;
  onSubmit: (data: UserPreferences) => void;
  onCancel: () => void;
}

const StepForm: React.FC<StepFormProps> = ({ initialData, onSubmit, onCancel }) => {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<UserPreferences>(initialData);
  const totalSteps = 5;

  const handleNext = () => step < totalSteps ? setStep(step + 1) : onSubmit(formData);
  const handleBack = () => step > 1 ? setStep(step - 1) : onCancel();

  const toggleDietary = (f: DietaryFilter) => {
    setFormData(p => ({
      ...p,
      dietaryFilters: p.dietaryFilters.includes(f) ? p.dietaryFilters.filter(x => x !== f) : [...p.dietaryFilters, f]
    }));
  };

  return (
    <div className="flex flex-col h-screen bg-white">
      {/* Header */}
      <div className="p-6 pb-2">
        <div className="flex justify-between items-end mb-4">
