            <input 
              placeholder="Ex: Panqueca, Poke, Wrap..."
              className="w-full p-5 bg-slate-50 border-2 border-slate-300 rounded-[1.5rem] font-bold text-slate-800 outline-none focus:border-emerald-500 transition-colors"
              value={formData.dishType}
              onChange={e => setFormData({...formData, dishType: e.target.value})}
            />
          </div>
        )}

        {step === 3 && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
            <h3 className="text-3xl font-black text-slate-900">Porções e Calorias</h3>
            <div className="flex items-center gap-6 p-6 bg-slate-50 rounded-[2rem] border-2 border-slate-200">
