              <button onClick={() => setFormData(p => ({...p, peopleCount: p.peopleCount+1}))} className="w-16 h-16 bg-white border-2 border-slate-300 rounded-2xl shadow-sm text-2xl font-black text-slate-700">+</button>
            </div>
            <div className="grid grid-cols-1 gap-2">
