import { GoogleGenAI, Type } from "@google/genai";
import { UserPreferences, RecipeResult } from "../types";

export const generateRecipe = async (prefs: UserPreferences): Promise<RecipeResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const systemInstruction = `Você é um nutricionista sênior e chef celebridade especializado em gastronomia funcional. 
  Crie receitas FIT que sejam nutritivas e visualmente atraentes. 
  Retorne APENAS o JSON conforme o esquema solicitado.`;

  const prompt = `Gere uma receita FIT para ${prefs.peopleCount} pessoa(s).
  Refeição: ${prefs.mealType} ${prefs.dishType ? `(Estilo: ${prefs.dishType})` : ''}
  Restrições: ${prefs.dietaryFilters.join(', ')}
  Calorias: ${prefs.calorieLevel}
  Sabor dominante: ${prefs.flavor}
  Dificuldade: ${prefs.skillLevel}
  Usar preferencialmente: ${prefs.ingredients || 'Ingredientes frescos'}
  Evitar: ${prefs.dispensableIngredients || 'Nada específico'}

  IMPORTANTE: Na propriedade 'estimatedCost', forneça o valor médio de gasto estimado em Reais (R$) para os ingredientes necessários (ex: "R$ 25,00 - R$ 35,00"). Considere a quantidade de pessoas: ${prefs.peopleCount}.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          description: { type: Type.STRING },
          ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
          instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
          estimatedCost: { 
            type: Type.STRING, 
            description: "O valor médio de gasto estimado em Reais (R$)." 
          },
          estimatedTime: { type: Type.STRING },
          macros: {
            type: Type.OBJECT,
            properties: {
              protein: { type: Type.STRING },
              carbs: { type: Type.STRING },
              fats: { type: Type.STRING },
              calories: { type: Type.STRING },
            },
            required: ["protein", "carbs", "fats", "calories"]
          }
        },
        required: ["title", "description", "ingredients", "instructions", "macros", "estimatedTime", "estimatedCost"]
      },
    },
  });

  const recipeData = JSON.parse(response.text) as RecipeResult;

  // Gerar imagem do prato
  try {
    const imgResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: `Fotografia profissional de culinária: ${recipeData.title}, iluminação de estúdio, prato gourmet, fundo neutro, 4k.`,
      config: { imageConfig: { aspectRatio: "1:1" } }
    });
    const part = imgResponse.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (part?.inlineData) {
      recipeData.imageUrl = `data:image/png;base64,${part.inlineData.data}`;
    }
  } catch (e) {
    recipeData.imageUrl = "https://images.unsplash.com/photo-1490645935967-10de6ba17061?auto=format&fit=crop&q=80&w=800";
  }

  return recipeData;
};

